export default Layout;

import React, { useState } from 'react';
import { QuestionData, QuestionStatus } from '../types';

interface QuestionInputProps {
  onAdd: (q: QuestionData) => void;
}

const QuestionInput: React.FC<QuestionInputProps> = ({ onAdd }) => {
  const [formData, setFormData] = useState({
    question: '',
    options: ['', '', '', ''],
    correctOptionIndex: 0,
    solution: '',
    topic: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.question || !formData.solution || formData.options.some(o => !o)) {
      alert("Please fill all components. Incomplete questions are blocked from the audit pipeline.");
      return;
    }

    const newQuestion: QuestionData = {
      id: Math.random().toString(36).substr(2, 9),
      topic: formData.topic || 'General',
      original: {
        question: formData.question,
        options: [...formData.options],
        correctOptionIndex: formData.correctOptionIndex,
        solution: formData.solution
      },
      version: 1,
      lastModified: Date.now()
    };

    onAdd(newQuestion);
    setFormData({
      question: '',
      options: ['', '', '', ''],
      correctOptionIndex: 0,
      solution: '',
      topic: ''
    });
  };

  const updateOption = (idx: number, val: string) => {
    const next = [...formData.options];
    next[idx] = val;
    setFormData({ ...formData, options: next });
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="bg-slate-50 px-6 py-4 border-b border-slate-200">
        <h2 className="text-lg font-bold text-slate-800">Add Question for Audit</h2>
        <p className="text-sm text-slate-500">Every component must be provided before the AI audit can begin.</p>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6">
        <div className="grid grid-cols-2 gap-4">
          <div className="col-span-1">
            <label className="block text-sm font-semibold text-slate-700 mb-1">Topic / Chapter</label>
            <input 
              type="text" 
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition"
              placeholder="e.g. Thermodynamics"
              value={formData.topic}
              onChange={e => setFormData({...formData, topic: e.target.value})}
            />
          </div>
        </div>

        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">Question Body</label>
          <textarea 
            rows={4}
            className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition resize-none"
            placeholder="Enter the complete question text..."
            value={formData.question}
            onChange={e => setFormData({...formData, question: e.target.value})}
          />
        </div>

        <div className="grid grid-cols-2 gap-4">
          {formData.options.map((opt, idx) => (
            <div key={idx} className="flex items-center gap-3">
              <input 
                type="radio" 
                name="correct" 
                checked={formData.correctOptionIndex === idx}
                onChange={() => setFormData({...formData, correctOptionIndex: idx})}
                className="w-4 h-4 text-indigo-600 border-slate-300 focus:ring-indigo-500"
              />
              <input 
                type="text" 
                className="flex-1 px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition"
                placeholder={`Option ${String.fromCharCode(65 + idx)}`}
                value={opt}
                onChange={e => updateOption(idx, e.target.value)}
              />
            </div>
          ))}
        </div>

        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">Detailed Solution</label>
          <textarea 
            rows={3}
            className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition resize-none"
            placeholder="Explain the logic step-by-step..."
            value={formData.solution}
            onChange={e => setFormData({...formData, solution: e.target.value})}
          />
        </div>

        <div className="pt-4 border-t border-slate-100 flex justify-end">
          <button 
            type="submit"
            className="px-6 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white font-semibold rounded-lg shadow-lg shadow-indigo-200 transition active:scale-95"
          >
            Add to Audit Pipeline
          </button>
        </div>
      </form>
    </div>
  );
};

export default QuestionInput;

import React, { useState } from 'react';
import { QuestionData, QuestionStatus } from '../types';

interface QuestionCardProps {
  data: QuestionData;
  onAudit: (id: string) => void;
  onApprove?: (id: string) => void;
  isAuditing: boolean;
  showQCControls?: boolean;
}

const QuestionCard: React.FC<QuestionCardProps> = ({ data, onAudit, onApprove, isAuditing, showQCControls }) => {
  const [viewMode, setViewMode] = useState<'AUDIT' | 'CLEAN'>('AUDIT');

  const getStatusStyle = (status: QuestionStatus) => {
    switch (status) {
      case QuestionStatus.APPROVED: return 'bg-green-100 text-green-700 border-green-200';
      case QuestionStatus.NEEDS_CORRECTION: return 'bg-amber-100 text-amber-700 border-amber-200';
      case QuestionStatus.REJECTED: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-slate-100 text-slate-600 border-slate-200';
    }
  };

  const renderRedlined = (html: string) => {
    // Basic parser for <del> and <ins>
    return (
      <div 
        className="prose-sm max-w-none"
        dangerouslySetInnerHTML={{ 
          __html: html.replace(/<del>/g, '<del class="bg-red-100 text-red-800 line-through px-1 rounded mx-0.5">')
                      .replace(/<\/del>/g, '</del>')
                      .replace(/<ins>/g, '<ins class="bg-green-100 text-green-800 font-medium px-1 rounded mx-0.5">')
                      .replace(/<\/ins>/g, '</ins>')
        }} 
      />
    );
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden mb-6 group hover:border-indigo-300 transition">
      {/* Header */}
      <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 bg-slate-50/50">
        <div className="flex items-center gap-4">
          <span className="text-xs font-bold uppercase tracking-widest text-slate-400">Q#{data.id.slice(0, 4)}</span>
          <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold border ${getStatusStyle(data.audit?.status || QuestionStatus.PENDING)}`}>
            {data.audit?.status || 'UNAUDITED'}
          </span>
          <span className="text-xs font-medium text-slate-500 bg-slate-200 px-2 py-0.5 rounded">{data.topic}</span>
        </div>

        <div className="flex items-center gap-2">
          {!data.audit && !isAuditing && (
            <button 
              onClick={() => onAudit(data.id)}
              className="px-4 py-1.5 bg-indigo-600 hover:bg-indigo-700 text-white text-xs font-bold rounded shadow transition active:scale-95"
            >
              Start AI Audit
            </button>
          )}
          {isAuditing && <span className="text-xs text-indigo-500 animate-pulse font-medium">Verifying logic...</span>}
          {data.audit && (
            <div className="inline-flex rounded-lg bg-slate-200 p-0.5">
              <button 
                onClick={() => setViewMode('AUDIT')}
                className={`px-3 py-1 text-[10px] font-bold rounded-md transition ${viewMode === 'AUDIT' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
              >
                AUDIT VIEW
              </button>
              <button 
                onClick={() => setViewMode('CLEAN')}
                className={`px-3 py-1 text-[10px] font-bold rounded-md transition ${viewMode === 'CLEAN' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
              >
                CLEAN VIEW
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Content */}
      <div className="p-6">
        {viewMode === 'AUDIT' || !data.audit ? (
          <div className="space-y-6">
            <div>
              <p className="text-[10px] font-bold text-slate-400 uppercase mb-2 tracking-wider">Question Body</p>
              {data.audit ? renderRedlined(data.audit.redlines.question) : <p className="text-slate-800 font-medium">{data.original.question}</p>}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {(data.audit?.redlines.options || data.original.options).map((opt, i) => (
                <div key={i} className={`p-3 rounded-lg border flex items-start gap-3 ${i === (data.audit?.clean.correctOptionIndex ?? data.original.correctOptionIndex) ? 'bg-green-50 border-green-200' : 'border-slate-100 bg-slate-50/30'}`}>
                  <span className="font-bold text-xs text-slate-400 mt-0.5">{String.fromCharCode(65+i)})</span>
                  <div className="text-sm text-slate-700">
                    {data.audit ? renderRedlined(opt) : opt}
                  </div>
                </div>
              ))}
            </div>

            <div>
              <p className="text-[10px] font-bold text-slate-400 uppercase mb-2 tracking-wider">Solution Logic</p>
              <div className="p-4 bg-slate-50 rounded-lg border border-slate-100 text-sm italic text-slate-600">
                {data.audit ? renderRedlined(data.audit.redlines.solution) : data.original.solution}
              </div>
            </div>

            {data.audit?.logs && data.audit.logs.length > 0 && (
              <div className="pt-4 border-t border-slate-100">
                <p className="text-[10px] font-bold text-red-400 uppercase mb-2 tracking-wider">Audit Findings</p>
                <div className="space-y-2">
                  {data.audit.logs.map((log, i) => (
                    <div key={i} className="flex gap-2 items-center text-xs text-slate-600 bg-red-50 p-2 rounded border border-red-100">
                      <span className="bg-red-500 text-white px-1.5 py-0.5 rounded text-[8px] font-black">{log.severity}</span>
                      <span className="font-bold uppercase text-[10px] text-red-700">{log.type}:</span>
                      <span>{log.message}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-6">
            <div>
              <p className="text-[10px] font-bold text-green-500 uppercase mb-2 tracking-wider">Exam-Ready Question</p>
              <p className="text-slate-900 font-semibold text-lg leading-relaxed">{data.audit.clean.question}</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {data.audit.clean.options.map((opt, i) => (
                <div key={i} className={`p-4 rounded-xl border-2 transition ${i === data.audit?.clean.correctOptionIndex ? 'border-green-500 bg-green-50' : 'border-slate-100 hover:border-slate-200'}`}>
                  <div className="flex items-center justify-between">
                    <span className="font-bold text-slate-400 text-xs">{String.fromCharCode(65+i)}</span>
                    {i === data.audit?.clean.correctOptionIndex && <span className="bg-green-600 text-white text-[8px] font-black px-1 rounded">CORRECT</span>}
                  </div>
                  <p className="text-sm font-medium text-slate-800 mt-1">{opt}</p>
                </div>
              ))}
            </div>

            <div>
              <p className="text-[10px] font-bold text-indigo-500 uppercase mb-2 tracking-wider">Verified Solution</p>
              <div className="bg-indigo-50/50 p-4 rounded-xl border border-indigo-100 text-sm text-slate-700 leading-relaxed">
                {data.audit.clean.solution}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Footer Controls */}
      {showQCControls && data.audit && (
        <div className="px-6 py-4 bg-slate-900 border-t border-slate-800 flex justify-between items-center">
          <div className="flex items-center gap-4">
             <span className="text-slate-400 text-[10px] font-bold uppercase">QC Review Required</span>
          </div>
          <div className="flex gap-3">
             <button 
              onClick={() => onApprove?.(data.id)}
              className="px-6 py-1.5 bg-green-600 hover:bg-green-700 text-white text-xs font-black rounded uppercase tracking-widest transition active:scale-95"
            >
              Approve & Lock
            </button>
            <button className="px-4 py-1.5 border border-red-500/50 text-red-400 hover:bg-red-900/20 text-xs font-black rounded uppercase tracking-widest transition">
              Reject Paper
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default QuestionCard;

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { AuditLog } from '../types';

interface AnalyticsDashboardProps {
  logs: AuditLog[];
}

const COLORS = ['#6366f1', '#f59e0b', '#ef4444', '#10b981'];

const AnalyticsDashboard: React.FC<AnalyticsDashboardProps> = ({ logs }) => {
  // Aggregate data
  const typeCount = logs.reduce((acc: any, log) => {
    acc[log.type] = (acc[log.type] || 0) + 1;
    return acc;
  }, {});

  const barData = Object.keys(typeCount).map(key => ({
    name: key,
    value: typeCount[key]
  }));

  const severityCount = logs.reduce((acc: any, log) => {
    acc[log.severity] = (acc[log.severity] || 0) + 1;
    return acc;
  }, {});

  const pieData = Object.keys(severityCount).map(key => ({
    name: key,
    value: severityCount[key]
  }));

  return (
    <div className="space-y-8">
      <header className="mb-8">
        <h1 className="text-3xl font-black text-slate-900">Academic Safety Audit Logs</h1>
        <p className="text-slate-500 font-medium">Tracking error patterns and quality trends across departments.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="text-sm font-bold text-slate-400 uppercase mb-6 tracking-widest">Error Types Distribution</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={barData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" fontSize={10} axisLine={false} tickLine={false} />
                <YAxis fontSize={10} axisLine={false} tickLine={false} />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }}
                  cursor={{ fill: '#f8fafc' }}
                />
                <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="text-sm font-bold text-slate-400 uppercase mb-6 tracking-widest">Severity Overview</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={pieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="flex justify-center gap-4 mt-2">
            {pieData.map((d, i) => (
              <div key={i} className="flex items-center gap-1">
                <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }}></div>
                <span className="text-[10px] font-bold text-slate-500 uppercase">{d.name}</span>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-slate-900 p-6 rounded-2xl shadow-2xl flex flex-col justify-center text-center">
          <div className="text-5xl font-black text-indigo-400">{logs.length}</div>
          <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px] mt-2">Total Intervention Points</p>
