import { GoogleGenAI, Type } from "@google/genai";
import { QuestionData, QuestionStatus } from "../types";

const SYSTEM_PROMPT = `You are a strict academic quality control auditor. 
Your task is to verify MCQ questions for accuracy, clarity, and logical consistency.

STRICT AUDIT RULES:
1. Question must be unambiguous.
2. Options must be distinct and mutually exclusive.
3. Exactly one option must be correct.
4. The solution must logically derive the correct answer.
5. Identify errors in math, grammar, or conceptual logic.

OUTPUT FORMAT:
- You must provide a JSON response.
- status: APPROVED, NEEDS_CORRECTION, or REJECTED.
- auditLogs: A list of specific errors found.
- redlines: A version where mistakes are wrapped in <del>tags and corrections in <ins>tags.
- clean: A corrected, ready-to-use version.

DO NOT BE CREATIVE. Only correct what is wrong. If it is correct, status is APPROVED.`;

const DOCUMENT_AUDIT_PROMPT = `Extract ALL multiple-choice questions from this document. 
For each question, perform a strict quality audit. 
Identify conceptual, logical, and numerical errors.

Return a JSON array of audited questions.
Each object in the array must match this schema:
{
  "topic": "string",
  "original": {
    "question": "string",
    "options": ["string", "string", "string", "string"],
    "correctOptionIndex": number,
    "solution": "string"
  },
  "audit": {
    "status": "APPROVED" | "NEEDS_CORRECTION" | "REJECTED",
    "auditLogs": [{ "type": "CONCEPTUAL" | "NUMERICAL" | "LOGICAL" | "GRAMMATICAL", "message": "string", "severity": "HIGH" | "MEDIUM" | "LOW" }],
    "redlines": { "question": "string", "options": ["string"], "solution": "string" },
    "clean": { "question": "string", "options": ["string"], "correctOptionIndex": number, "solution": "string" }
  }
}`;

export const auditQuestion = async (q: QuestionData['original']): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `Audit this question:
Question: ${q.question}
Options: ${q.options.map((opt, i) => `${String.fromCharCode(65 + i)}) ${opt}`).join(', ')}
Correct Index: ${q.correctOptionIndex}
Solution: ${q.solution}`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.1,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING, enum: ['APPROVED', 'NEEDS_CORRECTION', 'REJECTED'] },
            auditLogs: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING, enum: ['CONCEPTUAL', 'NUMERICAL', 'LOGICAL', 'GRAMMATICAL'] },
                  message: { type: Type.STRING },
                  severity: { type: Type.STRING, enum: ['HIGH', 'MEDIUM', 'LOW'] }
                },
                required: ['type', 'message', 'severity']
              }
            },
            redlines: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                options: { type: Type.ARRAY, items: { type: Type.STRING } },
                solution: { type: Type.STRING }
              }
            },
            clean: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                options: { type: Type.ARRAY, items: { type: Type.STRING } },
                correctOptionIndex: { type: Type.NUMBER },
                solution: { type: Type.STRING }
              }
            }
          },
          required: ['status', 'auditLogs', 'redlines', 'clean']
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Audit Error:", error);
    throw error;
  }
};

export const auditDocument = async (base64Data: string, mimeType: string): Promise<any[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        {
          inlineData: {
            data: base64Data,
            mimeType: mimeType
          }
        },
        { text: DOCUMENT_AUDIT_PROMPT }
      ],
      config: {
        systemInstruction: "You are a specialized academic paper parser and auditor. You extract MCQs from documents and run quality checks on them.",
        temperature: 0.1,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              topic: { type: Type.STRING },
              original: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctOptionIndex: { type: Type.NUMBER },
                  solution: { type: Type.STRING }
                },
                required: ['question', 'options', 'correctOptionIndex', 'solution']
              },
              audit: {
                type: Type.OBJECT,
                properties: {
                  status: { type: Type.STRING, enum: ['APPROVED', 'NEEDS_CORRECTION', 'REJECTED'] },
                  auditLogs: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        type: { type: Type.STRING, enum: ['CONCEPTUAL', 'NUMERICAL', 'LOGICAL', 'GRAMMATICAL'] },
                        message: { type: Type.STRING },
                        severity: { type: Type.STRING, enum: ['HIGH', 'MEDIUM', 'LOW'] }
                      }
                    }
                  },
                  redlines: {
                    type: Type.OBJECT,
                    properties: {
                      question: { type: Type.STRING },
                      options: { type: Type.ARRAY, items: { type: Type.STRING } },
                      solution: { type: Type.STRING }
                    }
                  },
                  clean: {
                    type: Type.OBJECT,
                    properties: {
                      question: { type: Type.STRING },
                      options: { type: Type.ARRAY, items: { type: Type.STRING } },
                      correctOptionIndex: { type: Type.NUMBER },
                      solution: { type: Type.STRING }
                    }
                  }
                },
                required: ['status', 'auditLogs', 'redlines', 'clean']
              }
            },
            required: ['topic', 'original', 'audit']
          }
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Document Audit Error:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { QuestionData, QuestionStatus } from '../types';
import { auditDocument } from '../services/geminiService';

interface QuestionInputProps {
  onAdd: (q: QuestionData) => void;
  onAddBulk: (qs: QuestionData[]) => void;
}

const QuestionInput: React.FC<QuestionInputProps> = ({ onAdd, onAddBulk }) => {
  const [activeTab, setActiveTab] = useState<'SINGLE' | 'UPLOAD'>('SINGLE');
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [formData, setFormData] = useState({
    question: '',
    options: ['', '', '', ''],
    correctOptionIndex: 0,
    solution: '',
    topic: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.question || !formData.solution || formData.options.some(o => !o)) {
      alert("Please fill all components. Incomplete questions are blocked from the audit pipeline.");
      return;
    }

    const newQuestion: QuestionData = {
      id: Math.random().toString(36).substr(2, 9),
      topic: formData.topic || 'General',
      original: {
        question: formData.question,
        options: [...formData.options],
        correctOptionIndex: formData.correctOptionIndex,
        solution: formData.solution
      },
      version: 1,
      lastModified: Date.now()
    };

    onAdd(newQuestion);
    setFormData({
      question: '',
      options: ['', '', '', ''],
      correctOptionIndex: 0,
      solution: '',
      topic: ''
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await auditDocument(base64, file.type);

        const mappedQuestions: QuestionData[] = results.map((res: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          topic: res.topic,
          original: res.original,
          audit: res.audit,
          version: 2,
          lastModified: Date.now()
        }));

        onAddBulk(mappedQuestions);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      alert("Failed to process document. Ensure it is a valid PDF or Word file.");
    } finally {
      setIsProcessing(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const updateOption = (idx: number, val: string) => {
    const next = [...formData.options];
    next[idx] = val;
    setFormData({ ...formData, options: next });
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden mb-8">
      {/* Tabs */}
      <div className="flex border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('SINGLE')}
          className={`flex-1 py-4 text-xs font-bold uppercase tracking-wider transition ${activeTab === 'SINGLE' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
          Manual Question Entry
        </button>
        <button 
          onClick={() => setActiveTab('UPLOAD')}
          className={`flex-1 py-4 text-xs font-bold uppercase tracking-wider transition ${activeTab === 'UPLOAD' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
          Upload Paper (PDF/Word)
        </button>
      </div>

      <div className="p-8">
        {activeTab === 'SINGLE' ? (
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-2 gap-4">
              <div className="col-span-1">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Topic / Chapter</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition bg-slate-50/50"
                  placeholder="e.g. Thermodynamics"
                  value={formData.topic}
                  onChange={e => setFormData({...formData, topic: e.target.value})}
                />
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Question Body</label>
              <textarea 
                rows={4}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition resize-none bg-slate-50/50 text-slate-800 font-medium"
                placeholder="Paste question text here..."
                value={formData.question}
                onChange={e => setFormData({...formData, question: e.target.value})}
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {formData.options.map((opt, idx) => (
                <div key={idx} className={`flex items-center gap-3 p-3 rounded-xl border transition ${formData.correctOptionIndex === idx ? 'border-green-500 bg-green-50/50' : 'border-slate-100 bg-slate-50/30'}`}>
                  <input 
                    type="radio" 
                    name="correct" 
                    checked={formData.correctOptionIndex === idx}
                    onChange={() => setFormData({...formData, correctOptionIndex: idx})}
                    className="w-4 h-4 text-indigo-600 border-slate-300 focus:ring-indigo-500"
                  />
                  <input 
                    type="text" 
                    className="flex-1 bg-transparent border-none focus:ring-0 text-sm font-medium text-slate-700"
                    placeholder={`Option ${String.fromCharCode(65 + idx)}`}
                    value={opt}
                    onChange={e => updateOption(idx, e.target.value)}
                  />
                </div>
              ))}
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Detailed Solution</label>
              <textarea 
                rows={3}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition resize-none bg-slate-50/50 text-slate-800 font-medium italic"
                placeholder="Explain the logic..."
                value={formData.solution}
                onChange={e => setFormData({...formData, solution: e.target.value})}
              />
            </div>

            <div className="pt-4 flex justify-end">
              <button 
                type="submit"
                className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-xl shadow-lg shadow-indigo-200 transition active:scale-95 text-xs uppercase tracking-widest"
              >
                Enqueue for Audit
              </button>
            </div>
          </form>
        ) : (
          <div className="py-12 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-3xl hover:border-indigo-400 transition-colors group relative overflow-hidden">
            {isProcessing && (
              <div className="absolute inset-0 bg-white/90 z-10 flex flex-col items-center justify-center space-y-4">
                <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                <div className="text-center">
                  <p className="text-sm font-black text-slate-900 uppercase tracking-widest">AI Ingestion in Progress</p>
                  <p className="text-xs text-slate-500 mt-1 font-medium italic">Extracting, analyzing and auditing multiple questions...</p>
                </div>
              </div>
            )}

            <div className="p-4 bg-indigo-50 rounded-2xl group-hover:bg-indigo-100 transition-colors">
              <svg className="w-12 h-12 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
              </svg>
            </div>
            <div className="mt-6 text-center">
              <h3 className="text-lg font-black text-slate-900 uppercase tracking-wide">Drop Question Paper</h3>
              <p className="text-sm text-slate-500 mt-2 font-medium">Supports PDF and Word Documents (.pdf, .docx)</p>
            </div>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="mt-8 px-10 py-3 bg-slate-900 text-white text-[10px] font-black uppercase tracking-[0.2em] rounded-full hover:bg-indigo-600 transition shadow-xl"
            >
              Select File
            </button>
            <input 
              type="file" 
              className="hidden" 
              ref={fileInputRef} 
              accept=".pdf,.docx,application/pdf,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
              onChange={handleFileUpload}
            />
          </div>
        )}
      </div>
    </div>
  );
};

