    switch (activeTab) {
      case 'input':
        return <QuestionInput onAdd={handleAddQuestion} onAddBulk={handleAddBulk} />;

      case 'review':
        return (
          <div className="space-y-6">
            <header className="mb-8">
              <h1 className="text-3xl font-black text-slate-900">Audit Pipeline</h1>
              <p className="text-slate-500 font-medium">Review AI interventions and verify corrected logic before submission.</p>
            </header>
            {questions.length === 0 ? (
              <div className="bg-white rounded-2xl border-2 border-dashed border-slate-200 p-12 text-center">
                <p className="text-slate-400 font-bold uppercase tracking-widest">No Questions in Pipeline</p>
                <button onClick={() => setActiveTab('input')} className="mt-4 text-indigo-600 font-bold hover:underline">Go to Input</button>
              </div>
            ) : (
              questions.map(q => (
                <QuestionCard 
                  key={q.id} 
                  data={q} 
                  onAudit={handleAuditRequest} 
                  isAuditing={isAuditingId === q.id}
                />
              ))
            )}
          </div>
        );

      case 'analytics':
        return <AnalyticsDashboard logs={allLogs} />;

      case 'approval':
        const pending = questions.filter(q => q.audit && q.audit.status !== QuestionStatus.APPROVED);
        return (
          <div className="space-y-6">
            <header className="mb-8">
              <h1 className="text-3xl font-black text-slate-900">QC Command Center</h1>
              <p className="text-slate-500 font-medium">Final approval required for all AI-corrected content.</p>
            </header>
            {pending.length === 0 ? (
              <div className="bg-green-50 rounded-2xl border border-green-100 p-12 text-center">
                <p className="text-green-600 font-black uppercase tracking-widest">Queue Clear</p>
                <p className="text-green-500 text-sm mt-1">All processed questions have been approved.</p>
              </div>
            ) : (
              pending.map(q => (
                <QuestionCard 
                  key={q.id} 
                  data={q} 
                  onAudit={handleAuditRequest} 
                  onApprove={handleApprove}
                  isAuditing={isAuditingId === q.id}
                  showQCControls
                />
              ))
            )}
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <Layout 
      activeRole={activeRole} 
      onRoleSwitch={setActiveRole}
      activeTab={activeTab}
      setActiveTab={setActiveTab}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { QuestionData, QuestionStatus } from '../types';
import { auditDocument } from '../services/geminiService';

interface QuestionInputProps {
  onAdd: (q: QuestionData) => void;
  onAddBulk: (qs: QuestionData[]) => void;
}

const LOADING_MESSAGES = [
  "Inhaling document structure...",
  "Identifying question boundaries...",
  "Analyzing academic logic...",
  "Running cross-validation checks...",
  "Formatting redlined corrections...",
  "Finalizing audit report...",
];

const QuestionInput: React.FC<QuestionInputProps> = ({ onAdd, onAddBulk }) => {
  const [activeTab, setActiveTab] = useState<'SINGLE' | 'UPLOAD'>('SINGLE');
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState(LOADING_MESSAGES[0]);
  const [progress, setProgress] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [formData, setFormData] = useState({
    question: '',
    options: ['', '', '', ''],
    correctOptionIndex: 0,
    solution: '',
    topic: ''
  });

  // Cycle through loading messages while processing
  useEffect(() => {
    let interval: any;
    let progressInterval: any;
    if (isProcessing) {
      let idx = 0;
      interval = setInterval(() => {
        idx = (idx + 1) % LOADING_MESSAGES.length;
        setLoadingMessage(LOADING_MESSAGES[idx]);
      }, 2500);

      setProgress(0);
      progressInterval = setInterval(() => {
        setProgress(prev => {
          if (prev >= 95) return prev; // Hold at 95 until complete
          return prev + (Math.random() * 5);
        });
      }, 400);
    } else {
      setLoadingMessage(LOADING_MESSAGES[0]);
      setProgress(0);
    }
    return () => {
      clearInterval(interval);
      clearInterval(progressInterval);
    };
  }, [isProcessing]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.question || !formData.solution || formData.options.some(o => !o)) {
      alert("Please fill all components. Incomplete questions are blocked from the audit pipeline.");
      return;
    }

    const newQuestion: QuestionData = {
      id: Math.random().toString(36).substr(2, 9),
      topic: formData.topic || 'General',
      original: {
        question: formData.question,
        options: [...formData.options],
        correctOptionIndex: formData.correctOptionIndex,
        solution: formData.solution
      },
      version: 1,
      lastModified: Date.now()
    };

    onAdd(newQuestion);
    setFormData({
      question: '',
      options: ['', '', '', ''],
      correctOptionIndex: 0,
      solution: '',
      topic: ''
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await auditDocument(base64, file.type);

        const mappedQuestions: QuestionData[] = results.map((res: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          topic: res.topic,
          original: res.original,
          audit: res.audit,
          version: 2,
          lastModified: Date.now()
        }));

        setProgress(100);
        setTimeout(() => {
          onAddBulk(mappedQuestions);
          setIsProcessing(false);
        }, 500);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      alert("Failed to process document. Ensure it is a valid PDF or Word file.");
      setIsProcessing(false);
    } finally {
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const updateOption = (idx: number, val: string) => {
    const next = [...formData.options];
    next[idx] = val;
    setFormData({ ...formData, options: next });
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden mb-8">
      {/* Tabs */}
      <div className="flex border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('SINGLE')}
          className={`flex-1 py-4 text-xs font-bold uppercase tracking-wider transition ${activeTab === 'SINGLE' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
          Manual Question Entry
        </button>
        <button 
          onClick={() => setActiveTab('UPLOAD')}
          className={`flex-1 py-4 text-xs font-bold uppercase tracking-wider transition ${activeTab === 'UPLOAD' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
          Upload Paper (PDF/Word)
        </button>
      </div>

      <div className="p-8">
        {activeTab === 'SINGLE' ? (
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-2 gap-4">
              <div className="col-span-1">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Topic / Chapter</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition bg-slate-50/50"
                  placeholder="e.g. Thermodynamics"
                  value={formData.topic}
                  onChange={e => setFormData({...formData, topic: e.target.value})}
                />
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Question Body</label>
              <textarea 
                rows={4}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition resize-none bg-slate-50/50 text-slate-800 font-medium"
                placeholder="Paste question text here..."
                value={formData.question}
                onChange={e => setFormData({...formData, question: e.target.value})}
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {formData.options.map((opt, idx) => (
                <div key={idx} className={`flex items-center gap-3 p-3 rounded-xl border transition ${formData.correctOptionIndex === idx ? 'border-green-500 bg-green-50/50' : 'border-slate-100 bg-slate-50/30'}`}>
                  <input 
                    type="radio" 
                    name="correct" 
                    checked={formData.correctOptionIndex === idx}
                    onChange={() => setFormData({...formData, correctOptionIndex: idx})}
                    className="w-4 h-4 text-indigo-600 border-slate-300 focus:ring-indigo-500"
                  />
                  <input 
                    type="text" 
                    className="flex-1 bg-transparent border-none focus:ring-0 text-sm font-medium text-slate-700"
                    placeholder={`Option ${String.fromCharCode(65 + idx)}`}
                    value={opt}
                    onChange={e => updateOption(idx, e.target.value)}
                  />
                </div>
              ))}
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Detailed Solution</label>
              <textarea 
                rows={3}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition resize-none bg-slate-50/50 text-slate-800 font-medium italic"
                placeholder="Explain the logic..."
                value={formData.solution}
                onChange={e => setFormData({...formData, solution: e.target.value})}
              />
            </div>

            <div className="pt-4 flex justify-end">
              <button 
                type="submit"
                className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-xl shadow-lg shadow-indigo-200 transition active:scale-95 text-xs uppercase tracking-widest"
              >
                Enqueue for Audit
              </button>
            </div>
          </form>
        ) : (
          <div className="py-12 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-3xl hover:border-indigo-400 transition-colors group relative overflow-hidden min-h-[400px]">
            {isProcessing && (
              <div className="absolute inset-0 bg-white/95 backdrop-blur-sm z-10 flex flex-col items-center justify-center space-y-6">
                <div className="relative">
                  <div className="w-16 h-16 border-4 border-slate-100 rounded-full"></div>
                  <div className="absolute inset-0 w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                  <div className="absolute -inset-4 border border-indigo-100 rounded-full animate-ping opacity-25"></div>
                </div>

                <div className="text-center max-w-xs">
                  <h3 className="text-lg font-black text-slate-900 uppercase tracking-[0.15em] mb-1">AI Audit Live</h3>
                  <p className="text-xs font-bold text-indigo-600 animate-pulse uppercase tracking-wider h-4">
                    {loadingMessage}
                  </p>

                  <div className="mt-8 w-64 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-indigo-600 transition-all duration-300 ease-out rounded-full shadow-[0_0_8px_rgba(79,70,229,0.5)]"
                      style={{ width: `${progress}%` }}
                    ></div>
                  </div>
                  <p className="mt-2 text-[10px] text-slate-400 font-bold uppercase tracking-widest">
                    Processing Accuracy: {Math.round(progress)}%
                  </p>
                </div>
              </div>
            )}

            <div className="p-4 bg-indigo-50 rounded-2xl group-hover:bg-indigo-100 transition-colors">
              <svg className="w-12 h-12 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
              </svg>
            </div>
            <div className="mt-6 text-center px-4">
              <h3 className="text-lg font-black text-slate-900 uppercase tracking-wide">Drop Question Paper</h3>
              <p className="text-sm text-slate-500 mt-2 font-medium max-w-sm">AI will automatically parse structure, detect errors, and suggest redlines across multiple questions.</p>
              <div className="mt-4 flex gap-2 justify-center">
                <span className="px-2 py-0.5 rounded bg-slate-100 text-[8px] font-black text-slate-500 border border-slate-200">PDF</span>
                <span className="px-2 py-0.5 rounded bg-slate-100 text-[8px] font-black text-slate-500 border border-slate-200">DOCX</span>
              </div>
            </div>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="mt-8 px-10 py-3 bg-slate-900 text-white text-[10px] font-black uppercase tracking-[0.2em] rounded-full hover:bg-indigo-600 transition shadow-xl active:scale-95"
            >
              Select File
            </button>
            <input 
              type="file" 
              className="hidden" 
              ref={fileInputRef} 
              accept=".pdf,.docx,application/pdf,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
              onChange={handleFileUpload}
            />
          </div>
        )}
      </div>
    </div>
  );
};

export default QuestionInput;

import React, { useState } from 'react';
import { QuestionData, QuestionStatus } from '../types';

interface QuestionCardProps {
  data: QuestionData;
  onAudit: (id: string) => void;
  onApprove?: (id: string) => void;
  isAuditing: boolean;
  showQCControls?: boolean;
}

const QuestionCard: React.FC<QuestionCardProps> = ({ data, onAudit, onApprove, isAuditing, showQCControls }) => {
  const [viewMode, setViewMode] = useState<'AUDIT' | 'CLEAN'>('AUDIT');

  const getStatusStyle = (status: QuestionStatus) => {
    switch (status) {
      case QuestionStatus.APPROVED: return 'bg-green-100 text-green-700 border-green-200';
      case QuestionStatus.NEEDS_CORRECTION: return 'bg-amber-100 text-amber-700 border-amber-200';
      case QuestionStatus.REJECTED: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-slate-100 text-slate-600 border-slate-200';
    }
  };

  const renderRedlined = (html: any) => {
    // Handle potential undefined or non-string values from API or state
    const safeHtml = typeof html === 'string' ? html : '';
    if (!safeHtml) return <span className="text-slate-400 italic">No content available</span>;

    // Basic parser for <del> and <ins>
    return (
      <div 
        className="prose-sm max-w-none"
        dangerouslySetInnerHTML={{ 
          __html: safeHtml.replace(/<del>/g, '<del class="bg-red-100 text-red-800 line-through px-1 rounded mx-0.5">')
                      .replace(/<\/del>/g, '</del>')
                      .replace(/<ins>/g, '<ins class="bg-green-100 text-green-800 font-medium px-1 rounded mx-0.5">')
                      .replace(/<\/ins>/g, '</ins>')
        }} 
      />
    );
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden mb-6 group hover:border-indigo-300 transition">
      {/* Header */}
      <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 bg-slate-50/50">
        <div className="flex items-center gap-4">
          <span className="text-xs font-bold uppercase tracking-widest text-slate-400">Q#{data.id.slice(0, 4)}</span>
          <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold border ${getStatusStyle(data.audit?.status || QuestionStatus.PENDING)}`}>
            {data.audit?.status || 'UNAUDITED'}
          </span>
          <span className="text-xs font-medium text-slate-500 bg-slate-200 px-2 py-0.5 rounded">{data.topic}</span>
        </div>

        <div className="flex items-center gap-2">
          {!data.audit && !isAuditing && (
            <button 
              onClick={() => onAudit(data.id)}
              className="px-4 py-1.5 bg-indigo-600 hover:bg-indigo-700 text-white text-xs font-bold rounded shadow transition active:scale-95"
            >
              Start AI Audit
            </button>
          )}
          {isAuditing && <span className="text-xs text-indigo-500 animate-pulse font-medium">Verifying logic...</span>}
          {data.audit && (
            <div className="inline-flex rounded-lg bg-slate-200 p-0.5">
              <button 
                onClick={() => setViewMode('AUDIT')}
                className={`px-3 py-1 text-[10px] font-bold rounded-md transition ${viewMode === 'AUDIT' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
              >
                AUDIT VIEW
              </button>
              <button 
                onClick={() => setViewMode('CLEAN')}
                className={`px-3 py-1 text-[10px] font-bold rounded-md transition ${viewMode === 'CLEAN' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
              >
                CLEAN VIEW
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Content */}
      <div className="p-6">
        {viewMode === 'AUDIT' || !data.audit ? (
          <div className="space-y-6">
            <div>
              <p className="text-[10px] font-bold text-slate-400 uppercase mb-2 tracking-wider">Question Body</p>
              {data.audit ? renderRedlined(data.audit.redlines.question) : <p className="text-slate-800 font-medium">{data.original.question}</p>}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {(data.audit?.redlines.options || data.original.options).map((opt, i) => (
                <div key={i} className={`p-3 rounded-lg border flex items-start gap-3 ${i === (data.audit?.clean.correctOptionIndex ?? data.original.correctOptionIndex) ? 'bg-green-50 border-green-200' : 'border-slate-100 bg-slate-50/30'}`}>
                  <span className="font-bold text-xs text-slate-400 mt-0.5">{String.fromCharCode(65+i)})</span>
                  <div className="text-sm text-slate-700">
                    {data.audit ? renderRedlined(opt) : opt}
                  </div>
                </div>
              ))}
            </div>

            <div>
              <p className="text-[10px] font-bold text-slate-400 uppercase mb-2 tracking-wider">Solution Logic</p>
              <div className="p-4 bg-slate-50 rounded-lg border border-slate-100 text-sm italic text-slate-600">
                {data.audit ? renderRedlined(data.audit.redlines.solution) : data.original.solution}
              </div>
            </div>

            {data.audit?.logs && data.audit.logs.length > 0 && (
              <div className="pt-4 border-t border-slate-100">
                <p className="text-[10px] font-bold text-red-400 uppercase mb-2 tracking-wider">Audit Findings</p>
                <div className="space-y-2">
                  {data.audit.logs.map((log, i) => (
                    <div key={i} className="flex gap-2 items-center text-xs text-slate-600 bg-red-50 p-2 rounded border border-red-100">
                      <span className="bg-red-500 text-white px-1.5 py-0.5 rounded text-[8px] font-black">{log.severity}</span>
                      <span className="font-bold uppercase text-[10px] text-red-700">{log.type}:</span>
                      <span>{log.message}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-6">
            <div>
              <p className="text-[10px] font-bold text-green-500 uppercase mb-2 tracking-wider">Exam-Ready Question</p>
              <p className="text-slate-900 font-semibold text-lg leading-relaxed">{data.audit.clean.question}</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {data.audit.clean.options.map((opt, i) => (
                <div key={i} className={`p-4 rounded-xl border-2 transition ${i === data.audit?.clean.correctOptionIndex ? 'border-green-500 bg-green-50' : 'border-slate-100 hover:border-slate-200'}`}>
                  <div className="flex items-center justify-between">
                    <span className="font-bold text-slate-400 text-xs">{String.fromCharCode(65+i)}</span>
                    {i === data.audit?.clean.correctOptionIndex && <span className="bg-green-600 text-white text-[8px] font-black px-1 rounded">CORRECT</span>}
                  </div>
                  <p className="text-sm font-medium text-slate-800 mt-1">{opt}</p>
                </div>
              ))}
            </div>

            <div>
              <p className="text-[10px] font-bold text-indigo-500 uppercase mb-2 tracking-wider">Verified Solution</p>
              <div className="bg-indigo-50/50 p-4 rounded-xl border border-indigo-100 text-sm text-slate-700 leading-relaxed">
                {data.audit.clean.solution}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Footer Controls */}
      {showQCControls && data.audit && (
        <div className="px-6 py-4 bg-slate-900 border-t border-slate-800 flex justify-between items-center">
          <div className="flex items-center gap-4">
             <span className="text-slate-400 text-[10px] font-bold uppercase">QC Review Required</span>
          </div>
          <div className="flex gap-3">
             <button 
              onClick={() => onApprove?.(data.id)}
              className="px-6 py-1.5 bg-green-600 hover:bg-green-700 text-white text-xs font-black rounded uppercase tracking-widest transition active:scale-95"
            >
              Approve & Lock
            </button>
            <button className="px-4 py-1.5 border border-red-500/50 text-red-400 hover:bg-red-900/20 text-xs font-black rounded uppercase tracking-widest transition">
              Reject Paper
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default QuestionCard;

