import { GoogleGenAI, Type } from "@google/genai";
import { QuestionData, QuestionStatus } from "../types";

const SYSTEM_PROMPT = `You are a strict academic quality control auditor and parser.

CORE DIRECTIVE: KEEP IT SIMPLE. 
DO NOT use LaTeX, Markdown math notation ($...$), or complex symbols. 
Ensure the content is readable as plain text for any teacher or student.

TASK:
1. PARSE: Extract Question Body, Options, Correct Answer (Index 0-3), and Solution.
2. AUDIT: Verify accuracy, clarity, and consistency.
   - Catch numerical mismatches.
   - Identify garbled characters (e.g., "\\nBC" instead of "wBC").
   - Ensure options are clear and distinct.

NOTATION RULES (STRICT):
- NO LaTeX: Do not use $q_{net}$, $\Rightarrow$, $\Delta$, etc.
- USE PLAIN TEXT: Use "q net", "leads to" or "->", "Delta U", "w2", "net heat exchange".
- Simplify scientific variables: Use standard characters (e.g., "wAB" instead of "w subscript AB").

STRICT REDLINING RULES:
- In the 'redlines' field, wrap errors in <del> and corrections in <ins>.
- Example: "The work done is <del>-5000</del> <ins>-500</ins> J".
- Only redline specific changes, do not rewrite entire sentences unless necessary.

MISSING DATA POLICY:
If core components (Question, Options, or Solution) are missing, set status to 'REJECTED'.

OUTPUT:
- Provide a JSON response following the specified schema.
- 'topic' should be specific (e.g., "Physics - Thermodynamics").`;

// Helper for the common question schema
const questionSchemaProperties = {
  status: { type: Type.STRING, enum: ['APPROVED', 'NEEDS_CORRECTION', 'REJECTED'] },
  topic: { type: Type.STRING },
  auditLogs: {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        type: { type: Type.STRING, enum: ['CONCEPTUAL', 'NUMERICAL', 'LOGICAL', 'GRAMMATICAL'] },
        message: { type: Type.STRING },
        severity: { type: Type.STRING, enum: ['HIGH', 'MEDIUM', 'LOW'] }
      },
      required: ['type', 'message', 'severity']
    }
  },
  originalParsed: {
    type: Type.OBJECT,
    properties: {
      question: { type: Type.STRING },
      options: { type: Type.ARRAY, items: { type: Type.STRING } },
      correctOptionIndex: { type: Type.NUMBER },
      solution: { type: Type.STRING }
    },
    required: ['question', 'options', 'correctOptionIndex', 'solution']
  },
  redlines: {
    type: Type.OBJECT,
    properties: {
      question: { type: Type.STRING },
      options: { type: Type.ARRAY, items: { type: Type.STRING } },
      solution: { type: Type.STRING }
    },
    required: ['question', 'options', 'solution']
  },
  clean: {
    type: Type.OBJECT,
    properties: {
      question: { type: Type.STRING },
      options: { type: Type.ARRAY, items: { type: Type.STRING } },
      correctOptionIndex: { type: Type.NUMBER },
      solution: { type: Type.STRING }
    },
    required: ['question', 'options', 'correctOptionIndex', 'solution']
  }
};

export const auditRawQuestion = async (rawText: string): Promise<any[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const prompt = `Parse and Audit this content. It may contain one or multiple multiple-choice questions. Extract them all. Remove all complex math notations and use simple text: """ ${rawText} """`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: questionSchemaProperties,
            required: ['status', 'topic', 'auditLogs', 'originalParsed', 'redlines', 'clean']
          }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Audit Error:", error);
    throw error;
  }
};

export const auditQuestion = async (q: QuestionData['original']): Promise<any> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const prompt = `Audit this existing question. Ensure all complex symbols/LaTeX are replaced with plain text:
    Question: ${q.question}
    Options: ${q.options.map((opt, i) => `${String.fromCharCode(65 + i)}) ${opt}`).join(', ')}
    Correct Index: ${q.correctOptionIndex}
    Solution: ${q.solution}`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          systemInstruction: SYSTEM_PROMPT,
          temperature: 0,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: questionSchemaProperties,
            required: ['status', 'topic', 'auditLogs', 'originalParsed', 'redlines', 'clean']
          }
        }
    });
    return JSON.parse(response.text);
};

export const auditDocument = async (base64Data: string, mimeType: string): Promise<any[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const DOCUMENT_AUDIT_PROMPT = `Extract ALL multiple-choice questions from this document. Replace all complex math notations/LaTeX with simple plain text (e.g., Delta U instead of symbols). Perform a rigorous audit for each question.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        { inlineData: { data: base64Data, mimeType: mimeType } }, 
        { text: DOCUMENT_AUDIT_PROMPT }
      ],
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: questionSchemaProperties,
            required: ['status', 'topic', 'auditLogs', 'originalParsed', 'redlines', 'clean']
          }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Document Audit Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { QuestionData } from '../types';
import { auditRawQuestion, auditDocument } from '../services/geminiService';

interface QuestionInputProps {
  onAdd: (q: QuestionData) => void;
  onAddBulk: (qs: QuestionData[]) => void;
}

const LOADING_MESSAGES = [
  "Detecting question components...",
  "Parsing options A, B, C, D...",
  "Extracting solution logic...",
  "Verifying academic accuracy...",
  "Generating redline comparison...",
];

const QuestionInput: React.FC<QuestionInputProps> = ({ onAdd, onAddBulk }) => {
  const [activeTab, setActiveTab] = useState<'SINGLE' | 'UPLOAD'>('SINGLE');
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState(LOADING_MESSAGES[0]);
  const [progress, setProgress] = useState(0);
  const [rawInput, setRawInput] = useState('');
  const [inputQueue, setInputQueue] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    let interval: any;
    if (isProcessing) {
      let idx = 0;
      interval = setInterval(() => {
        idx = (idx + 1) % LOADING_MESSAGES.length;
        setLoadingMessage(LOADING_MESSAGES[idx]);
      }, 2000);
    }
    return () => clearInterval(interval);
  }, [isProcessing]);

  const addToQueue = () => {
    if (!rawInput.trim()) return;
    setInputQueue(prev => [...prev, rawInput.trim()]);
    setRawInput('');
  };

  const removeFromQueue = (idx: number) => {
    setInputQueue(prev => prev.filter((_, i) => i !== idx));
  };

  const handleSmartPasteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Include current input if it's not empty
    const itemsToProcess = [...inputQueue];
    if (rawInput.trim()) itemsToProcess.push(rawInput.trim());

    if (itemsToProcess.length === 0) return;

    setIsProcessing(true);
    setProgress(10);
    try {
      const combinedInput = itemsToProcess.join('\n\n---NEXT QUESTION---\n\n');
      const results = await auditRawQuestion(combinedInput);

      const mappedQuestions: QuestionData[] = results.map((result: any) => ({
        id: Math.random().toString(36).substr(2, 9),
        topic: result.topic || 'General',
        original: result.originalParsed,
        audit: {
          status: result.status,
          logs: result.auditLogs,
          redlines: result.redlines,
          clean: result.clean
        },
        version: 2,
        lastModified: Date.now()
      }));

      setProgress(100);
      setTimeout(() => {
        onAddBulk(mappedQuestions);
        setRawInput('');
        setInputQueue([]);
        setIsProcessing(false);
      }, 500);
    } catch (err) {
      alert("AI failed to parse the questions. Please ensure the text contains clear questions, options, and solutions.");
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsProcessing(true);
    const allParsedQuestions: QuestionData[] = [];

    try {
      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        setLoadingMessage(`Reading ${file.name} (${i + 1} of ${files.length})...`);
        setProgress(((i) / files.length) * 100);

        const fileContent = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onload = () => resolve((reader.result as string).split(',')[1]);
          reader.readAsDataURL(file);
        });

        const results = await auditDocument(fileContent, file.type);

        const mapped = results.map((res: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          topic: res.topic || `From ${file.name}`,
          original: res.originalParsed,
          audit: {
            status: res.status,
            logs: res.auditLogs,
            redlines: res.redlines,
            clean: res.clean
          },
          version: 2,
          lastModified: Date.now()
        }));

        allParsedQuestions.push(...mapped);
      }

      setProgress(100);
      setTimeout(() => {
        onAddBulk(allParsedQuestions);
        setIsProcessing(false);
      }, 500);
    } catch (err) {
      console.error(err);
      alert("Failed to process one or more documents. Ensure files contain clear MCQ content.");
      setIsProcessing(false);
    } finally {
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden mb-8">
      <div className="flex border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('SINGLE')}
          className={`flex-1 py-4 text-xs font-bold uppercase tracking-wider transition ${activeTab === 'SINGLE' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50/30' : 'text-slate-400 hover:text-slate-600'}`}
        >
          Smart Paste {inputQueue.length > 0 && `(${inputQueue.length})`}
        </button>
        <button 
          onClick={() => setActiveTab('UPLOAD')}
          className={`flex-1 py-4 text-xs font-bold uppercase tracking-wider transition ${activeTab === 'UPLOAD' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50/30' : 'text-slate-400 hover:text-slate-600'}`}
        >
          Bulk File Upload
        </button>
      </div>

      <div className="p-8 relative min-h-[400px]">
        {isProcessing && (
          <div className="absolute inset-0 bg-white/95 backdrop-blur-sm z-10 flex flex-col items-center justify-center space-y-6">
            <div className="relative">
              <div className="w-16 h-16 border-4 border-slate-100 rounded-full"></div>
              <div className="absolute inset-0 w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            </div>
            <div className="text-center px-6 max-w-sm">
              <h3 className="text-lg font-black text-slate-900 uppercase tracking-widest">AI Audit Active</h3>
              <p className="text-xs font-bold text-indigo-600 animate-pulse mt-1 h-4">{loadingMessage}</p>
              <div className="mt-6 w-64 h-2 bg-slate-100 rounded-full overflow-hidden mx-auto border border-slate-200">
                <div 
                  className="h-full bg-indigo-600 transition-all duration-500 rounded-full shadow-[0_0_8px_rgba(79,70,229,0.4)]"
                  style={{ width: `${progress}%` }}
                ></div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'SINGLE' ? (
          <div className="space-y-6">
            <div className="space-y-4">
              <div>
                <div className="flex justify-between items-center mb-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Question Workspace</label>
                  {inputQueue.length > 0 && (
                    <span className="text-[9px] font-black bg-indigo-100 text-indigo-600 px-2 py-0.5 rounded-full uppercase">
                      {inputQueue.length} Staged in Queue
                    </span>
                  )}
                </div>
                <textarea 
                  rows={8}
                  className="w-full px-5 py-4 rounded-2xl border-2 border-slate-100 focus:border-indigo-500 focus:ring-0 transition resize-none bg-slate-50/50 text-slate-800 font-medium font-mono text-sm leading-relaxed"
                  placeholder={`Paste Question Here...\nExample: Q1. What is 2+2? (A) 3 (B) 4 (C) 5 (D) 6\nCorrect: B\nSolution: Basic arithmetic.`}
                  value={rawInput}
                  onChange={e => setRawInput(e.target.value)}
                />
              </div>

              {inputQueue.length > 0 && (
                <div className="space-y-2">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Queued for Audit</p>
                  <div className="flex flex-wrap gap-2">
                    {inputQueue.map((snippet, idx) => (
                      <div key={idx} className="flex items-center gap-2 bg-white border border-slate-200 px-3 py-1.5 rounded-lg shadow-sm">
                        <span className="text-[10px] font-bold text-slate-500 truncate max-w-[120px]">#{idx+1}: {snippet.slice(0, 15)}...</span>
                        <button 
                          onClick={() => removeFromQueue(idx)}
                          className="text-red-400 hover:text-red-600 transition-colors"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
                          </svg>
                        </button>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="flex flex-col sm:flex-row gap-4 pt-4 border-t border-slate-100">
              <button 
                onClick={addToQueue}
                disabled={!rawInput.trim()}
                className="flex-1 px-6 py-3.5 border-2 border-indigo-100 text-indigo-600 hover:bg-indigo-50 disabled:opacity-30 font-black rounded-xl transition active:scale-95 text-[10px] uppercase tracking-widest"
              >
                + Add Another Question
              </button>
              <button 
                onClick={handleSmartPasteSubmit}
                disabled={(inputQueue.length === 0 && !rawInput.trim()) || isProcessing}
                className="flex-[1.5] px-10 py-3.5 bg-slate-900 hover:bg-indigo-600 disabled:bg-slate-300 text-white font-black rounded-xl shadow-xl shadow-indigo-100 transition active:scale-95 text-[10px] uppercase tracking-[0.2em]"
              >
                Run Batch AI Audit ({inputQueue.length + (rawInput.trim() ? 1 : 0)})
              </button>
            </div>
          </div>
        ) : (
          <div className="py-12 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-3xl hover:border-indigo-400 transition-colors group bg-slate-50/50">
            <div className="p-4 bg-indigo-50 rounded-2xl group-hover:bg-indigo-100 transition-colors">
              <svg className="w-12 h-12 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
            </div>
            <div className="mt-6 text-center px-4">
              <h3 className="text-lg font-black text-slate-900 uppercase tracking-wide">Multi-File Processor</h3>
              <p className="text-sm text-slate-500 mt-2 font-medium">Select multiple PDF or DOCX files to audit in bulk.</p>
            </div>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="mt-8 px-12 py-3.5 bg-slate-900 text-white text-[10px] font-black uppercase tracking-[0.2em] rounded-full hover:bg-indigo-600 transition shadow-xl"
            >
              Select Files
            </button>
            <input 
              type="file" 
              className="hidden" 
              ref={fileInputRef} 
              accept=".pdf,.docx"
              multiple
              onChange={handleFileUpload}
            />
          </div>
        )}
      </div>
    </div>
  );
};

