                onClick={handleResetFilters}
                className="mt-6 text-[10px] font-black text-indigo-600 uppercase tracking-widest hover:underline"
              >
                Reset All Filters
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

