import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import QuestionInput from './components/QuestionInput';
import QuestionCard from './components/QuestionCard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import { UserRole, QuestionData, Paper, QuestionStatus, AuditLog } from './types';
import { auditQuestion } from './services/geminiService';

const STORAGE_KEY_ACTIVE_ID = 'paperchecker_active_paper_id';
const STORAGE_KEY_HISTORY = 'paperchecker_paper_history';
const STORAGE_KEY_DARK_MODE = 'paperchecker_dark_mode';

const App: React.FC = () => {
  const [activeRole, setActiveRole] = useState<UserRole>(UserRole.TEACHER);
  const [activeTab, setActiveTab] = useState<string>('input');
  const [history, setHistory] = useState<Paper[]>([]);
  const [activePaperId, setActivePaperId] = useState<string | null>(null);
  const [isAuditingId, setIsAuditingId] = useState<string | null>(null);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    try {
      const savedMode = localStorage.getItem(STORAGE_KEY_DARK_MODE);
      if (savedMode !== null) return JSON.parse(savedMode);
    } catch (e) { console.warn("LocalStorage access failed."); }
    return window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  // Derived state: Current Questions
  const currentPaper = useMemo(() => history.find(p => p.id === activePaperId), [history, activePaperId]);
  const questions = useMemo(() => currentPaper?.questions || [], [currentPaper]);

  // Sync dark mode
  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDarkMode);
    try { localStorage.setItem(STORAGE_KEY_DARK_MODE, JSON.stringify(isDarkMode)); } catch (e) {}
  }, [isDarkMode]);

  // Initial Load
  useEffect(() => {
    try {
      const savedHistory = localStorage.getItem(STORAGE_KEY_HISTORY);
      if (savedHistory) {
        const parsed = JSON.parse(savedHistory);
        if (Array.isArray(parsed)) setHistory(parsed);
      }
      const savedActiveId = localStorage.getItem(STORAGE_KEY_ACTIVE_ID);
      if (savedActiveId) setActivePaperId(savedActiveId);
    } catch (e) { console.error("Load failed"); }
  }, []);

  // Persist history
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
      if (activePaperId) {
        localStorage.setItem(STORAGE_KEY_ACTIVE_ID, activePaperId);
      } else {
        localStorage.removeItem(STORAGE_KEY_ACTIVE_ID);
      }
    } catch (e) {}
  }, [history, activePaperId]);

  useEffect(() => {
    if (activeRole === UserRole.TEACHER) {
      if (questions.length > 0 && activeTab === 'input') setActiveTab('review');
    } else {
      setActiveTab('analytics');
    }
  }, [activeRole, questions.length]);

  const updateActivePaperQuestions = (newQuestions: QuestionData[]) => {
    if (!activePaperId) {
      // Create new paper if none active
      const paperName = newQuestions[0]?.topic || 'New Verification';
      const newPaper: Paper = {
        id: Math.random().toString(36).substr(2, 9),
        title: paperName,
        subject: paperName,
        createdBy: 'Faculty User',
        status: 'IN_REVIEW',
        questions: newQuestions,
        createdAt: Date.now()
      };
      setHistory(prev => [newPaper, ...prev]);
      setActivePaperId(newPaper.id);
    } else {
      // Update existing
      setHistory(prev => prev.map(p => 
        p.id === activePaperId ? { ...p, questions: newQuestions } : p
      ));
    }
  };

  const handleAddBulk = (qs: QuestionData[]) => {
    updateActivePaperQuestions([...questions, ...qs]);
    setActiveTab('review');
  };

  const handleAuditRequest = async (id: string) => {
    const q = questions.find(item => item.id === id);
    if (!q || !q.original) return;

    setIsAuditingId(id);
    try {
      const result = await auditQuestion(q.original);
      const updatedQuestions = questions.map(item => 
        item.id === id 
          ? { 
              ...item, 
              topic: result.topic || item.topic,
              audit: {
                status: result.status,
                logs: result.auditLogs,
                redlines: result.redlines,
                clean: result.clean
              }, 
              version: item.version + 1 
            } 
          : item
      );
      updateActivePaperQuestions(updatedQuestions);
    } catch (err) {
      alert("Verification failed.");
    } finally {
      setIsAuditingId(null);
    }
  };

  const handleApprove = (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
        : item
    );
    updateActivePaperQuestions(updated);
  };

  const handleApproveAll = () => {
    if (window.confirm("Approve all currently audited questions?")) {
      const updated = questions.map(item => 
        item.audit && item.audit.status !== QuestionStatus.APPROVED
          ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
          : item
      );
      updateActivePaperQuestions(updated);
    }
  };

  const handleReject = (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.REJECTED }, version: item.version + 1 }
        : item
    );
    updateActivePaperQuestions(updated);
  };

  const createNewPaper = () => {
    setActivePaperId(null);
    setActiveTab('input');
  };

  const loadFromHistory = (paper: Paper) => {
    setActivePaperId(paper.id);
    setActiveTab('review');
  };

  const deleteFromHistory = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Delete this paper permanently?")) {
      setHistory(prev => prev.filter(p => p.id !== id));
      if (activePaperId === id) {
        setActivePaperId(null);
        setActiveTab('input');
      }
    }
  };

  const generatePaperContent = () => {
    const title = currentPaper?.title || 'Paper Checker AI Verified';
    const content = questions.map((q, idx) => {
      const data = q.audit?.clean || q.original;
      return `
        <div style="margin-bottom: 30px; page-break-inside: avoid;">
          <h3 style="margin-bottom: 10px; font-family: sans-serif;">Question ${idx + 1}</h3>
          <p style="font-size: 16px; line-height: 1.5; margin-bottom: 15px;">${data.question}</p>
          <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 15px;">
            ${data.options.map((opt, i) => `
              <div style="padding: 8px; border: 1px solid #eee; border-radius: 4px; background: #f8fafc;">
                <strong>${String.fromCharCode(65 + i)})</strong> ${opt}
              </div>
            `).join('')}
          </div>
          <div style="padding: 15px; background: #f8fafc; border-radius: 8px; border-left: 4px solid #6366f1;">
            <p style="font-size: 14px; margin: 0; font-style: italic;">${data.solution}</p>
          </div>
        </div>
      `;
    }).join('');

    return `<html><body style="padding: 40px; font-family: sans-serif;"><h1>${title}</h1>${content}</body></html>`;
  };

  const handleExportPDF = () => {
    const win = window.open('', '_blank');
    if (win) {
      win.document.write(generatePaperContent());
      win.document.close();
      setTimeout(() => win.print(), 500);
    }
  };

  const allLogs: AuditLog[] = history.flatMap(p => p.questions.flatMap(q => q.audit?.logs || []));

  const renderContent = () => {
    switch (activeTab) {
      case 'input':
        return <QuestionInput onAdd={() => {}} onAddBulk={handleAddBulk} />;
      case 'review':
        return (
          <div className="space-y-6">
            <header className="mb-8 flex flex-col md:flex-row md:justify-between md:items-end gap-4">
              <div>
                <h1 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">
                  {currentPaper ? currentPaper.title : 'New Workspace'}
                </h1>
                <p className="text-slate-500 dark:text-slate-300 font-medium">Verify AI corrections and lock content.</p>
              </div>
              <div className="flex flex-wrap gap-2">
                <button 
                  onClick={handleExportPDF}
                  disabled={questions.length === 0}
                  className="px-4 py-2 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 text-[10px] font-black rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 transition disabled:opacity-30 uppercase tracking-widest"
                >
                  📄 Export
                </button>
                <button 
                  onClick={createNewPaper}
                  className="px-6 py-2 bg-indigo-600 text-white text-[10px] font-black rounded-lg shadow-lg hover:bg-indigo-700 transition uppercase tracking-widest"
                >
                  New Paper
                </button>
              </div>
            </header>
            {questions.length === 0 ? (
              <div className="bg-white dark:bg-slate-800 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 p-12 text-center">
                <p className="text-slate-400 dark:text-slate-300 font-bold uppercase tracking-widest text-sm">No Active Session</p>
                <button onClick={() => setActiveTab('input')} className="mt-4 px-6 py-2 bg-indigo-50 text-indigo-600 rounded-full font-bold hover:bg-indigo-100 transition">Start Input</button>
              </div>
            ) : (
              questions.map(q => (
                <QuestionCard key={q.id} data={q} onAudit={handleAuditRequest} isAuditing={isAuditingId === q.id} />
              ))
            )}
          </div>
        );
      case 'analytics':
        return <AnalyticsDashboard logs={allLogs} />;
      case 'approval':
        const pending = questions.filter(q => q.audit && q.audit.status !== QuestionStatus.APPROVED);
        return (
          <div className="space-y-6">
            <header className="mb-8">
              <h1 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">QC Approvals</h1>
              <p className="text-slate-500 dark:text-slate-300 font-medium">Approve {currentPaper?.title || 'current paper'}.</p>
              <button onClick={handleApproveAll} className="mt-4 px-4 py-2 bg-indigo-600 text-white text-[10px] font-black rounded-lg uppercase">Approve All</button>
            </header>
            <div className="space-y-4">
              {pending.length === 0 ? (
                <p className="text-slate-400 font-bold uppercase">No pending questions in this file.</p>
              ) : (
                pending.map(q => (
                  <QuestionCard key={q.id} data={q} onAudit={handleAuditRequest} onApprove={handleApprove} onReject={handleReject} isAuditing={isAuditingId === q.id} showQCControls />
                ))
              )}
            </div>
          </div>
        );
      default: return null;
    }
  };

  return (
    <Layout 
      activeRole={activeRole} onRoleSwitch={setActiveRole}
      activeTab={activeTab} setActiveTab={setActiveTab}
      history={history} onLoadHistory={loadFromHistory}
      activePaperId={activePaperId} createNewPaper={createNewPaper}
      onDeleteHistory={deleteFromHistory}
      isDarkMode={isDarkMode} toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { UserRole, Paper } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeRole: UserRole;
  onRoleSwitch: (role: UserRole) => void;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  history: Paper[];
  onLoadHistory: (paper: Paper) => void;
  onDeleteHistory: (e: React.MouseEvent, id: string) => void;
  activePaperId: string | null;
  createNewPaper: () => void;
  isDarkMode: boolean;
  toggleDarkMode: () => void;
}

const Layout: React.FC<LayoutProps> = ({ 
  children, 
  activeRole, 
  onRoleSwitch, 
  activeTab, 
  setActiveTab,
  history,
  onLoadHistory,
  onDeleteHistory,
  activePaperId,
  createNewPaper,
  isDarkMode,
  toggleDarkMode
}) => {
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);

  useEffect(() => {
    document.body.style.overflow = isDrawerOpen ? 'hidden' : '';
    return () => { document.body.style.overflow = ''; };
  }, [isDrawerOpen]);

  const toggleDrawer = () => setIsDrawerOpen(!isDrawerOpen);
  const closeDrawer = () => setIsDrawerOpen(false);

  const handleTabClick = (tab: string) => {
    setActiveTab(tab);
    closeDrawer();
  };

  const formatTime = (ts: number) => {
    const diff = Date.now() - ts;
    const mins = Math.floor(diff / 60000);
    const hours = Math.floor(mins / 60);
    if (mins < 60) return `${mins}m ago`;
    if (hours < 24) return `${hours}h ago`;
    return new Date(ts).toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
  };

  return (
    <div className="flex min-h-screen bg-slate-50 text-slate-900 dark:bg-slate-900 dark:text-slate-50 transition-colors duration-300">
      <div 
        className={`fixed inset-0 bg-slate-900/60 z-30 lg:hidden transition-all duration-500 ${isDrawerOpen ? 'opacity-100 backdrop-blur-sm' : 'opacity-0 pointer-events-none backdrop-blur-none'}`}
        onClick={closeDrawer}
      />

      <aside 
        className={`
          fixed inset-y-0 left-0 w-72 bg-slate-900 text-white flex flex-col z-40 shadow-2xl transition-all duration-500
          ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'} lg:translate-x-0 lg:static
        `}
      >
        <div className="p-6 border-b border-slate-800 dark:border-slate-700 flex items-center justify-between">
          <div onClick={() => handleTabClick('input')} className="cursor-pointer">
            <h1 className="text-xl font-bold flex items-center gap-2">
              <span className="bg-indigo-600 p-1.5 rounded-lg">🔍</span> Paper Checker
            </h1>
            <p className="text-[10px] text-slate-400 mt-1 uppercase tracking-widest font-black opacity-80">Academic Verification</p>
          </div>
          <button onClick={toggleDarkMode} className="p-2 rounded-full bg-slate-800 hover:bg-slate-700 text-slate-400">
            {isDarkMode ? '☀️' : '🌙'}
          </button>
        </div>

        <nav className="flex-1 p-5 space-y-1 overflow-y-auto custom-scrollbar">
          <p className="px-4 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 mt-4">Workspace</p>
          <button 
            onClick={() => handleTabClick('input')}
            className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-semibold transition-all ${activeTab === 'input' ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            Input Mode
          </button>
          <button 
            onClick={() => handleTabClick('review')}
            className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-semibold transition-all ${activeTab === 'review' ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            Review Pipeline
          </button>

          <div className="pt-8 pb-4">
            <div className="px-4 flex items-center justify-between mb-4">
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Library</p>
              <button 
                onClick={createNewPaper}
                className="text-[9px] bg-indigo-600/20 text-indigo-400 px-2 py-1 rounded-md font-black hover:bg-indigo-600 hover:text-white transition"
              >
                + NEW FILE
              </button>
            </div>

            <div className="space-y-2 px-1">
              {history.length === 0 ? (
                <p className="px-4 text-[10px] text-slate-600 uppercase font-bold italic">No saved papers</p>
              ) : (
                history.map((paper) => (
                  <div key={paper.id} className="relative group">
                    <button
                      onClick={() => onLoadHistory(paper)}
                      className={`w-full text-left p-4 rounded-2xl border transition-all duration-300 active:scale-95 ${activePaperId === paper.id ? 'bg-slate-800 border-indigo-600 shadow-lg' : 'bg-slate-900/40 border-slate-800 hover:bg-slate-800 hover:border-slate-700'}`}
                    >
                      <div className={`text-xs font-bold truncate ${activePaperId === paper.id ? 'text-indigo-400' : 'text-slate-200'}`}>
                        {paper.title}
                      </div>
                      <div className="flex items-center gap-2 mt-2">
                        <span className="text-[9px] bg-slate-800 text-slate-400 px-1.5 py-0.5 rounded border border-slate-700">{paper.questions.length} Qs</span>
                        <span className="text-[9px] text-slate-500 font-bold">{formatTime(paper.createdAt)}</span>
                      </div>
                    </button>
                    <button 
                      onClick={(e) => onDeleteHistory(e, paper.id)}
                      className="absolute top-2 right-2 p-1 text-slate-600 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
                      </svg>
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        </nav>

        <div className="p-4 border-t border-slate-800">
          <button 
            onClick={() => onRoleSwitch(activeRole === UserRole.TEACHER ? UserRole.QC_HEAD : UserRole.TEACHER)}
            className="w-full text-[10px] text-white font-black uppercase tracking-widest bg-slate-800 hover:bg-indigo-600 py-3 rounded-xl transition flex items-center justify-center gap-2"
          >
            {activeRole === UserRole.TEACHER ? 'Switch to QC Mode' : 'Switch to Teacher Mode'}
          </button>
        </div>
      </aside>

      <div className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        <header className="lg:hidden bg-white dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700 px-6 py-4 flex items-center justify-between sticky top-0 z-20">
          <button onClick={toggleDrawer} className="p-2 text-slate-600 dark:text-slate-300">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" />
            </svg>
          </button>
          <span className="font-black text-slate-900 dark:text-slate-50 uppercase tracking-tighter">Paper Checker AI</span>
          <div className="w-10"></div>
        </header>

        <main className="flex-1 overflow-y-auto custom-scrollbar p-6 lg:p-10">
          <div className="max-w-6xl mx-auto pb-10">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
};

