  useEffect(() => {
    if (activeRole === UserRole.TEACHER) {
      if (questions.length > 0 && activeTab === 'input') {
        setActiveTab('review');
      }
    } else if (activeTab === 'input') {
       setActiveTab('analytics');
    }
  }, [activeRole, questions.length, activeTab]);

  // Create a brand new paper entry (Automatic archiving)
  const createPaperFromQuestions = useCallback((qs: QuestionData[]) => {
    const paperName = qs[0]?.topic || 'New Question Set';
    const newPaper: Paper = {
      id: Math.random().toString(36).substr(2, 9),
      title: paperName,
      subject: paperName,
      createdBy: 'Faculty User',
      status: 'IN_REVIEW',
      questions: qs,
      createdAt: Date.now()
    };

    setHistory(prev => [newPaper, ...prev]);
    setActivePaperId(newPaper.id);
    setActiveTab('review');
  }, []);

  // Update questions within the currently active paper
  const updateCurrentPaperQuestions = useCallback((newQuestions: QuestionData[]) => {
    if (!activePaperId) return;
    setHistory(prev => prev.map(p => 
      p.id === activePaperId ? { ...p, questions: newQuestions } : p
    ));
  }, [activePaperId]);

  const handleAddBulk = (qs: QuestionData[]) => {
    // If we're already in a session and it's empty, or we want each bulk to be its own file
    // We treat each "Add Bulk" call (from one file or one paste) as a separate archival entry
    createPaperFromQuestions(qs);
  };

  const handleAuditRequest = async (id: string) => {
    const q = questions.find(item => item.id === id);
    if (!q || !q.original) return;

    setIsAuditingId(id);
    try {
      const result = await auditQuestion(q.original);
      const updatedQuestions = questions.map(item => 
        item.id === id 
          ? { 
              ...item, 
              topic: result.topic || item.topic,
              audit: {
                status: result.status,
                logs: result.auditLogs,
                redlines: result.redlines,
                clean: result.clean
              }, 
              version: item.version + 1 
            } 
          : item
      );
      updateCurrentPaperQuestions(updatedQuestions);
    } catch (err) {
      alert("Verification failed.");
    } finally {
      setIsAuditingId(null);
    }
  };

  const handleApprove = (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
        : item
    );
    updateCurrentPaperQuestions(updated);
  };

  const handleApproveAll = () => {
    if (window.confirm("Approve all currently audited questions?")) {
      const updated = questions.map(item => 
        item.audit && item.audit.status !== QuestionStatus.APPROVED
          ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
          : item
      );
      updateCurrentPaperQuestions(updated);
    }
  };

  const handleReject = (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.REJECTED }, version: item.version + 1 }
        : item
    );
    updateCurrentPaperQuestions(updated);
  };

  const handleLoadHistory = (paper: Paper) => {
    setActivePaperId(paper.id);
    setActiveTab('review');
  };

  const handleDeleteHistory = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Delete this paper permanently from the archive?")) {
      setHistory(prev => prev.filter(p => p.id !== id));
      if (activePaperId === id) {
        setActivePaperId(null);
        setActiveTab('input');
      }
    }
  };

  const generatePaperContent = () => {
    const title = currentPaper?.title || 'Verified Questions';
    const htmlContent = questions.map((q, idx) => {
      const data = q.audit?.clean || q.original;
      return `
        <div style="margin-bottom: 40px; page-break-inside: avoid; font-family: sans-serif;">
          <h3 style="color: #4f46e5;">Question ${idx + 1}</h3>
          <p style="font-size: 16px;">${data.question}</p>
          <div style="margin: 15px 0;">
            ${data.options.map((opt, i) => `
              <div style="margin-bottom: 5px; padding: 8px; background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 6px;">
                <strong>${String.fromCharCode(65 + i)})</strong> ${opt}
              </div>
            `).join('')}
          </div>
          <div style="padding: 15px; background: #eef2ff; border-radius: 8px; border-left: 4px solid #4f46e5;">
            <p style="margin: 0; font-size: 14px; color: #374151;"><strong>Solution:</strong> <em>${data.solution}</em></p>
          </div>
        </div>
      `;
    }).join('');

    return `<html><body style="padding: 50px;"><h1>${title}</h1>${htmlContent}</body></html>`;
  };

  const handleExportPDF = () => {
    const win = window.open('', '_blank');
    if (win) {
      win.document.write(generatePaperContent());
      win.document.close();
      setTimeout(() => win.print(), 500);
    }
  };

  const allLogs: AuditLog[] = history.flatMap(p => p.questions.flatMap(q => q.audit?.logs || []));

  const renderContent = () => {
    // Unique key for the content section ensures React doesn't reuse elements when switching papers
    const workspaceKey = activePaperId || 'new-workspace';

    switch (activeTab) {
      case 'input':
        return <QuestionInput key="input-tab" onAdd={() => {}} onAddBulk={handleAddBulk} />;
      case 'review':
        return (
          <div key={workspaceKey} className="space-y-6 animate-in fade-in duration-300">
            <header className="mb-8 flex flex-col md:flex-row md:justify-between md:items-end gap-4 border-b border-slate-100 dark:border-slate-800 pb-6">
              <div>
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-[10px] font-black bg-indigo-100 dark:bg-indigo-900/40 text-indigo-600 px-2 py-0.5 rounded uppercase tracking-widest">Selected File</span>
                  {currentPaper && <span className="text-[10px] text-slate-400 font-bold">{new Date(currentPaper.createdAt).toLocaleString()}</span>}
                </div>
                <h1 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">
                  {currentPaper ? currentPaper.title : 'Workspace Empty'}
                </h1>
                <p className="text-slate-500 dark:text-slate-400 font-medium">Verify AI corrections and lock content for this specific paper.</p>
              </div>
              <div className="flex flex-wrap gap-2">
                <button 
                  onClick={handleExportPDF}
                  disabled={questions.length === 0}
                  className="px-4 py-2 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 text-[10px] font-black rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 transition disabled:opacity-30 uppercase tracking-widest"
                >
                  📄 Export
                </button>
                <button 
                  onClick={() => { setActivePaperId(null); setActiveTab('input'); }}
                  className="px-6 py-2 bg-indigo-600 text-white text-[10px] font-black rounded-lg shadow-lg hover:bg-indigo-700 transition uppercase tracking-widest"
                >
                  + New Input
                </button>
              </div>
            </header>

            {questions.length === 0 ? (
              <div className="bg-white dark:bg-slate-800 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 p-16 text-center">
                <div className="w-16 h-16 bg-slate-50 dark:bg-slate-700 rounded-full flex items-center justify-center mx-auto mb-4">
                  <svg className="w-8 h-8 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
                  </svg>
                </div>
                <p className="text-slate-400 dark:text-slate-300 font-bold uppercase tracking-widest text-sm">No Paper Selected</p>
                <p className="text-xs text-slate-500 mt-2 mb-6">Select a file from the archive or start a new input.</p>
                <button onClick={() => setActiveTab('input')} className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition shadow-xl">Go to Input</button>
              </div>
            ) : (
              <div className="space-y-6">
                {questions.map(q => (
                  <QuestionCard 
                    key={`${workspaceKey}-${q.id}`} 
                    data={q} 
                    onAudit={handleAuditRequest} 
                    isAuditing={isAuditingId === q.id} 
                  />
                ))}
              </div>
            )}
          </div>
        );
      case 'analytics':
        return <AnalyticsDashboard logs={allLogs} />;
      case 'approval':
        const pending = questions.filter(q => q.audit && q.audit.status !== QuestionStatus.APPROVED);
        return (
          <div key={`qc-${workspaceKey}`} className="space-y-6 animate-in fade-in duration-300">
            <header className="mb-8">
              <h1 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">QC Approvals</h1>
              <p className="text-slate-500 dark:text-slate-400 font-medium">Final review for: <span className="text-indigo-600 font-bold">{currentPaper?.title || 'No Paper Selected'}</span></p>
              <button 
                onClick={handleApproveAll} 
                disabled={pending.length === 0}
                className="mt-6 px-6 py-2.5 bg-indigo-600 text-white text-[10px] font-black rounded-lg uppercase tracking-widest hover:bg-indigo-700 transition disabled:opacity-30 shadow-lg"
              >
                Approve All Pending
              </button>
            </header>
            <div className="space-y-4">
              {pending.length === 0 ? (
                <div className="p-12 border border-dashed border-slate-200 dark:border-slate-700 rounded-2xl text-center">
                  <p className="text-slate-400 font-bold uppercase text-xs tracking-widest">All questions approved or none pending in this file.</p>
                </div>
              ) : (
                pending.map(q => (
                  <QuestionCard 
                    key={`qc-${workspaceKey}-${q.id}`} 
                    data={q} 
                    onAudit={handleAuditRequest} 
                    onApprove={handleApprove} 
                    onReject={handleReject} 
                    isAuditing={isAuditingId === q.id} 
                    showQCControls 
                  />
                ))
              )}
            </div>
          </div>
        );
      default: return null;
    }
  };

  return (
    <Layout 
      activeRole={activeRole} 
      onRoleSwitch={setActiveRole}
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      history={history} 
      onLoadHistory={handleLoadHistory}
      activePaperId={activePaperId} 
      createNewPaper={() => { setActivePaperId(null); setActiveTab('input'); }}
      onDeleteHistory={handleDeleteHistory}
      isDarkMode={isDarkMode} 
      toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { QuestionData } from '../types';
import { auditRawQuestion, auditDocument } from '../services/geminiService';

interface QuestionInputProps {
  onAdd: (q: QuestionData) => void;
  onAddBulk: (qs: QuestionData[]) => void;
}

const LOADING_MESSAGES = [
  "Detecting question components...",
  "Parsing options A, B, C, D...",
  "Extracting solution logic...",
  "Verifying academic accuracy...",
  "Generating redline comparison...",
];

const QuestionInput: React.FC<QuestionInputProps> = ({ onAdd, onAddBulk }) => {
  const [activeTab, setActiveTab] = useState<'SINGLE' | 'UPLOAD'>('SINGLE');
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState(LOADING_MESSAGES[0]);
  const [progress, setProgress] = useState(0);
  const [rawInput, setRawInput] = useState('');
  const [stagedSnippets, setStagedSnippets] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    let interval: any;
    if (isProcessing) {
      let idx = 0;
      interval = setInterval(() => {
        idx = (idx + 1) % LOADING_MESSAGES.length;
        setLoadingMessage(LOADING_MESSAGES[idx]);
      }, 2000);
    }
    return () => clearInterval(interval);
  }, [isProcessing]);

  const handleStageSnippet = () => {
    if (!rawInput.trim()) return;
    setStagedSnippets(prev => [...prev, rawInput.trim()]);
    setRawInput('');
  };

  const removeStagedSnippet = (index: number) => {
    setStagedSnippets(prev => prev.filter((_, i) => i !== index));
  };

  const handleSmartPasteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const finalQueue = [...stagedSnippets];
    if (rawInput.trim()) finalQueue.push(rawInput.trim());

    if (finalQueue.length === 0) return;

    setIsProcessing(true);
    setProgress(10);
    try {
      const combinedInput = finalQueue.join('\n\n---NEXT QUESTION---\n\n');
      const results = await auditRawQuestion(combinedInput);

      const mappedQuestions: QuestionData[] = results.map((result: any) => ({
        id: Math.random().toString(36).substr(2, 9),
        topic: result.topic || 'Pasted Content',
        original: result.originalParsed,
        audit: {
          status: result.status,
          logs: result.auditLogs,
          redlines: result.redlines,
          clean: result.clean
        },
        version: 2,
        lastModified: Date.now()
      }));

      setProgress(100);
      setTimeout(() => {
        onAddBulk(mappedQuestions);
        setRawInput('');
        setStagedSnippets([]);
        setIsProcessing(false);
      }, 500);
    } catch (err) {
      alert("AI failed to parse the questions. Please ensure the text format is clear.");
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsProcessing(true);
    const filesArray: File[] = Array.from(files);

    try {
      for (let i = 0; i < filesArray.length; i++) {
        const file = filesArray[i];
        setLoadingMessage(`Processing ${file.name} (${i + 1} of ${filesArray.length})...`);
        setProgress(Math.floor((i / filesArray.length) * 100));

        const base64 = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onload = () => {
            const result = reader.result as string;
            resolve(result.split(',')[1]);
          };
          reader.readAsDataURL(file);
        });

        const results = await auditDocument(base64, file.type);

        const mapped = results.map((res: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          topic: `[${file.name}] ${res.topic || 'General'}`,
          original: res.originalParsed,
          audit: {
            status: res.status,
            logs: res.auditLogs,
            redlines: res.redlines,
            clean: res.clean
          },
          version: 2,
          lastModified: Date.now()
        }));

        // Trigger onAddBulk for EACH file to create separate archival entries
        onAddBulk(mapped);
      }

      setProgress(100);
      setTimeout(() => {
        setIsProcessing(false);
      }, 500);
    } catch (err) {
      console.error(err);
      alert("Failed to process one or more files.");
      setIsProcessing(false);
    } finally {
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  return (
    <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-700 overflow-hidden mb-8">
      <div className="flex border-b border-slate-200 dark:border-slate-700">
        <button 
          onClick={() => setActiveTab('SINGLE')}
          className={`flex-1 py-4 text-xs font-bold uppercase tracking-wider transition ${activeTab === 'SINGLE' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50/30 dark:bg-indigo-900/30' : 'text-slate-400 hover:text-slate-600 dark:hover:text-slate-200'}`}
        >
          Smart Paste {stagedSnippets.length > 0 && `(${stagedSnippets.length})`}
        </button>
        <button 
          onClick={() => setActiveTab('UPLOAD')}
          className={`flex-1 py-4 text-xs font-bold uppercase tracking-wider transition ${activeTab === 'UPLOAD' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50/30 dark:bg-indigo-900/30' : 'text-slate-400 hover:text-slate-600 dark:hover:text-slate-200'}`}
        >
          Bulk File Upload
        </button>
      </div>

      <div className="p-8 relative min-h-[400px]">
        {isProcessing && (
          <div className="absolute inset-0 bg-white/95 dark:bg-slate-900/95 backdrop-blur-sm z-10 flex flex-col items-center justify-center space-y-6">
            <div className="relative">
              <div className="w-16 h-16 border-4 border-slate-100 dark:border-slate-700 rounded-full"></div>
              <div className="absolute inset-0 w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            </div>
            <div className="text-center px-6 max-w-sm">
              <h3 className="text-lg font-black text-slate-900 dark:text-slate-50 uppercase tracking-widest">AI Extraction Active</h3>
              <p className="text-xs font-bold text-indigo-600 animate-pulse mt-1 h-4">{loadingMessage}</p>
              <div className="mt-6 w-64 h-2 bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden mx-auto border border-slate-200 dark:border-slate-600">
                <div 
                  className="h-full bg-indigo-600 transition-all duration-500 rounded-full shadow-[0_0_8px_rgba(79,70,229,0.4)]"
                  style={{ width: `${progress}%` }}
                ></div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'SINGLE' ? (
          <div className="space-y-6">
            <div className="space-y-4">
              <div>
                <div className="flex justify-between items-center mb-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Raw Input Workspace</label>
                  <span className="text-[10px] font-bold text-slate-300 dark:text-slate-500">Separated by clear labels (Q, Options, Solution)</span>
                </div>
                <textarea 
                  rows={8}
                  className="w-full px-5 py-4 rounded-2xl border-2 border-slate-100 dark:border-slate-700 focus:border-indigo-500 focus:ring-0 transition resize-none bg-slate-50/50 dark:bg-slate-700/50 text-slate-800 dark:text-slate-200 font-medium font-mono text-sm leading-relaxed"
                  placeholder="Paste questions here. AI will detect and organize them into a new file..."
                  value={rawInput}
                  onChange={e => setRawInput(e.target.value)}
                />
              </div>

              {stagedSnippets.length > 0 && (
                <div className="space-y-3">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Staged Batches ({stagedSnippets.length})</p>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {stagedSnippets.map((snippet, idx) => (
                      <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-xl group hover:border-indigo-200 transition">
                        <div className="flex items-center gap-3 overflow-hidden">
                          <span className="w-5 h-5 flex items-center justify-center bg-slate-200 dark:bg-slate-600 text-slate-500 dark:text-slate-300 rounded-full text-[10px] font-bold shrink-0">{idx + 1}</span>
                          <p className="text-[11px] font-medium text-slate-600 dark:text-slate-300 truncate">{snippet.slice(0, 40)}...</p>
                        </div>
                        <button 
                          onClick={() => removeStagedSnippet(idx)}
                          className="text-slate-300 hover:text-red-500 transition-colors p-1"
                        >
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                          </svg>
                        </button>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="flex flex-col sm:flex-row gap-4 pt-4 border-t border-slate-100 dark:border-slate-700">
              <button 
                type="button"
                onClick={handleStageSnippet}
                disabled={!rawInput.trim() || isProcessing}
                className="flex-1 px-6 py-3.5 border-2 border-indigo-600 text-indigo-600 hover:bg-indigo-50 disabled:opacity-30 disabled:border-slate-300 disabled:text-slate-400 font-black rounded-xl transition active:scale-95 text-[10px] uppercase tracking-widest flex items-center justify-center gap-2"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" />
                </svg>
                Stage for Process
              </button>
              <button 
                type="button"
                onClick={handleSmartPasteSubmit}
                disabled={(stagedSnippets.length === 0 && !rawInput.trim()) || isProcessing}
                className="flex-[1.5] px-10 py-3.5 bg-slate-900 hover:bg-indigo-600 disabled:bg-slate-300 dark:disabled:bg-slate-600 text-white font-black rounded-xl shadow-xl transition active:scale-95 text-[10px] uppercase tracking-[0.2em]"
              >
                Auto-Archive & Verify ({stagedSnippets.length + (rawInput.trim() ? 1 : 0)})
              </button>
            </div>
          </div>
        ) : (
          <div className="py-12 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl hover:border-indigo-400 transition-colors group bg-slate-50/50 dark:bg-slate-700/50">
            <div className="p-4 bg-indigo-50 dark:bg-indigo-900/40 rounded-2xl group-hover:bg-indigo-100 transition-colors">
              <svg className="w-12 h-12 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 13h6m-3-3v6m5 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
            </div>
            <div className="mt-6 text-center px-4">
              <h3 className="text-lg font-black text-slate-900 dark:text-slate-50 uppercase tracking-wide">Multi-Document Intake</h3>
              <p className="text-sm text-slate-500 dark:text-slate-400 mt-2 font-medium">Each file will be saved as a separate archive entry.</p>
            </div>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="mt-8 px-12 py-3.5 bg-slate-900 text-white text-[10px] font-black uppercase tracking-[0.2em] rounded-full hover:bg-indigo-600 transition shadow-xl"
            >
              Select PDF/DOCX
            </button>
            <input 
              type="file" 
              className="hidden" 
              ref={fileInputRef} 
              accept=".pdf,.docx" 
              multiple 
              onChange={handleFileUpload} 
            />
          </div>
        )}
      </div>
    </div>
  );
};

export default QuestionInput;

import React, { useState, useEffect } from 'react';
import { UserRole, Paper } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeRole: UserRole;
  onRoleSwitch: (role: UserRole) => void;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  history: Paper[];
  onLoadHistory: (paper: Paper) => void;
  onDeleteHistory: (e: React.MouseEvent, id: string) => void;
  activePaperId: string | null;
  createNewPaper: () => void;
  isDarkMode: boolean;
  toggleDarkMode: () => void;
}

const Layout: React.FC<LayoutProps> = ({ 
  children, 
  activeRole, 
  onRoleSwitch, 
  activeTab, 
  setActiveTab,
  history,
  onLoadHistory,
  onDeleteHistory,
  activePaperId,
  createNewPaper,
  isDarkMode,
  toggleDarkMode
}) => {
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);

  useEffect(() => {
    document.body.style.overflow = isDrawerOpen ? 'hidden' : '';
    return () => { document.body.style.overflow = ''; };
  }, [isDrawerOpen]);

  const toggleDrawer = () => setIsDrawerOpen(!isDrawerOpen);
  const closeDrawer = () => setIsDrawerOpen(false);

  const handleTabClick = (tab: string) => {
    setActiveTab(tab);
    closeDrawer();
  };

  const formatTime = (ts: number) => {
    const diff = Date.now() - ts;
    const mins = Math.floor(diff / 60000);
    const hours = Math.floor(mins / 60);
    if (mins < 60) return `${mins}m ago`;
    if (hours < 24) return `${hours}h ago`;
    return new Date(ts).toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
  };

  return (
    <div className="flex min-h-screen bg-slate-50 text-slate-900 dark:bg-slate-900 dark:text-slate-50 transition-colors duration-300">
      {/* Mobile Drawer Overlay */}
      <div 
        className={`fixed inset-0 bg-slate-900/60 z-30 lg:hidden transition-all duration-500 ${isDrawerOpen ? 'opacity-100 backdrop-blur-sm' : 'opacity-0 pointer-events-none backdrop-blur-none'}`}
        onClick={closeDrawer}
      />

      <aside 
        className={`
          fixed inset-y-0 left-0 w-72 bg-slate-900 text-white flex flex-col z-40 shadow-2xl transition-all duration-500
          ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'} lg:translate-x-0 lg:static
        `}
      >
        <div className="p-6 border-b border-slate-800 dark:border-slate-700 flex items-center justify-between">
          <div onClick={() => handleTabClick('input')} className="cursor-pointer group">
            <h1 className="text-xl font-bold flex items-center gap-2 group-hover:text-indigo-400 transition-colors">
              <span className="bg-indigo-600 p-1.5 rounded-lg shadow-lg shadow-indigo-600/20 group-hover:scale-110 transition-transform">🔍</span> Paper Checker
            </h1>
            <p className="text-[10px] text-slate-400 mt-1 uppercase tracking-widest font-black opacity-80">Academic Verification</p>
          </div>
          <button onClick={toggleDarkMode} className="p-2 rounded-full bg-slate-800 hover:bg-slate-700 text-slate-400 transition-all active:scale-90">
            {isDarkMode ? '☀️' : '🌙'}
          </button>
        </div>

        <nav className="flex-1 p-5 space-y-1 overflow-y-auto custom-scrollbar">
          <p className="px-4 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 mt-4">Main Menu</p>
          <button 
            onClick={() => handleTabClick('input')}
            className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-semibold transition-all duration-300 ${activeTab === 'input' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
            Paper Input
          </button>
          <button 
            onClick={() => handleTabClick('review')}
            className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-semibold transition-all duration-300 ${activeTab === 'review' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
            Audit Review
          </button>

          <div className="pt-10 pb-4">
            <div className="px-4 flex items-center justify-between mb-4">
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Session Archive</p>
              <span className="text-[9px] bg-slate-800 text-indigo-400 px-2 py-0.5 rounded-full font-black border border-slate-700">HIST</span>
            </div>

            <div className="space-y-3 px-1">
              {history.length === 0 ? (
                <div className="px-4 py-5 border border-dashed border-slate-800 rounded-2xl flex flex-col items-center gap-2">
                   <p className="text-[10px] text-slate-600 font-bold uppercase text-center leading-tight">No archived<br/>sessions</p>
                </div>
              ) : (
                history.map((paper) => (
                  <div key={paper.id} className="relative group">
                    <button
                      onClick={() => onLoadHistory(paper)}
                      className={`w-full text-left p-4 rounded-2xl border transition-all duration-300 active:scale-95 ${activePaperId === paper.id ? 'bg-slate-800 border-indigo-600 shadow-xl ring-1 ring-indigo-500/50' : 'bg-slate-900/40 border-slate-800 hover:bg-slate-800 hover:border-slate-700'}`}
                    >
                      <div className={`text-xs font-bold truncate ${activePaperId === paper.id ? 'text-indigo-400' : 'text-slate-200'}`}>
                        {paper.title}
                      </div>
                      <div className="flex items-center gap-2 mt-2.5">
                        <span className={`text-[9px] px-1.5 py-0.5 rounded border ${activePaperId === paper.id ? 'bg-indigo-600/20 text-indigo-300 border-indigo-600/30' : 'bg-slate-800 text-slate-400 border-slate-700'}`}>
                          {paper.questions.length} Qs
                        </span>
                        <span className="text-[9px] text-slate-500 font-bold flex items-center gap-1">
                          <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                          {formatTime(paper.createdAt)}
                        </span>
                      </div>
                    </button>
                    <button 
                      onClick={(e) => onDeleteHistory(e, paper.id)}
                      className="absolute top-2 right-2 p-1.5 text-slate-600 hover:text-red-500 hover:bg-red-500/10 rounded-lg opacity-0 group-hover:opacity-100 transition-all"
                      title="Delete archive entry"
                    >
                      <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                      </svg>
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        </nav>

        <div className="p-4 border-t border-slate-800 bg-slate-900/50">
          <button 
            onClick={() => onRoleSwitch(activeRole === UserRole.TEACHER ? UserRole.QC_HEAD : UserRole.TEACHER)}
            className="w-full text-[10px] text-white font-black uppercase tracking-widest bg-indigo-600 hover:bg-indigo-500 py-3 rounded-xl shadow-lg shadow-indigo-600/20 transition-all flex items-center justify-center gap-2 active:scale-95"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4" /></svg>
            Switch Perspective
          </button>
        </div>
      </aside>

      <div className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        {/* Mobile Header */}
        <header className="lg:hidden bg-white dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700 px-6 py-4 flex items-center justify-between sticky top-0 z-20 shadow-sm transition-colors duration-300">
          <button onClick={toggleDrawer} className="p-2 -ml-2 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" />
            </svg>
          </button>
          <div className="flex items-center gap-2">
            <span className="bg-indigo-600 text-white p-1 rounded shadow-sm">🔍</span>
            <span className="font-black text-slate-900 dark:text-slate-50 uppercase tracking-tighter">Paper Checker AI</span>
          </div>
          <div className="w-10"></div>
        </header>

        <main className="flex-1 overflow-y-auto custom-scrollbar p-6 lg:p-10 scroll-smooth">
          <div className="max-w-6xl mx-auto pb-10">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import Layout from './components/Layout';
import QuestionInput from './components/QuestionInput';
import QuestionCard from './components/QuestionCard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import { UserRole, QuestionData, Paper, QuestionStatus, AuditLog } from './types';
import { auditQuestion } from './services/geminiService';

const STORAGE_KEY_ACTIVE_ID = 'paperchecker_active_paper_id_v2';
const STORAGE_KEY_HISTORY = 'paperchecker_paper_history_v2';
const STORAGE_KEY_DARK_MODE = 'paperchecker_dark_mode_v2';

const App: React.FC = () => {
  const [activeRole, setActiveRole] = useState<UserRole>(UserRole.TEACHER);
  const [activeTab, setActiveTab] = useState<string>('input');
  const [history, setHistory] = useState<Paper[]>([]);
  const [activePaperId, setActivePaperId] = useState<string | null>(null);
  const [isAuditingId, setIsAuditingId] = useState<string | null>(null);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    try {
      const savedMode = localStorage.getItem(STORAGE_KEY_DARK_MODE);
      if (savedMode !== null) return JSON.parse(savedMode);
    } catch (e) { console.warn("LocalStorage access failed."); }
    return window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  // Derived state: Strictly find the paper in history based on the active ID
  const currentPaper = useMemo(() => {
    return history.find(p => p.id === activePaperId) || null;
  }, [history, activePaperId]);

  const questions = useMemo(() => {
    return currentPaper?.questions || [];
  }, [currentPaper]);

  // Sync dark mode class
  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDarkMode);
    try { localStorage.setItem(STORAGE_KEY_DARK_MODE, JSON.stringify(isDarkMode)); } catch (e) {}
  }, [isDarkMode]);

  // Initial Load from localStorage
  useEffect(() => {
    try {
      const savedHistory = localStorage.getItem(STORAGE_KEY_HISTORY);
      if (savedHistory) {
        const parsed = JSON.parse(savedHistory);
        if (Array.isArray(parsed)) setHistory(parsed);
      }
      const savedActiveId = localStorage.getItem(STORAGE_KEY_ACTIVE_ID);
      if (savedActiveId) setActivePaperId(savedActiveId);
    } catch (e) { console.error("History load failed"); }
  }, []);

  // Persist history and active ID whenever they change
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
      if (activePaperId) {
        localStorage.setItem(STORAGE_KEY_ACTIVE_ID, activePaperId);
      } else {
        localStorage.removeItem(STORAGE_KEY_ACTIVE_ID);
      }
    } catch (e) {}
  }, [history, activePaperId]);

  // Automatically switch tabs based on content presence
  useEffect(() => {
    if (activeRole === UserRole.TEACHER) {
      if (questions.length > 0 && activeTab === 'input') {
        setActiveTab('review');
      }
    } else if (activeTab === 'input') {
       setActiveTab('analytics');
    }
  }, [activeRole, questions.length, activeTab]);

  // Create a brand new paper entry (Automatic archiving)
  const createPaperFromQuestions = useCallback((qs: QuestionData[]) => {
    const paperName = qs[0]?.topic || 'New Question Set';
    const newPaper: Paper = {
      id: Math.random().toString(36).substr(2, 9),
      title: paperName,
      subject: paperName,
      createdBy: 'Faculty User',
      status: 'IN_REVIEW',
      questions: qs,
      createdAt: Date.now()
    };

    setHistory(prev => [newPaper, ...prev]);
    setActivePaperId(newPaper.id);
    setActiveTab('review');
  }, []);

  // Update questions within the currently active paper
  const updateCurrentPaperQuestions = useCallback((newQuestions: QuestionData[]) => {
    if (!activePaperId) return;
    setHistory(prev => prev.map(p => 
      p.id === activePaperId ? { ...p, questions: newQuestions } : p
    ));
  }, [activePaperId]);

  const handleAddBulk = (qs: QuestionData[]) => {
    createPaperFromQuestions(qs);
  };

  const handleAuditRequest = async (id: string) => {
    const q = questions.find(item => item.id === id);
    if (!q || !q.original) return;

    setIsAuditingId(id);
    try {
      const result = await auditQuestion(q.original);
      const updatedQuestions = questions.map(item => 
        item.id === id 
          ? { 
              ...item, 
              topic: result.topic || item.topic,
              audit: {
                status: result.status,
                logs: result.auditLogs,
                redlines: result.redlines,
                clean: result.clean
              }, 
              version: item.version + 1 
            } 
          : item
      );
      updateCurrentPaperQuestions(updatedQuestions);
    } catch (err) {
      alert("Verification failed.");
    } finally {
      setIsAuditingId(null);
    }
  };

  const handleApprove = (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
        : item
    );
    updateCurrentPaperQuestions(updated);
  };

  const handleApproveAll = () => {
    if (window.confirm("Approve all currently audited questions?")) {
      const updated = questions.map(item => 
        item.audit && item.audit.status !== QuestionStatus.APPROVED
          ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
          : item
      );
      updateCurrentPaperQuestions(updated);
    }
  };

  const handleReject = (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.REJECTED }, version: item.version + 1 }
        : item
    );
    updateCurrentPaperQuestions(updated);
  };

  const handleLoadHistory = (paper: Paper) => {
    setActivePaperId(paper.id);
    setActiveTab('review');
  };

  const handleDeleteHistory = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Delete this paper permanently from the archive?")) {
      setHistory(prev => prev.filter(p => p.id !== id));
      if (activePaperId === id) {
        setActivePaperId(null);
        setActiveTab('input');
      }
    }
  };

  const generatePaperContent = (isRedlined: boolean = false) => {
    const title = currentPaper?.title || (isRedlined ? 'Audit Report' : 'Verified Questions');
    const htmlContent = questions.map((q, idx) => {
      const data = isRedlined && q.audit?.redlines ? q.audit.redlines : (q.audit?.clean || q.original);
      const cleanData = q.audit?.clean || q.original;

      return `
        <div style="margin-bottom: 40px; page-break-inside: avoid; font-family: sans-serif;">
          <h3 style="color: #4f46e5; margin-bottom: 8px;">Question ${idx + 1}</h3>
          <p style="font-size: 16px; line-height: 1.5;">${data.question}</p>
          <div style="margin: 15px 0;">
            ${data.options.map((opt, i) => `
              <div style="margin-bottom: 5px; padding: 10px; background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 6px; display: flex; align-items: flex-start; gap: 8px;">
                <strong style="color: #6b7280; font-size: 14px;">${String.fromCharCode(65 + i)})</strong>
                <span style="font-size: 14px; flex: 1;">${opt}</span>
                ${!isRedlined && i === cleanData.correctOptionIndex ? '<span style="font-size: 10px; background: #10b981; color: white; padding: 2px 6px; border-radius: 4px; font-weight: bold;">CORRECT</span>' : ''}
              </div>
            `).join('')}
          </div>
          <div style="padding: 15px; background: #eef2ff; border-radius: 8px; border-left: 4px solid #4f46e5;">
            <p style="margin: 0; font-size: 14px; color: #374151;"><strong>Solution Logic:</strong> <em style="display: block; margin-top: 5px;">${data.solution}</em></p>
          </div>
          ${isRedlined && q.audit?.logs && q.audit.logs.length > 0 ? `
            <div style="margin-top: 15px; padding: 10px; border: 1px solid #fee2e2; background: #fef2f2; border-radius: 6px;">
              <strong style="font-size: 11px; text-transform: uppercase; color: #ef4444; display: block; margin-bottom: 5px;">Audit Intervention Notes:</strong>
              ${q.audit.logs.map(log => `<p style="font-size: 12px; margin: 4px 0; color: #b91c1c;">• [${log.type}] ${log.message}</p>`).join('')}
            </div>
          ` : ''}
        </div>
      `;
    }).join('');

    return `
      <html>
        <head>
          <style>
            body { padding: 40px; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; color: #1f2937; }
            h1 { text-align: center; border-bottom: 2px solid #e5e7eb; padding-bottom: 20px; color: #111827; }
            del { background-color: #fee2e2; color: #991b1b; text-decoration: line-through; padding: 0 2px; border-radius: 2px; }
            ins { background-color: #dcfce7; color: #166534; text-decoration: none; font-weight: bold; padding: 0 2px; border-radius: 2px; }
            .header-meta { text-align: right; color: #9ca3af; font-size: 12px; margin-bottom: 30px; }
          </style>
        </head>
        <body>
          <div class="header-meta">Audit System Report • ${new Date().toLocaleString()}</div>
          <h1>${title} ${isRedlined ? '(Intervention Logs)' : ''}</h1>
          ${htmlContent}
        </body>
      </html>
    `;
  };

  const handleExportPDF = () => {
    const win = window.open('', '_blank');
    if (win) {
      win.document.write(generatePaperContent(false));
      win.document.close();
      setTimeout(() => win.print(), 500);
    }
  };

  const handleExportRedlines = () => {
    const win = window.open('', '_blank');
    if (win) {
      win.document.write(generatePaperContent(true));
      win.document.close();
      setTimeout(() => win.print(), 500);
    }
  };

  const allLogs: AuditLog[] = history.flatMap(p => p.questions.flatMap(q => q.audit?.logs || []));

  const renderContent = () => {
    const workspaceKey = activePaperId || 'new-workspace';

    switch (activeTab) {
      case 'input':
        return <QuestionInput key="input-tab" onAdd={() => {}} onAddBulk={handleAddBulk} />;
      case 'review':
        return (
          <div key={workspaceKey} className="space-y-6 animate-in fade-in duration-300">
            <header className="mb-8 flex flex-col md:flex-row md:justify-between md:items-end gap-4 border-b border-slate-100 dark:border-slate-800 pb-6">
              <div>
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-[10px] font-black bg-indigo-100 dark:bg-indigo-900/40 text-indigo-600 px-2 py-0.5 rounded uppercase tracking-widest">Selected File</span>
                  {currentPaper && <span className="text-[10px] text-slate-400 font-bold">{new Date(currentPaper.createdAt).toLocaleString()}</span>}
                </div>
                <h1 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">
                  {currentPaper ? currentPaper.title : 'Workspace Empty'}
                </h1>
                <p className="text-slate-500 dark:text-slate-400 font-medium">Verify AI corrections and lock content for this specific paper.</p>
              </div>
              <div className="flex flex-wrap gap-2">
                <button 
                  onClick={handleExportRedlines}
                  disabled={questions.length === 0}
                  className="px-4 py-2 border-2 border-amber-200 dark:border-amber-900/40 text-amber-700 dark:text-amber-400 text-[10px] font-black rounded-lg hover:bg-amber-50 dark:hover:bg-amber-900/20 transition disabled:opacity-30 uppercase tracking-widest flex items-center gap-2"
                >
                  🚩 Download Redlines
                </button>
                <button 
                  onClick={handleExportPDF}
                  disabled={questions.length === 0}
                  className="px-4 py-2 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 text-[10px] font-black rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 transition disabled:opacity-30 uppercase tracking-widest"
                >
                  📄 Export Clean
                </button>
                <button 
                  onClick={() => { setActivePaperId(null); setActiveTab('input'); }}
                  className="px-6 py-2 bg-indigo-600 text-white text-[10px] font-black rounded-lg shadow-lg hover:bg-indigo-700 transition uppercase tracking-widest"
                >
                  + New Input
                </button>
              </div>
            </header>

            {questions.length === 0 ? (
              <div className="bg-white dark:bg-slate-800 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 p-16 text-center">
                <div className="w-16 h-16 bg-slate-50 dark:bg-slate-700 rounded-full flex items-center justify-center mx-auto mb-4">
                  <svg className="w-8 h-8 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
                  </svg>
                </div>
                <p className="text-slate-400 dark:text-slate-300 font-bold uppercase tracking-widest text-sm">No Paper Selected</p>
                <p className="text-xs text-slate-500 mt-2 mb-6">Select a file from the archive or start a new input.</p>
                <button onClick={() => setActiveTab('input')} className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition shadow-xl">Go to Input</button>
              </div>
            ) : (
              <div className="space-y-6">
                {questions.map(q => (
                  <QuestionCard 
                    key={`${workspaceKey}-${q.id}`} 
                    data={q} 
                    onAudit={handleAuditRequest} 
                    isAuditing={isAuditingId === q.id} 
                  />
                ))}
              </div>
            )}
          </div>
        );
      case 'analytics':
        return <AnalyticsDashboard logs={allLogs} />;
      case 'approval':
        const pending = questions.filter(q => q.audit && q.audit.status !== QuestionStatus.APPROVED);
        return (
          <div key={`qc-${workspaceKey}`} className="space-y-6 animate-in fade-in duration-300">
            <header className="mb-8">
              <h1 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">QC Approvals</h1>
              <p className="text-slate-500 dark:text-slate-400 font-medium">Final review for: <span className="text-indigo-600 font-bold">{currentPaper?.title || 'No Paper Selected'}</span></p>
              <button 
                onClick={handleApproveAll} 
                disabled={pending.length === 0}
                className="mt-6 px-6 py-2.5 bg-indigo-600 text-white text-[10px] font-black rounded-lg uppercase tracking-widest hover:bg-indigo-700 transition disabled:opacity-30 shadow-lg"
              >
                Approve All Pending
              </button>
            </header>
            <div className="space-y-4">
              {pending.length === 0 ? (
                <div className="p-12 border border-dashed border-slate-200 dark:border-slate-700 rounded-2xl text-center">
                  <p className="text-slate-400 font-bold uppercase text-xs tracking-widest">All questions approved or none pending in this file.</p>
                </div>
              ) : (
                pending.map(q => (
                  <QuestionCard 
                    key={`qc-${workspaceKey}-${q.id}`} 
                    data={q} 
                    onAudit={handleAuditRequest} 
                    onApprove={handleApprove} 
                    onReject={handleReject} 
                    isAuditing={isAuditingId === q.id} 
                    showQCControls 
                  />
                ))
              )}
            </div>
          </div>
        );
      default: return null;
    }
  };

  return (
    <Layout 
      activeRole={activeRole} 
      onRoleSwitch={setActiveRole}
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      history={history} 
      onLoadHistory={handleLoadHistory}
      activePaperId={activePaperId} 
      createNewPaper={() => { setActivePaperId(null); setActiveTab('input'); }}
      onDeleteHistory={handleDeleteHistory}
      isDarkMode={isDarkMode} 
      toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

export enum UserRole {
  TEACHER = 'TEACHER',
  QC_HEAD = 'QC_HEAD'
}

export enum QuestionStatus {
  APPROVED = 'APPROVED',
  NEEDS_CORRECTION = 'NEEDS_CORRECTION',
  REJECTED = 'REJECTED',
  PENDING = 'PENDING'
}

export interface AuditLog {
  id: string;
  type: 'CONCEPTUAL' | 'NUMERICAL' | 'LOGICAL' | 'GRAMMATICAL';
  message: string;
  severity: 'HIGH' | 'MEDIUM' | 'LOW';
}

export interface QuestionData {
  id: string;
  topic: string;
  original: {
    question: string;
    options?: string[]; // Optional for numerical/subjective
    correctOptionIndex?: number; // Optional for non-MCQ
    correctAnswer?: string; // For numerical/subjective answers
    solution: string;
  };
  audit?: {
    status: QuestionStatus;
    logs: AuditLog[];
    redlines: {
      question: string;
      options?: string[];
      correctAnswer?: string;
      solution: string;
    };
    clean: {
      question: string;
      options?: string[];
      correctOptionIndex?: number;
      correctAnswer?: string;
      solution: string;
    };
  };
  version: number;
  lastModified: number;
}

export interface Paper {
  id: string;
  title: string;
  subject: string;
  createdBy: string;
  status: 'DRAFT' | 'IN_REVIEW' | 'LOCKED';
  questions: QuestionData[];
  createdAt: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { QuestionData, QuestionStatus } from "../types";

const SYSTEM_PROMPT = `You are a strict academic quality control auditor and parser.

CORE DIRECTIVE: Support both Multiple Choice Questions (MCQ) and Numerical/Subjective problems. 
KEEP IT SIMPLE. DO NOT use LaTeX or complex math notation.

TASK:
1. PARSE: Extract Question Body, Options (if MCQ), Correct Answer (Index 0-3 for MCQ OR a direct value/string for Numerical), and Solution.
2. AUDIT: Verify accuracy and clarity.
   - For numerical problems, verify the calculation logic in the solution.
   - For MCQs, ensure the correct option index matches the solution.

NOTATION RULES (STRICT):
- NO LaTeX. Use plain text (e.g., "q net", "Delta U", "sqrt(x)").

STRICT REDLINING RULES:
- Use <del> for errors and <ins> for corrections.

INPUT HANDLING:
- If a question has NO options (Numerical Problem), set 'options' to an empty array and provide the 'correctAnswer' as a string.
- If a question HAS options, provide 'correctOptionIndex' (0-3).

OUTPUT:
- Return JSON following the schema.`;

const questionSchemaProperties = {
  status: { type: Type.STRING, enum: ['APPROVED', 'NEEDS_CORRECTION', 'REJECTED'] },
  topic: { type: Type.STRING },
  auditLogs: {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        type: { type: Type.STRING, enum: ['CONCEPTUAL', 'NUMERICAL', 'LOGICAL', 'GRAMMATICAL'] },
        message: { type: Type.STRING },
        severity: { type: Type.STRING, enum: ['HIGH', 'MEDIUM', 'LOW'] }
      },
      required: ['type', 'message', 'severity']
    }
  },
  originalParsed: {
    type: Type.OBJECT,
    properties: {
      question: { type: Type.STRING },
      options: { type: Type.ARRAY, items: { type: Type.STRING } },
      correctOptionIndex: { type: Type.NUMBER },
      correctAnswer: { type: Type.STRING },
      solution: { type: Type.STRING }
    },
    required: ['question', 'solution']
  },
  redlines: {
    type: Type.OBJECT,
    properties: {
      question: { type: Type.STRING },
      options: { type: Type.ARRAY, items: { type: Type.STRING } },
      correctAnswer: { type: Type.STRING },
      solution: { type: Type.STRING }
    },
    required: ['question', 'solution']
  },
  clean: {
    type: Type.OBJECT,
    properties: {
      question: { type: Type.STRING },
      options: { type: Type.ARRAY, items: { type: Type.STRING } },
      correctOptionIndex: { type: Type.NUMBER },
      correctAnswer: { type: Type.STRING },
      solution: { type: Type.STRING }
    },
    required: ['question', 'solution']
  }
};

export const auditRawQuestion = async (rawText: string): Promise<any[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Parse and Audit this content. Handle both MCQs and Numerical problems (where only Q, Ans, and Solution are given). Remove LaTeX: """ ${rawText} """`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: questionSchemaProperties,
            required: ['status', 'topic', 'auditLogs', 'originalParsed', 'redlines', 'clean']
          }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Gemini Audit Error:", error);
    throw error;
  }
};

export const auditQuestion = async (q: QuestionData['original']): Promise<any> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `Audit this existing question. Support numerical/subjective formats:
    Question: ${q.question}
    Options: ${q.options ? q.options.map((opt, i) => `${String.fromCharCode(65 + i)}) ${opt}`).join(', ') : 'NONE'}
    Correct Answer/Index: ${q.correctAnswer || q.correctOptionIndex}
    Solution: ${q.solution}`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          systemInstruction: SYSTEM_PROMPT,
          temperature: 0,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: questionSchemaProperties,
            required: ['status', 'topic', 'auditLogs', 'originalParsed', 'redlines', 'clean']
          }
        }
    });
    return JSON.parse(response.text || '{}');
};

export const auditDocument = async (base64Data: string, mimeType: string): Promise<any[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const DOCUMENT_AUDIT_PROMPT = `Extract ALL questions (MCQs and Numerical Problems) from this document. If no options are present, extract the Question, correct Answer, and Solution. Replace all complex math with plain text.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } }, 
          { text: DOCUMENT_AUDIT_PROMPT }
        ]
      },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: questionSchemaProperties,
            required: ['status', 'topic', 'auditLogs', 'originalParsed', 'redlines', 'clean']
          }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Gemini Document Audit Error:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { QuestionData, QuestionStatus } from '../types';

interface QuestionCardProps {
  data: QuestionData;
  onAudit: (id: string) => void;
  onApprove?: (id: string) => void;
  onReject?: (id: string) => void;
  isAuditing: boolean;
  showQCControls?: boolean;
}

const QuestionCard: React.FC<QuestionCardProps> = ({ 
  data, 
  onAudit, 
  onApprove, 
  onReject,
  isAuditing, 
  showQCControls 
}) => {
  const [viewMode, setViewMode] = useState<'AUDIT' | 'CLEAN'>('AUDIT');

  const getStatusStyle = (status: QuestionStatus) => {
    switch (status) {
      case QuestionStatus.APPROVED: return 'bg-green-100 text-green-700 border-green-200';
      case QuestionStatus.NEEDS_CORRECTION: return 'bg-amber-100 text-amber-700 border-amber-200';
      case QuestionStatus.REJECTED: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-slate-100 text-slate-600 border-slate-200';
    }
  };

  const renderRedlined = (html: any) => {
    const safeHtml = typeof html === 'string' ? html : '';
    if (!safeHtml) return <span className="text-slate-400 italic">No content available</span>;

    return (
      <div 
        className="prose-sm max-w-none dark:text-slate-200"
        dangerouslySetInnerHTML={{ 
          __html: safeHtml.replace(/<del>/g, '<del class="bg-red-100 text-red-800 line-through px-1 rounded mx-0.5">')
                      .replace(/<\/del>/g, '</del>')
                      .replace(/<ins>/g, '<ins class="bg-green-100 text-green-800 font-medium px-1 rounded mx-0.5">')
                      .replace(/<\/ins>/g, '</ins>')
        }} 
      />
    );
  };

  // Safely extract content with fallbacks
  const displayOptions = data.audit?.redlines?.options || data.original?.options || [];
  const cleanOptions = data.audit?.clean?.options || [];
  const correctIdx = data.audit?.clean?.correctOptionIndex ?? data.original?.correctOptionIndex ?? 0;
  const isNumerical = displayOptions.length === 0;

  return (
    <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden mb-6 group hover:border-indigo-300 transition">
      {/* Header */}
      <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 dark:border-slate-700 bg-slate-50/50 dark:bg-slate-800/50">
        <div className="flex items-center gap-4">
          <span className="text-xs font-bold uppercase tracking-widest text-slate-400 dark:text-slate-300">Q#{data.id?.slice(0, 4) || 'N/A'}</span>
          <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold border ${getStatusStyle(data.audit?.status || QuestionStatus.PENDING)}`}>
            {data.audit?.status || 'UNAUDITED'}
          </span>
          <span className="text-xs font-medium text-slate-500 dark:text-slate-300 bg-slate-200 dark:bg-slate-700 px-2 py-0.5 rounded">{data.topic || 'General'}</span>
          {isNumerical && <span className="text-[10px] font-black text-indigo-500 uppercase tracking-widest border border-indigo-200 px-1.5 py-0.5 rounded">Numerical</span>}
        </div>

        <div className="flex items-center gap-2">
          {!data.audit && !isAuditing && (
            <button 
              onClick={() => onAudit(data.id)}
              className="px-4 py-1.5 bg-indigo-600 hover:bg-indigo-700 text-white text-xs font-bold rounded shadow transition active:scale-95"
            >
              Start AI Audit
            </button>
          )}
          {isAuditing && <span className="text-xs text-indigo-500 animate-pulse font-medium">Verifying logic...</span>}
          {data.audit && (
            <div className="inline-flex rounded-lg bg-slate-200 dark:bg-slate-700 p-0.5">
              <button 
                onClick={() => setViewMode('AUDIT')}
                className={`px-3 py-1 text-[10px] font-bold rounded-md transition ${viewMode === 'AUDIT' ? 'bg-white dark:bg-slate-900 shadow-sm text-slate-900 dark:text-slate-50' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
              >
                AUDIT VIEW
              </button>
              <button 
                onClick={() => setViewMode('CLEAN')}
                className={`px-3 py-1 text-[10px] font-bold rounded-md transition ${viewMode === 'CLEAN' ? 'bg-white dark:bg-slate-900 shadow-sm text-slate-900 dark:text-slate-50' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
              >
                CLEAN VIEW
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Content */}
      <div className="p-6">
        {viewMode === 'AUDIT' || !data.audit ? (
          <div className="space-y-6">
            <div>
              <p className="text-[10px] font-bold text-slate-400 dark:text-slate-300 uppercase mb-2 tracking-wider">Question Body</p>
              {data.audit?.redlines?.question ? (
                renderRedlined(data.audit.redlines.question)
              ) : (
                <p className="text-slate-800 dark:text-slate-200 font-medium">{data.original?.question || 'No question text provided.'}</p>
              )}
            </div>

            {isNumerical ? (
              <div className="p-4 bg-indigo-50/30 dark:bg-indigo-900/10 border border-indigo-100 dark:border-indigo-800 rounded-lg">
                <p className="text-[10px] font-bold text-indigo-500 uppercase mb-2 tracking-wider">Target Answer</p>
                <div className="text-sm font-bold text-slate-700 dark:text-slate-200">
                  {data.audit?.redlines?.correctAnswer ? renderRedlined(data.audit.redlines.correctAnswer) : (data.original?.correctAnswer || 'N/A')}
                </div>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {displayOptions.map((opt, i) => (
                  <div key={i} className={`p-3 rounded-lg border flex items-start gap-3 ${i === correctIdx ? 'bg-green-50 border-green-200' : 'border-slate-100 dark:border-slate-700 bg-slate-50/30 dark:bg-slate-700/30'}`}>
                    <span className="font-bold text-xs text-slate-400 dark:text-slate-300 mt-0.5">{String.fromCharCode(65+i)})</span>
                    <div className="text-sm text-slate-700 dark:text-slate-200">
                      {data.audit?.redlines?.options ? renderRedlined(opt) : opt}
                    </div>
                  </div>
                ))}
              </div>
            )}

            <div>
              <p className="text-[10px] font-bold text-slate-400 dark:text-slate-300 uppercase mb-2 tracking-wider">Solution Logic</p>
              <div className="p-4 bg-slate-50 dark:bg-slate-700 rounded-lg border border-slate-100 dark:border-slate-600 text-sm italic text-slate-600 dark:text-slate-300">
                {data.audit?.redlines?.solution ? (
                  renderRedlined(data.audit.redlines.solution)
                ) : (
                  data.original?.solution || 'No solution provided.'
                )}
              </div>
            </div>

            {data.audit?.logs && data.audit.logs.length > 0 && (
              <div className="pt-4 border-t border-slate-100 dark:border-slate-700">
                <p className="text-[10px] font-bold text-red-400 uppercase mb-2 tracking-wider">Audit Findings</p>
                <div className="space-y-2">
                  {data.audit.logs.map((log, i) => (
                    <div key={i} className="flex gap-2 items-center text-xs text-slate-600 dark:text-slate-300 bg-red-50 p-2 rounded border border-red-100 dark:border-red-800">
                      <span className="bg-red-500 text-white px-1.5 py-0.5 rounded text-[8px] font-black">{log.severity}</span>
                      <span className="font-bold uppercase text-[10px] text-red-700">{log.type}:</span>
                      <span>{log.message}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-6">
            <div>
              <p className="text-[10px] font-bold text-green-500 uppercase mb-2 tracking-wider">Exam-Ready Question</p>
              <p className="text-slate-900 dark:text-slate-50 font-semibold text-lg leading-relaxed">{data.audit?.clean?.question || 'No cleaned content available.'}</p>
            </div>

            {isNumerical ? (
              <div className="p-6 bg-green-50/50 dark:bg-green-900/10 border-2 border-green-500/20 rounded-2xl">
                <p className="text-[10px] font-bold text-green-600 uppercase mb-2 tracking-wider">Verified Final Answer</p>
                <p className="text-xl font-black text-slate-900 dark:text-slate-50">{data.audit?.clean?.correctAnswer || 'N/A'}</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {cleanOptions.map((opt, i) => (
                  <div key={i} className={`p-4 rounded-xl border-2 transition ${i === correctIdx ? 'border-green-500 bg-green-50' : 'border-slate-100 dark:border-slate-700 hover:border-slate-200 dark:hover:border-slate-600'}`}>
                    <div className="flex items-center justify-between">
                      <span className="font-bold text-slate-400 dark:text-slate-300 text-xs">{String.fromCharCode(65+i)}</span>
                      {i === correctIdx && <span className="bg-green-600 text-white text-[8px] font-black px-1 rounded">CORRECT</span>}
                    </div>
                    <p className="text-sm font-medium text-slate-800 dark:text-slate-200 mt-1">{opt}</p>
                  </div>
                ))}
              </div>
            )}

            <div>
              <p className="text-[10px] font-bold text-indigo-500 uppercase mb-2 tracking-wider">Verified Solution</p>
              <div className="bg-indigo-50/50 dark:bg-indigo-900/50 p-4 rounded-xl border border-indigo-100 dark:border-indigo-800 text-sm text-slate-700 dark:text-slate-200 leading-relaxed">
                {data.audit?.clean?.solution || 'No cleaned solution available.'}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Footer Controls */}
      {showQCControls && data.audit && (
        <div className="px-6 py-4 bg-slate-900 border-t border-slate-800 dark:border-slate-700 flex justify-between items-center">
          <div className="flex items-center gap-4">
             <span className="text-slate-400 dark:text-slate-300 text-[10px] font-bold uppercase">QC Review Required</span>
          </div>
          <div className="flex gap-3">
             <button 
              onClick={() => onApprove?.(data.id)}
              className="px-6 py-1.5 bg-green-600 hover:bg-green-700 text-white text-xs font-black rounded uppercase tracking-widest transition active:scale-95"
            >
              Approve & Lock
            </button>
            <button 
              onClick={() => onReject?.(data.id)}
              className="px-4 py-1.5 border border-red-500/50 text-red-400 hover:bg-red-900/20 text-xs font-black rounded uppercase tracking-widest transition active:scale-95"
            >
              Reject Paper
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default QuestionCard;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import Layout from './components/Layout';
import QuestionInput from './components/QuestionInput';
import QuestionCard from './components/QuestionCard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import { UserRole, QuestionData, Paper, QuestionStatus, AuditLog } from './types';
import { auditQuestion } from './services/geminiService';

const STORAGE_KEY_ACTIVE_ID = 'paperchecker_active_paper_id_v2';
const STORAGE_KEY_HISTORY = 'paperchecker_paper_history_v2';
const STORAGE_KEY_DARK_MODE = 'paperchecker_dark_mode_v2';

const App: React.FC = () => {
  const [activeRole, setActiveRole] = useState<UserRole>(UserRole.TEACHER);
  const [activeTab, setActiveTab] = useState<string>('input');
  const [history, setHistory] = useState<Paper[]>([]);
  const [activePaperId, setActivePaperId] = useState<string | null>(null);
  const [isAuditingId, setIsAuditingId] = useState<string | null>(null);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    try {
      const savedMode = localStorage.getItem(STORAGE_KEY_DARK_MODE);
      if (savedMode !== null) return JSON.parse(savedMode);
    } catch (e) { console.warn("LocalStorage access failed."); }
    return window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  // Derived state: Strictly find the paper in history based on the active ID
  const currentPaper = useMemo(() => {
    return history.find(p => p.id === activePaperId) || null;
  }, [history, activePaperId]);

  const questions = useMemo(() => {
    return currentPaper?.questions || [];
  }, [currentPaper]);

  // Sync dark mode class
  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDarkMode);
    try { localStorage.setItem(STORAGE_KEY_DARK_MODE, JSON.stringify(isDarkMode)); } catch (e) {}
  }, [isDarkMode]);

  // Initial Load from localStorage
  useEffect(() => {
    try {
      const savedHistory = localStorage.getItem(STORAGE_KEY_HISTORY);
      if (savedHistory) {
        const parsed = JSON.parse(savedHistory);
        if (Array.isArray(parsed)) setHistory(parsed);
      }
      const savedActiveId = localStorage.getItem(STORAGE_KEY_ACTIVE_ID);
      if (savedActiveId) setActivePaperId(savedActiveId);
    } catch (e) { console.error("History load failed"); }
  }, []);

  // Persist history and active ID whenever they change
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
      if (activePaperId) {
        localStorage.setItem(STORAGE_KEY_ACTIVE_ID, activePaperId);
      } else {
        localStorage.removeItem(STORAGE_KEY_ACTIVE_ID);
      }
    } catch (e) {}
  }, [history, activePaperId]);

  // Automatically switch tabs based on content presence
  useEffect(() => {
    if (activeRole === UserRole.TEACHER) {
      if (questions.length > 0 && activeTab === 'input') {
        setActiveTab('review');
      }
    } else if (activeTab === 'input') {
       setActiveTab('analytics');
    }
  }, [activeRole, questions.length, activeTab]);

  // Create a brand new paper entry (Automatic archiving)
  const createPaperFromQuestions = useCallback((qs: QuestionData[]) => {
    const paperName = qs[0]?.topic || 'New Question Set';
    const newPaper: Paper = {
      id: Math.random().toString(36).substr(2, 9),
      title: paperName,
      subject: paperName,
      createdBy: 'Faculty User',
      status: 'IN_REVIEW',
      questions: qs,
      createdAt: Date.now()
    };

    setHistory(prev => [newPaper, ...prev]);
    setActivePaperId(newPaper.id);
    setActiveTab('review');
  }, []);

  // Update questions within the currently active paper
  const updateCurrentPaperQuestions = useCallback((newQuestions: QuestionData[]) => {
    if (!activePaperId) return;
    setHistory(prev => prev.map(p => 
      p.id === activePaperId ? { ...p, questions: newQuestions } : p
    ));
  }, [activePaperId]);

  const handleAddBulk = (qs: QuestionData[]) => {
    createPaperFromQuestions(qs);
  };

  const handleAuditRequest = async (id: string) => {
    const q = questions.find(item => item.id === id);
    if (!q || !q.original) return;

    setIsAuditingId(id);
    try {
      const result = await auditQuestion(q.original);
      const updatedQuestions = questions.map(item => 
        item.id === id 
          ? { 
              ...item, 
              topic: result.topic || item.topic,
              audit: {
                status: result.status,
                logs: result.auditLogs,
                redlines: result.redlines,
                clean: result.clean
              }, 
              version: item.version + 1 
            } 
          : item
      );
      updateCurrentPaperQuestions(updatedQuestions);
    } catch (err) {
      alert("Verification failed.");
    } finally {
      setIsAuditingId(null);
    }
  };

  const handleApprove = (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
        : item
    );
    updateCurrentPaperQuestions(updated);
  };

  const handleApproveAll = () => {
    if (window.confirm("Approve all currently audited questions?")) {
      const updated = questions.map(item => 
        item.audit && item.audit.status !== QuestionStatus.APPROVED
          ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
          : item
      );
      updateCurrentPaperQuestions(updated);
    }
  };

  const handleReject = (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.REJECTED }, version: item.version + 1 }
        : item
    );
    updateCurrentPaperQuestions(updated);
  };

  const handleLoadHistory = (paper: Paper) => {
    setActivePaperId(paper.id);
    setActiveTab('review');
  };

  const handleDeleteHistory = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Delete this paper permanently from the archive?")) {
      setHistory(prev => prev.filter(p => p.id !== id));
      if (activePaperId === id) {
        setActivePaperId(null);
        setActiveTab('input');
      }
    }
  };

  const generatePaperContent = (isRedlined: boolean = false) => {
    const title = currentPaper?.title || (isRedlined ? 'Audit Report' : 'Verified Questions');
    const htmlContent = questions.map((q, idx) => {
      const data = isRedlined && q.audit?.redlines ? q.audit.redlines : (q.audit?.clean || q.original);
      const cleanData = q.audit?.clean || q.original;
      const isNumerical = !data.options || data.options.length === 0;

      return `
        <div style="margin-bottom: 40px; page-break-inside: avoid; font-family: sans-serif;">
          <h3 style="color: #4f46e5; margin-bottom: 8px;">Question ${idx + 1} ${isNumerical ? '(Numerical)' : ''}</h3>
          <p style="font-size: 16px; line-height: 1.5;">${data.question}</p>
          <div style="margin: 15px 0;">
            ${isNumerical ? `
              <div style="margin-bottom: 5px; padding: 10px; background: #f0fdf4; border: 1px solid #bbf7d0; border-radius: 6px;">
                <strong style="color: #166534; font-size: 12px; text-transform: uppercase;">Correct Answer:</strong>
                <span style="font-size: 14px; font-weight: bold; margin-left: 10px;">${data.correctAnswer || cleanData.correctAnswer || 'N/A'}</span>
              </div>
            ` : `
              ${data.options!.map((opt, i) => `
                <div style="margin-bottom: 5px; padding: 10px; background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 6px; display: flex; align-items: flex-start; gap: 8px;">
                  <strong style="color: #6b7280; font-size: 14px;">${String.fromCharCode(65 + i)})</strong>
                  <span style="font-size: 14px; flex: 1;">${opt}</span>
                  ${!isRedlined && i === cleanData.correctOptionIndex ? '<span style="font-size: 10px; background: #10b981; color: white; padding: 2px 6px; border-radius: 4px; font-weight: bold;">CORRECT</span>' : ''}
                </div>
              `).join('')}
            `}
          </div>
          <div style="padding: 15px; background: #eef2ff; border-radius: 8px; border-left: 4px solid #4f46e5;">
            <p style="margin: 0; font-size: 14px; color: #374151;"><strong>Solution Logic:</strong> <em style="display: block; margin-top: 5px;">${data.solution}</em></p>
          </div>
          ${isRedlined && q.audit?.logs && q.audit.logs.length > 0 ? `
            <div style="margin-top: 15px; padding: 10px; border: 1px solid #fee2e2; background: #fef2f2; border-radius: 6px;">
              <strong style="font-size: 11px; text-transform: uppercase; color: #ef4444; display: block; margin-bottom: 5px;">Audit Intervention Notes:</strong>
              ${q.audit.logs.map(log => `<p style="font-size: 12px; margin: 4px 0; color: #b91c1c;">• [${log.type}] ${log.message}</p>`).join('')}
            </div>
          ` : ''}
        </div>
      `;
    }).join('');

    return `
      <html>
        <head>
          <style>
            body { padding: 40px; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; color: #1f2937; }
            h1 { text-align: center; border-bottom: 2px solid #e5e7eb; padding-bottom: 20px; color: #111827; }
            del { background-color: #fee2e2; color: #991b1b; text-decoration: line-through; padding: 0 2px; border-radius: 2px; }
            ins { background-color: #dcfce7; color: #166534; text-decoration: none; font-weight: bold; padding: 0 2px; border-radius: 2px; }
            .header-meta { text-align: right; color: #9ca3af; font-size: 12px; margin-bottom: 30px; }
          </style>
        </head>
        <body>
          <div class="header-meta">Audit System Report • ${new Date().toLocaleString()}</div>
          <h1>${title} ${isRedlined ? '(Intervention Logs)' : ''}</h1>
          ${htmlContent}
        </body>
      </html>
    `;
  };

  const handleExportPDF = () => {
    const win = window.open('', '_blank');
    if (win) {
      win.document.write(generatePaperContent(false));
      win.document.close();
      setTimeout(() => win.print(), 500);
    }
  };

  const handleExportRedlines = () => {
    const win = window.open('', '_blank');
    if (win) {
      win.document.write(generatePaperContent(true));
      win.document.close();
      setTimeout(() => win.print(), 500);
    }
  };

  const allLogs: AuditLog[] = history.flatMap(p => p.questions.flatMap(q => q.audit?.logs || []));

  const renderContent = () => {
    const workspaceKey = activePaperId || 'new-workspace';

    switch (activeTab) {
      case 'input':
        return <QuestionInput key="input-tab" onAdd={() => {}} onAddBulk={handleAddBulk} />;
      case 'review':
        return (
          <div key={workspaceKey} className="space-y-6 animate-in fade-in duration-300">
            <header className="mb-8 flex flex-col md:flex-row md:justify-between md:items-end gap-4 border-b border-slate-100 dark:border-slate-800 pb-6">
              <div>
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-[10px] font-black bg-indigo-100 dark:bg-indigo-900/40 text-indigo-600 px-2 py-0.5 rounded uppercase tracking-widest">Selected File</span>
                  {currentPaper && <span className="text-[10px] text-slate-400 font-bold">{new Date(currentPaper.createdAt).toLocaleString()}</span>}
                </div>
                <h1 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">
                  {currentPaper ? currentPaper.title : 'Workspace Empty'}
                </h1>
                <p className="text-slate-500 dark:text-slate-400 font-medium">Verify AI corrections and lock content for this specific paper.</p>
              </div>
              <div className="flex flex-wrap gap-2">
                <button 
                  onClick={handleExportRedlines}
                  disabled={questions.length === 0}
                  className="px-4 py-2 border-2 border-amber-200 dark:border-amber-900/40 text-amber-700 dark:text-amber-400 text-[10px] font-black rounded-lg hover:bg-amber-50 dark:hover:bg-amber-900/20 transition disabled:opacity-30 uppercase tracking-widest flex items-center gap-2"
                >
                  🚩 Download Redlines
                </button>
                <button 
                  onClick={handleExportPDF}
                  disabled={questions.length === 0}
                  className="px-4 py-2 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 text-[10px] font-black rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 transition disabled:opacity-30 uppercase tracking-widest"
                >
                  📄 Export Clean
                </button>
                <button 
                  onClick={() => { setActivePaperId(null); setActiveTab('input'); }}
                  className="px-6 py-2 bg-indigo-600 text-white text-[10px] font-black rounded-lg shadow-lg hover:bg-indigo-700 transition uppercase tracking-widest"
                >
                  + New Input
                </button>
              </div>
            </header>

            {questions.length === 0 ? (
              <div className="bg-white dark:bg-slate-800 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 p-16 text-center">
                <div className="w-16 h-16 bg-slate-50 dark:bg-slate-700 rounded-full flex items-center justify-center mx-auto mb-4">
                  <svg className="w-8 h-8 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
                  </svg>
                </div>
                <p className="text-slate-400 dark:text-slate-300 font-bold uppercase tracking-widest text-sm">No Paper Selected</p>
                <p className="text-xs text-slate-500 mt-2 mb-6">Select a file from the archive or start a new input.</p>
                <button onClick={() => setActiveTab('input')} className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition shadow-xl">Go to Input</button>
              </div>
            ) : (
              <div className="space-y-6">
                {questions.map(q => (
                  <QuestionCard 
                    key={`${workspaceKey}-${q.id}`} 
                    data={q} 
                    onAudit={handleAuditRequest} 
                    isAuditing={isAuditingId === q.id} 
                  />
                ))}
              </div>
            )}
          </div>
        );
      case 'analytics':
        return <AnalyticsDashboard logs={allLogs} />;
      case 'approval':
        const pending = questions.filter(q => q.audit && q.audit.status !== QuestionStatus.APPROVED);
        return (
          <div key={`qc-${workspaceKey}`} className="space-y-6 animate-in fade-in duration-300">
            <header className="mb-8">
              <h1 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">QC Approvals</h1>
              <p className="text-slate-500 dark:text-slate-400 font-medium">Final review for: <span className="text-indigo-600 font-bold">{currentPaper?.title || 'No Paper Selected'}</span></p>
              <button 
                onClick={handleApproveAll} 
                disabled={pending.length === 0}
                className="mt-6 px-6 py-2.5 bg-indigo-600 text-white text-[10px] font-black rounded-lg uppercase tracking-widest hover:bg-indigo-700 transition disabled:opacity-30 shadow-lg"
              >
                Approve All Pending
              </button>
            </header>
            <div className="space-y-4">
              {pending.length === 0 ? (
                <div className="p-12 border border-dashed border-slate-200 dark:border-slate-700 rounded-2xl text-center">
                  <p className="text-slate-400 font-bold uppercase text-xs tracking-widest">All questions approved or none pending in this file.</p>
                </div>
              ) : (
                pending.map(q => (
                  <QuestionCard 
                    key={`qc-${workspaceKey}-${q.id}`} 
                    data={q} 
                    onAudit={handleAuditRequest} 
                    onApprove={handleApprove} 
                    onReject={handleReject} 
                    isAuditing={isAuditingId === q.id} 
                    showQCControls 
                  />
                ))
              )}
            </div>
          </div>
        );
      default: return null;
    }
  };

  return (
    <Layout 
      activeRole={activeRole} 
      onRoleSwitch={setActiveRole}
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      history={history} 
      onLoadHistory={handleLoadHistory}
      activePaperId={activePaperId} 
      createNewPaper={() => { setActivePaperId(null); setActiveTab('input'); }}
      onDeleteHistory={handleDeleteHistory}
      isDarkMode={isDarkMode} 
      toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { QuestionData, QuestionStatus } from '../types';

interface QuestionCardProps {
  data: QuestionData;
  index: number; // Sequential number of the question in the paper
  onAudit: (id: string) => void;
  onApprove?: (id: string) => void;
  onReject?: (id: string) => void;
  isAuditing: boolean;
  showQCControls?: boolean;
}

const QuestionCard: React.FC<QuestionCardProps> = ({ 
  data, 
  index,
  onAudit, 
  onApprove, 
  onReject,
  isAuditing, 
  showQCControls 
}) => {
  const [viewMode, setViewMode] = useState<'AUDIT' | 'CLEAN'>('AUDIT');

  const getStatusStyle = (status: QuestionStatus) => {
    switch (status) {
      case QuestionStatus.APPROVED: return 'bg-green-100 text-green-700 border-green-200';
      case QuestionStatus.NEEDS_CORRECTION: return 'bg-amber-100 text-amber-700 border-amber-200';
      case QuestionStatus.REJECTED: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-slate-100 text-slate-600 border-slate-200';
    }
  };

  const renderRedlined = (html: any) => {
    const safeHtml = typeof html === 'string' ? html : '';
    if (!safeHtml) return <span className="text-slate-400 italic">No content available</span>;

    return (
      <div 
        className="prose-sm max-w-none dark:text-slate-200"
        dangerouslySetInnerHTML={{ 
          __html: safeHtml.replace(/<del>/g, '<del class="bg-red-100 text-red-800 line-through px-1 rounded mx-0.5">')
                      .replace(/<\/del>/g, '</del>')
                      .replace(/<ins>/g, '<ins class="bg-green-100 text-green-800 font-medium px-1 rounded mx-0.5">')
                      .replace(/<\/ins>/g, '</ins>')
        }} 
      />
    );
  };

  // Safely extract content with fallbacks
  const displayOptions = data.audit?.redlines?.options || data.original?.options || [];
  const cleanOptions = data.audit?.clean?.options || [];
  const correctIdx = data.audit?.clean?.correctOptionIndex ?? data.original?.correctOptionIndex ?? 0;
  const isNumerical = displayOptions.length === 0;

  return (
    <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden mb-6 group hover:border-indigo-300 transition">
      {/* Header */}
      <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 dark:border-slate-700 bg-slate-50/50 dark:bg-slate-800/50">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <span className="flex items-center justify-center w-8 h-8 rounded-full bg-indigo-600 text-white font-black text-sm shadow-sm">
              {index}
            </span>
            <span className="text-xs font-bold uppercase tracking-widest text-slate-400 dark:text-slate-300">Question</span>
          </div>
          <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold border ${getStatusStyle(data.audit?.status || QuestionStatus.PENDING)}`}>
            {data.audit?.status || 'UNAUDITED'}
          </span>
          <span className="text-xs font-medium text-slate-500 dark:text-slate-300 bg-slate-200 dark:bg-slate-700 px-2 py-0.5 rounded">{data.topic || 'General'}</span>
          {isNumerical && <span className="text-[10px] font-black text-indigo-500 uppercase tracking-widest border border-indigo-200 px-1.5 py-0.5 rounded">Numerical</span>}
        </div>

        <div className="flex items-center gap-2">
          {!data.audit && !isAuditing && (
            <button 
              onClick={() => onAudit(data.id)}
              className="px-4 py-1.5 bg-indigo-600 hover:bg-indigo-700 text-white text-xs font-bold rounded shadow transition active:scale-95"
            >
              Start AI Audit
            </button>
          )}
          {isAuditing && <span className="text-xs text-indigo-500 animate-pulse font-medium">Verifying logic...</span>}
          {data.audit && (
            <div className="inline-flex rounded-lg bg-slate-200 dark:bg-slate-700 p-0.5">
              <button 
                onClick={() => setViewMode('AUDIT')}
                className={`px-3 py-1 text-[10px] font-bold rounded-md transition ${viewMode === 'AUDIT' ? 'bg-white dark:bg-slate-900 shadow-sm text-slate-900 dark:text-slate-50' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
              >
                AUDIT VIEW
              </button>
              <button 
                onClick={() => setViewMode('CLEAN')}
                className={`px-3 py-1 text-[10px] font-bold rounded-md transition ${viewMode === 'CLEAN' ? 'bg-white dark:bg-slate-900 shadow-sm text-slate-900 dark:text-slate-50' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
              >
                CLEAN VIEW
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Content */}
      <div className="p-6">
        {viewMode === 'AUDIT' || !data.audit ? (
          <div className="space-y-6">
            <div>
              <p className="text-[10px] font-bold text-slate-400 dark:text-slate-300 uppercase mb-2 tracking-wider">Question Body</p>
              {data.audit?.redlines?.question ? (
                renderRedlined(data.audit.redlines.question)
              ) : (
                <p className="text-slate-800 dark:text-slate-200 font-medium">{data.original?.question || 'No question text provided.'}</p>
              )}
            </div>

            {isNumerical ? (
              <div className="p-4 bg-indigo-50/30 dark:bg-indigo-900/10 border border-indigo-100 dark:border-indigo-800 rounded-lg">
                <p className="text-[10px] font-bold text-indigo-500 uppercase mb-2 tracking-wider">Target Answer</p>
                <div className="text-sm font-bold text-slate-700 dark:text-slate-200">
                  {data.audit?.redlines?.correctAnswer ? renderRedlined(data.audit.redlines.correctAnswer) : (data.original?.correctAnswer || 'N/A')}
                </div>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {displayOptions.map((opt, i) => (
                  <div key={i} className={`p-3 rounded-lg border flex items-start gap-3 ${i === correctIdx ? 'bg-green-50 border-green-200' : 'border-slate-100 dark:border-slate-700 bg-slate-50/30 dark:bg-slate-700/30'}`}>
                    <span className="font-bold text-xs text-slate-400 dark:text-slate-300 mt-0.5">{String.fromCharCode(65+i)})</span>
                    <div className="text-sm text-slate-700 dark:text-slate-200">
                      {data.audit?.redlines?.options ? renderRedlined(opt) : opt}
                    </div>
                  </div>
                ))}
              </div>
            )}

            <div>
              <p className="text-[10px] font-bold text-slate-400 dark:text-slate-300 uppercase mb-2 tracking-wider">Solution Logic</p>
              <div className="p-4 bg-slate-50 dark:bg-slate-700 rounded-lg border border-slate-100 dark:border-slate-600 text-sm italic text-slate-600 dark:text-slate-300">
                {data.audit?.redlines?.solution ? (
                  renderRedlined(data.audit.redlines.solution)
                ) : (
                  data.original?.solution || 'No solution provided.'
                )}
              </div>
            </div>

            {data.audit?.logs && data.audit.logs.length > 0 && (
              <div className="pt-4 border-t border-slate-100 dark:border-slate-700">
                <p className="text-[10px] font-bold text-red-400 uppercase mb-2 tracking-wider">Audit Findings</p>
                <div className="space-y-2">
                  {data.audit.logs.map((log, i) => (
                    <div key={i} className="flex gap-2 items-center text-xs text-slate-600 dark:text-slate-300 bg-red-50 p-2 rounded border border-red-100 dark:border-red-800">
                      <span className="bg-red-500 text-white px-1.5 py-0.5 rounded text-[8px] font-black">{log.severity}</span>
                      <span className="font-bold uppercase text-[10px] text-red-700">{log.type}:</span>
                      <span>{log.message}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-6">
            <div>
              <p className="text-[10px] font-bold text-green-500 uppercase mb-2 tracking-wider">Exam-Ready Question</p>
              <p className="text-slate-900 dark:text-slate-50 font-semibold text-lg leading-relaxed">{data.audit?.clean?.question || 'No cleaned content available.'}</p>
            </div>

            {isNumerical ? (
              <div className="p-6 bg-green-50/50 dark:bg-green-900/10 border-2 border-green-500/20 rounded-2xl">
                <p className="text-[10px] font-bold text-green-600 uppercase mb-2 tracking-wider">Verified Final Answer</p>
                <p className="text-xl font-black text-slate-900 dark:text-slate-50">{data.audit?.clean?.correctAnswer || 'N/A'}</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {cleanOptions.map((opt, i) => (
                  <div key={i} className={`p-4 rounded-xl border-2 transition ${i === correctIdx ? 'border-green-500 bg-green-50' : 'border-slate-100 dark:border-slate-700 hover:border-slate-200 dark:hover:border-slate-600'}`}>
                    <div className="flex items-center justify-between">
                      <span className="font-bold text-slate-400 dark:text-slate-300 text-xs">{String.fromCharCode(65+i)}</span>
                      {i === correctIdx && <span className="bg-green-600 text-white text-[8px] font-black px-1 rounded">CORRECT</span>}
                    </div>
                    <p className="text-sm font-medium text-slate-800 dark:text-slate-200 mt-1">{opt}</p>
                  </div>
                ))}
              </div>
            )}

            <div>
              <p className="text-[10px] font-bold text-indigo-500 uppercase mb-2 tracking-wider">Verified Solution</p>
              <div className="bg-indigo-50/50 dark:bg-indigo-900/50 p-4 rounded-xl border border-indigo-100 dark:border-indigo-800 text-sm text-slate-700 dark:text-slate-200 leading-relaxed">
                {data.audit?.clean?.solution || 'No cleaned solution available.'}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Footer Controls */}
      {showQCControls && data.audit && (
        <div className="px-6 py-4 bg-slate-900 border-t border-slate-800 dark:border-slate-700 flex justify-between items-center">
          <div className="flex items-center gap-4">
             <span className="text-slate-400 dark:text-slate-300 text-[10px] font-bold uppercase">QC Review Required</span>
          </div>
          <div className="flex gap-3">
             <button 
              onClick={() => onApprove?.(data.id)}
              className="px-6 py-1.5 bg-green-600 hover:bg-green-700 text-white text-xs font-black rounded uppercase tracking-widest transition active:scale-95"
            >
              Approve & Lock
            </button>
            <button 
              onClick={() => onReject?.(data.id)}
              className="px-4 py-1.5 border border-red-500/50 text-red-400 hover:bg-red-900/20 text-xs font-black rounded uppercase tracking-widest transition active:scale-95"
            >
              Reject Question
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default QuestionCard;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import Layout from './components/Layout';
import QuestionInput from './components/QuestionInput';
import QuestionCard from './components/QuestionCard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import { UserRole, QuestionData, Paper, QuestionStatus, AuditLog } from './types';
import { auditQuestion } from './services/geminiService';

const STORAGE_KEY_ACTIVE_ID = 'paperchecker_active_paper_id_v2';
const STORAGE_KEY_HISTORY = 'paperchecker_paper_history_v2';
const STORAGE_KEY_DARK_MODE = 'paperchecker_dark_mode_v2';

const App: React.FC = () => {
  const [activeRole, setActiveRole] = useState<UserRole>(UserRole.TEACHER);
  const [activeTab, setActiveTab] = useState<string>('input');
  const [history, setHistory] = useState<Paper[]>([]);
  const [activePaperId, setActivePaperId] = useState<string | null>(null);
  const [isAuditingId, setIsAuditingId] = useState<string | null>(null);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    try {
      const savedMode = localStorage.getItem(STORAGE_KEY_DARK_MODE);
      if (savedMode !== null) return JSON.parse(savedMode);
    } catch (e) { console.warn("LocalStorage access failed."); }
    return window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  // Derived state: Strictly find the paper in history based on the active ID
  const currentPaper = useMemo(() => {
    return history.find(p => p.id === activePaperId) || null;
  }, [history, activePaperId]);

  const questions = useMemo(() => {
    return currentPaper?.questions || [];
  }, [currentPaper]);

  // Sync dark mode class
  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDarkMode);
    try { localStorage.setItem(STORAGE_KEY_DARK_MODE, JSON.stringify(isDarkMode)); } catch (e) {}
  }, [isDarkMode]);

  // Initial Load from localStorage
  useEffect(() => {
    try {
      const savedHistory = localStorage.getItem(STORAGE_KEY_HISTORY);
      if (savedHistory) {
        const parsed = JSON.parse(savedHistory);
        if (Array.isArray(parsed)) setHistory(parsed);
      }
      const savedActiveId = localStorage.getItem(STORAGE_KEY_ACTIVE_ID);
      if (savedActiveId) setActivePaperId(savedActiveId);
    } catch (e) { console.error("History load failed"); }
  }, []);

  // Persist history and active ID whenever they change
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
      if (activePaperId) {
        localStorage.setItem(STORAGE_KEY_ACTIVE_ID, activePaperId);
      } else {
        localStorage.removeItem(STORAGE_KEY_ACTIVE_ID);
      }
    } catch (e) {}
  }, [history, activePaperId]);

  // Automatically switch tabs based on content presence
  useEffect(() => {
    if (activeRole === UserRole.TEACHER) {
      if (questions.length > 0 && activeTab === 'input') {
        setActiveTab('review');
      }
    } else if (activeTab === 'input') {
       setActiveTab('analytics');
    }
  }, [activeRole, questions.length, activeTab]);

  // Create a brand new paper entry (Automatic archiving)
  const createPaperFromQuestions = useCallback((qs: QuestionData[]) => {
    const paperName = qs[0]?.topic || 'New Question Set';
    const newPaper: Paper = {
      id: Math.random().toString(36).substr(2, 9),
      title: paperName,
      subject: paperName,
      createdBy: 'Faculty User',
      status: 'IN_REVIEW',
      questions: qs,
      createdAt: Date.now()
    };

    setHistory(prev => [newPaper, ...prev]);
    setActivePaperId(newPaper.id);
    setActiveTab('review');
  }, []);

  // Update questions within the currently active paper
  const updateCurrentPaperQuestions = useCallback((newQuestions: QuestionData[]) => {
    if (!activePaperId) return;
    setHistory(prev => prev.map(p => 
      p.id === activePaperId ? { ...p, questions: newQuestions } : p
    ));
  }, [activePaperId]);

  const handleAddBulk = (qs: QuestionData[]) => {
    createPaperFromQuestions(qs);
  };

  const handleAuditRequest = async (id: string) => {
    const q = questions.find(item => item.id === id);
    if (!q || !q.original) return;

    setIsAuditingId(id);
    try {
      const result = await auditQuestion(q.original);
      const updatedQuestions = questions.map(item => 
        item.id === id 
          ? { 
              ...item, 
              topic: result.topic || item.topic,
              audit: {
                status: result.status,
                logs: result.auditLogs,
                redlines: result.redlines,
                clean: result.clean
              }, 
              version: item.version + 1 
            } 
          : item
      );
      updateCurrentPaperQuestions(updatedQuestions);
    } catch (err) {
      alert("Verification failed.");
    } finally {
      setIsAuditingId(null);
    }
  };

  const handleApprove = (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
        : item
    );
    updateCurrentPaperQuestions(updated);
  };

  const handleApproveAll = () => {
    if (window.confirm("Approve all currently audited questions?")) {
      const updated = questions.map(item => 
        item.audit && item.audit.status !== QuestionStatus.APPROVED
          ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
          : item
      );
      updateCurrentPaperQuestions(updated);
    }
  };

  const handleReject = (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.REJECTED }, version: item.version + 1 }
        : item
    );
    updateCurrentPaperQuestions(updated);
  };

  const handleLoadHistory = (paper: Paper) => {
    setActivePaperId(paper.id);
    setActiveTab('review');
  };

  const handleDeleteHistory = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Delete this paper permanently from the archive?")) {
      setHistory(prev => prev.filter(p => p.id !== id));
      if (activePaperId === id) {
        setActivePaperId(null);
        setActiveTab('input');
      }
    }
  };

  const generatePaperContent = (isRedlined: boolean = false) => {
    const title = currentPaper?.title || (isRedlined ? 'Audit Report' : 'Verified Questions');
    const htmlContent = questions.map((q, idx) => {
      const data = isRedlined && q.audit?.redlines ? q.audit.redlines : (q.audit?.clean || q.original);
      const cleanData = q.audit?.clean || q.original;
      const isNumerical = !data.options || data.options.length === 0;

      return `
        <div style="margin-bottom: 40px; page-break-inside: avoid; font-family: sans-serif;">
          <h3 style="color: #4f46e5; margin-bottom: 8px;">Question ${idx + 1} ${isNumerical ? '(Numerical)' : ''}</h3>
          <p style="font-size: 16px; line-height: 1.5;">${data.question}</p>
          <div style="margin: 15px 0;">
            ${isNumerical ? `
              <div style="margin-bottom: 5px; padding: 10px; background: #f0fdf4; border: 1px solid #bbf7d0; border-radius: 6px;">
                <strong style="color: #166534; font-size: 12px; text-transform: uppercase;">Correct Answer:</strong>
                <span style="font-size: 14px; font-weight: bold; margin-left: 10px;">${data.correctAnswer || cleanData.correctAnswer || 'N/A'}</span>
              </div>
            ` : `
              ${data.options!.map((opt, i) => `
                <div style="margin-bottom: 5px; padding: 10px; background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 6px; display: flex; align-items: flex-start; gap: 8px;">
                  <strong style="color: #6b7280; font-size: 14px;">${String.fromCharCode(65 + i)})</strong>
                  <span style="font-size: 14px; flex: 1;">${opt}</span>
                  ${!isRedlined && i === cleanData.correctOptionIndex ? '<span style="font-size: 10px; background: #10b981; color: white; padding: 2px 6px; border-radius: 4px; font-weight: bold;">CORRECT</span>' : ''}
                </div>
              `).join('')}
            `}
          </div>
          <div style="padding: 15px; background: #eef2ff; border-radius: 8px; border-left: 4px solid #4f46e5;">
            <p style="margin: 0; font-size: 14px; color: #374151;"><strong>Solution Logic:</strong> <em style="display: block; margin-top: 5px;">${data.solution}</em></p>
          </div>
          ${isRedlined && q.audit?.logs && q.audit.logs.length > 0 ? `
            <div style="margin-top: 15px; padding: 10px; border: 1px solid #fee2e2; background: #fef2f2; border-radius: 6px;">
              <strong style="font-size: 11px; text-transform: uppercase; color: #ef4444; display: block; margin-bottom: 5px;">Audit Intervention Notes:</strong>
              ${q.audit.logs.map(log => `<p style="font-size: 12px; margin: 4px 0; color: #b91c1c;">• [${log.type}] ${log.message}</p>`).join('')}
            </div>
          ` : ''}
        </div>
      `;
    }).join('');

    return `
      <html>
        <head>
          <style>
            body { padding: 40px; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; color: #1f2937; }
            h1 { text-align: center; border-bottom: 2px solid #e5e7eb; padding-bottom: 20px; color: #111827; }
            del { background-color: #fee2e2; color: #991b1b; text-decoration: line-through; padding: 0 2px; border-radius: 2px; }
            ins { background-color: #dcfce7; color: #166534; text-decoration: none; font-weight: bold; padding: 0 2px; border-radius: 2px; }
            .header-meta { text-align: right; color: #9ca3af; font-size: 12px; margin-bottom: 30px; }
          </style>
        </head>
        <body>
          <div class="header-meta">Audit System Report • ${new Date().toLocaleString()}</div>
          <h1>${title} ${isRedlined ? '(Intervention Logs)' : ''}</h1>
          ${htmlContent}
        </body>
      </html>
    `;
  };

  const handleExportPDF = () => {
    const win = window.open('', '_blank');
    if (win) {
      win.document.write(generatePaperContent(false));
      win.document.close();
      setTimeout(() => win.print(), 500);
    }
  };

  const handleExportRedlines = () => {
    const win = window.open('', '_blank');
    if (win) {
      win.document.write(generatePaperContent(true));
      win.document.close();
      setTimeout(() => win.print(), 500);
    }
  };

  const allLogs: AuditLog[] = history.flatMap(p => p.questions.flatMap(q => q.audit?.logs || []));

  const renderContent = () => {
    const workspaceKey = activePaperId || 'new-workspace';

    switch (activeTab) {
      case 'input':
        return <QuestionInput key="input-tab" onAdd={() => {}} onAddBulk={handleAddBulk} />;
      case 'review':
        return (
          <div key={workspaceKey} className="space-y-6 animate-in fade-in duration-300">
            <header className="mb-8 flex flex-col md:flex-row md:justify-between md:items-end gap-4 border-b border-slate-100 dark:border-slate-800 pb-6">
              <div>
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-[10px] font-black bg-indigo-100 dark:bg-indigo-900/40 text-indigo-600 px-2 py-0.5 rounded uppercase tracking-widest">Selected File</span>
                  {currentPaper && <span className="text-[10px] text-slate-400 font-bold">{new Date(currentPaper.createdAt).toLocaleString()}</span>}
                </div>
                <h1 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">
                  {currentPaper ? currentPaper.title : 'Workspace Empty'}
                </h1>
                <p className="text-slate-500 dark:text-slate-400 font-medium">Verify AI corrections and lock content for this specific paper.</p>
              </div>
              <div className="flex flex-wrap gap-2">
                <button 
                  onClick={handleExportRedlines}
                  disabled={questions.length === 0}
                  className="px-4 py-2 border-2 border-amber-200 dark:border-amber-900/40 text-amber-700 dark:text-amber-400 text-[10px] font-black rounded-lg hover:bg-amber-50 dark:hover:bg-amber-900/20 transition disabled:opacity-30 uppercase tracking-widest flex items-center gap-2"
                >
                  🚩 Download Redlines
                </button>
                <button 
                  onClick={handleExportPDF}
                  disabled={questions.length === 0}
                  className="px-4 py-2 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 text-[10px] font-black rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 transition disabled:opacity-30 uppercase tracking-widest"
                >
                  📄 Export Clean
                </button>
                <button 
                  onClick={() => { setActivePaperId(null); setActiveTab('input'); }}
                  className="px-6 py-2 bg-indigo-600 text-white text-[10px] font-black rounded-lg shadow-lg hover:bg-indigo-700 transition uppercase tracking-widest"
                >
                  + New Input
                </button>
              </div>
            </header>

            {questions.length === 0 ? (
              <div className="bg-white dark:bg-slate-800 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 p-16 text-center">
                <div className="w-16 h-16 bg-slate-50 dark:bg-slate-700 rounded-full flex items-center justify-center mx-auto mb-4">
                  <svg className="w-8 h-8 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
                  </svg>
                </div>
                <p className="text-slate-400 dark:text-slate-300 font-bold uppercase tracking-widest text-sm">No Paper Selected</p>
                <p className="text-xs text-slate-500 mt-2 mb-6">Select a file from the archive or start a new input.</p>
                <button onClick={() => setActiveTab('input')} className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition shadow-xl">Go to Input</button>
              </div>
            ) : (
              <div className="space-y-6">
                {questions.map((q, idx) => (
                  <QuestionCard 
                    key={`${workspaceKey}-${q.id}`} 
                    index={idx + 1}
                    data={q} 
                    onAudit={handleAuditRequest} 
                    isAuditing={isAuditingId === q.id} 
                  />
                ))}
              </div>
            )}
          </div>
        );
      case 'analytics':
        return <AnalyticsDashboard logs={allLogs} />;
      case 'approval':
        const pending = questions.filter(q => q.audit && q.audit.status !== QuestionStatus.APPROVED);
        return (
          <div key={`qc-${workspaceKey}`} className="space-y-6 animate-in fade-in duration-300">
            <header className="mb-8">
              <h1 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">QC Approvals</h1>
              <p className="text-slate-500 dark:text-slate-400 font-medium">Final review for: <span className="text-indigo-600 font-bold">{currentPaper?.title || 'No Paper Selected'}</span></p>
              <button 
                onClick={handleApproveAll} 
                disabled={pending.length === 0}
                className="mt-6 px-6 py-2.5 bg-indigo-600 text-white text-[10px] font-black rounded-lg uppercase tracking-widest hover:bg-indigo-700 transition disabled:opacity-30 shadow-lg"
              >
                Approve All Pending
              </button>
            </header>
            <div className="space-y-4">
              {pending.length === 0 ? (
                <div className="p-12 border border-dashed border-slate-200 dark:border-slate-700 rounded-2xl text-center">
                  <p className="text-slate-400 font-bold uppercase text-xs tracking-widest">All questions approved or none pending in this file.</p>
                </div>
              ) : (
                pending.map((q, idx) => {
                  // Find the true index in the full list
                  const trueIndex = questions.findIndex(item => item.id === q.id) + 1;
                  return (
                    <QuestionCard 
                      key={`qc-${workspaceKey}-${q.id}`} 
                      index={trueIndex}
                      data={q} 
                      onAudit={handleAuditRequest} 
                      onApprove={handleApprove} 
                      onReject={handleReject} 
                      isAuditing={isAuditingId === q.id} 
                      showQCControls 
                    />
                  );
                })
              )}
            </div>
          </div>
        );
      default: return null;
    }
  };

  return (
    <Layout 
      activeRole={activeRole} 
      onRoleSwitch={setActiveRole}
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      history={history} 
      onLoadHistory={handleLoadHistory}
      activePaperId={activePaperId} 
      createNewPaper={() => { setActivePaperId(null); setActiveTab('input'); }}
      onDeleteHistory={handleDeleteHistory}
      isDarkMode={isDarkMode} 
      toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { UserRole, Paper } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeRole: UserRole;
  onRoleSwitch: (role: UserRole) => void;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  history: Paper[];
  onLoadHistory: (paper: Paper) => void;
  onDeleteHistory: (e: React.MouseEvent, id: string) => void;
  activePaperId: string | null;
  createNewPaper: () => void;
  isDarkMode: boolean;
  toggleDarkMode: () => void;
}

const Layout: React.FC<LayoutProps> = ({ 
  children, 
  activeRole, 
  onRoleSwitch, 
  activeTab, 
  setActiveTab,
  history,
  onLoadHistory,
  onDeleteHistory,
  activePaperId,
  createNewPaper,
  isDarkMode,
  toggleDarkMode
}) => {
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);

  useEffect(() => {
    document.body.style.overflow = isDrawerOpen ? 'hidden' : '';
    return () => { document.body.style.overflow = ''; };
  }, [isDrawerOpen]);

  const toggleDrawer = () => setIsDrawerOpen(!isDrawerOpen);
  const closeDrawer = () => setIsDrawerOpen(false);

  const handleTabClick = (tab: string) => {
    setActiveTab(tab);
    closeDrawer();
  };

  const formatTime = (ts: number) => {
    const diff = Date.now() - ts;
    const mins = Math.floor(diff / 60000);
    const hours = Math.floor(mins / 60);
    if (mins < 60) return `${mins}m ago`;
    if (hours < 24) return `${hours}h ago`;
    return new Date(ts).toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
  };

  return (
    <div className="flex min-h-screen bg-slate-50 text-slate-900 dark:bg-slate-900 dark:text-slate-50 transition-colors duration-300">
      {/* Mobile Drawer Overlay */}
      <div 
        className={`fixed inset-0 bg-slate-900/60 z-30 lg:hidden transition-all duration-500 ${isDrawerOpen ? 'opacity-100 backdrop-blur-sm' : 'opacity-0 pointer-events-none backdrop-blur-none'}`}
        onClick={closeDrawer}
      />

      <aside 
        className={`
          fixed inset-y-0 left-0 w-72 bg-slate-900 text-white flex flex-col z-40 shadow-2xl transition-all duration-500
          ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'} lg:translate-x-0 lg:static
        `}
      >
        <div className="p-6 border-b border-slate-800 dark:border-slate-700 flex items-center justify-between">
          <div onClick={() => handleTabClick(activeRole === UserRole.TEACHER ? 'input' : 'approval')} className="cursor-pointer group">
            <h1 className="text-xl font-bold flex items-center gap-2 group-hover:text-indigo-400 transition-colors">
              <span className="bg-indigo-600 p-1.5 rounded-lg shadow-lg shadow-indigo-600/20 group-hover:scale-110 transition-transform">🔍</span> Paper Checker
            </h1>
            <p className="text-[10px] text-slate-400 mt-1 uppercase tracking-widest font-black opacity-80">Academic Verification</p>
          </div>
          <button onClick={toggleDarkMode} className="p-2 rounded-full bg-slate-800 hover:bg-slate-700 text-slate-400 transition-all active:scale-90">
            {isDarkMode ? '☀️' : '🌙'}
          </button>
        </div>

        <nav className="flex-1 p-5 space-y-1 overflow-y-auto custom-scrollbar">
          <div className="flex items-center justify-between px-4 mb-3 mt-4">
            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">
              {activeRole === UserRole.TEACHER ? 'Teacher Menu' : 'QC Lead Menu'}
            </p>
            <div className={`w-2 h-2 rounded-full animate-pulse ${activeRole === UserRole.TEACHER ? 'bg-indigo-500' : 'bg-rose-500'}`} />
          </div>

          {activeRole === UserRole.TEACHER ? (
            <>
              <button 
                onClick={() => handleTabClick('input')}
                className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-semibold transition-all duration-300 ${activeTab === 'input' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                Paper Input
              </button>
              <button 
                onClick={() => handleTabClick('review')}
                className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-semibold transition-all duration-300 ${activeTab === 'review' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                Audit Review
              </button>
            </>
          ) : (
            <>
              <button 
                onClick={() => handleTabClick('approval')}
                className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-semibold transition-all duration-300 ${activeTab === 'approval' ? 'bg-rose-600 text-white shadow-xl shadow-rose-600/30' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4" /></svg>
                QC Approvals
              </button>
              <button 
                onClick={() => handleTabClick('analytics')}
                className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-semibold transition-all duration-300 ${activeTab === 'analytics' ? 'bg-rose-600 text-white shadow-xl shadow-rose-600/30' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>
                Analytics
              </button>
            </>
          )}

          <div className="pt-10 pb-4">
            <div className="px-4 flex items-center justify-between mb-4">
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Session Archive</p>
              <span className="text-[9px] bg-slate-800 text-indigo-400 px-2 py-0.5 rounded-full font-black border border-slate-700">HIST</span>
            </div>

            <div className="space-y-3 px-1">
              {history.length === 0 ? (
                <div className="px-4 py-5 border border-dashed border-slate-800 rounded-2xl flex flex-col items-center gap-2">
                   <p className="text-[10px] text-slate-600 font-bold uppercase text-center leading-tight">No archived<br/>sessions</p>
                </div>
              ) : (
                history.map((paper) => (
                  <div key={paper.id} className="relative group">
                    <button
                      onClick={() => onLoadHistory(paper)}
                      className={`w-full text-left p-4 rounded-2xl border transition-all duration-300 active:scale-95 ${activePaperId === paper.id ? 'bg-slate-800 border-indigo-600 shadow-xl ring-1 ring-indigo-500/50' : 'bg-slate-900/40 border-slate-800 hover:bg-slate-800 hover:border-slate-700'}`}
                    >
                      <div className={`text-xs font-bold truncate ${activePaperId === paper.id ? 'text-indigo-400' : 'text-slate-200'}`}>
                        {paper.title}
                      </div>
                      <div className="flex items-center gap-2 mt-2.5">
                        <span className={`text-[9px] px-1.5 py-0.5 rounded border ${activePaperId === paper.id ? 'bg-indigo-600/20 text-indigo-300 border-indigo-600/30' : 'bg-slate-800 text-slate-400 border-slate-700'}`}>
                          {paper.questions.length} Qs
                        </span>
                        <span className="text-[9px] text-slate-500 font-bold flex items-center gap-1">
                          <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                          {formatTime(paper.createdAt)}
                        </span>
                      </div>
                    </button>
                    <button 
                      onClick={(e) => onDeleteHistory(e, paper.id)}
                      className="absolute top-2 right-2 p-1.5 text-slate-600 hover:text-red-500 hover:bg-red-500/10 rounded-lg opacity-0 group-hover:opacity-100 transition-all"
                      title="Delete archive entry"
                    >
                      <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                      </svg>
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        </nav>

        <div className="p-4 border-t border-slate-800 bg-slate-900/50">
          <button 
            onClick={() => onRoleSwitch(activeRole === UserRole.TEACHER ? UserRole.QC_HEAD : UserRole.TEACHER)}
            className={`w-full text-[10px] text-white font-black uppercase tracking-widest py-3 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 active:scale-95 ${activeRole === UserRole.TEACHER ? 'bg-rose-600 hover:bg-rose-500 shadow-rose-600/20' : 'bg-indigo-600 hover:bg-indigo-500 shadow-indigo-600/20'}`}
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4" /></svg>
            {activeRole === UserRole.TEACHER ? 'Switch to QC Mode' : 'Switch to Teacher Mode'}
          </button>
        </div>
      </aside>

      <div className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        {/* Mobile Header */}
        <header className="lg:hidden bg-white dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700 px-6 py-4 flex items-center justify-between sticky top-0 z-20 shadow-sm transition-colors duration-300">
          <button onClick={toggleDrawer} className="p-2 -ml-2 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" />
            </svg>
          </button>
          <div className="flex items-center gap-2">
            <span className="bg-indigo-600 text-white p-1 rounded shadow-sm">🔍</span>
            <span className="font-black text-slate-900 dark:text-slate-50 uppercase tracking-tighter">Paper Checker AI</span>
          </div>
          <div className="w-10"></div>
        </header>

        <main className="flex-1 overflow-y-auto custom-scrollbar p-6 lg:p-10 scroll-smooth">
          <div className="max-w-6xl mx-auto pb-10">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import Layout from './components/Layout';
import QuestionInput from './components/QuestionInput';
import QuestionCard from './components/QuestionCard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import { UserRole, QuestionData, Paper, QuestionStatus, AuditLog } from './types';
import { auditQuestion } from './services/geminiService';

const STORAGE_KEY_ACTIVE_ID = 'paperchecker_active_paper_id_v2';
const STORAGE_KEY_HISTORY = 'paperchecker_paper_history_v2';
const STORAGE_KEY_DARK_MODE = 'paperchecker_dark_mode_v2';

const App: React.FC = () => {
  const [activeRole, setActiveRole] = useState<UserRole>(UserRole.TEACHER);
  const [activeTab, setActiveTab] = useState<string>('input');
  const [history, setHistory] = useState<Paper[]>([]);
  const [activePaperId, setActivePaperId] = useState<string | null>(null);
  const [isAuditingId, setIsAuditingId] = useState<string | null>(null);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    try {
      const savedMode = localStorage.getItem(STORAGE_KEY_DARK_MODE);
      if (savedMode !== null) return JSON.parse(savedMode);
    } catch (e) { console.warn("LocalStorage access failed."); }
    return window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  // Derived state: Strictly find the paper in history based on the active ID
  const currentPaper = useMemo(() => {
    return history.find(p => p.id === activePaperId) || null;
  }, [history, activePaperId]);

  const questions = useMemo(() => {
    return currentPaper?.questions || [];
  }, [currentPaper]);

  // Sync dark mode class
  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDarkMode);
    try { localStorage.setItem(STORAGE_KEY_DARK_MODE, JSON.stringify(isDarkMode)); } catch (e) {}
  }, [isDarkMode]);

  // Initial Load from localStorage
  useEffect(() => {
    try {
      const savedHistory = localStorage.getItem(STORAGE_KEY_HISTORY);
      if (savedHistory) {
        const parsed = JSON.parse(savedHistory);
        if (Array.isArray(parsed)) setHistory(parsed);
      }
      const savedActiveId = localStorage.getItem(STORAGE_KEY_ACTIVE_ID);
      if (savedActiveId) setActivePaperId(savedActiveId);
    } catch (e) { console.error("History load failed"); }
  }, []);

  // Persist history and active ID whenever they change
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
      if (activePaperId) {
        localStorage.setItem(STORAGE_KEY_ACTIVE_ID, activePaperId);
      } else {
        localStorage.removeItem(STORAGE_KEY_ACTIVE_ID);
      }
    } catch (e) {}
  }, [history, activePaperId]);

  // Handle Role Switch
  const handleRoleSwitch = (newRole: UserRole) => {
    setActiveRole(newRole);
    // When switching to QC, jump to approval or analytics
    if (newRole === UserRole.QC_HEAD) {
      if (questions.length > 0) setActiveTab('approval');
      else setActiveTab('analytics');
    } else {
      // When switching to Teacher, jump to review or input
      if (questions.length > 0) setActiveTab('review');
      else setActiveTab('input');
    }
  };

  // Automatically switch tabs based on content presence (only if in Teacher mode)
  useEffect(() => {
    if (activeRole === UserRole.TEACHER) {
      if (questions.length > 0 && activeTab === 'input') {
        setActiveTab('review');
      }
    }
  }, [activeRole, questions.length, activeTab]);

  // Create a brand new paper entry (Automatic archiving)
  const createPaperFromQuestions = useCallback((qs: QuestionData[]) => {
    const paperName = qs[0]?.topic || 'New Question Set';
    const newPaper: Paper = {
      id: Math.random().toString(36).substr(2, 9),
      title: paperName,
      subject: paperName,
      createdBy: 'Faculty User',
      status: 'IN_REVIEW',
      questions: qs,
      createdAt: Date.now()
    };

    setHistory(prev => [newPaper, ...prev]);
    setActivePaperId(newPaper.id);
    setActiveTab('review');
  }, []);

  // Update questions within the currently active paper
  const updateCurrentPaperQuestions = useCallback((newQuestions: QuestionData[]) => {
    if (!activePaperId) return;
    setHistory(prev => prev.map(p => 
      p.id === activePaperId ? { ...p, questions: newQuestions } : p
    ));
  }, [activePaperId]);

  const handleAddBulk = (qs: QuestionData[]) => {
    createPaperFromQuestions(qs);
  };

  const handleAuditRequest = async (id: string) => {
    const q = questions.find(item => item.id === id);
    if (!q || !q.original) return;

    setIsAuditingId(id);
    try {
      const result = await auditQuestion(q.original);
      const updatedQuestions = questions.map(item => 
        item.id === id 
          ? { 
              ...item, 
              topic: result.topic || item.topic,
              audit: {
                status: result.status,
                logs: result.auditLogs,
                redlines: result.redlines,
                clean: result.clean
              }, 
              version: item.version + 1 
            } 
          : item
      );
      updateCurrentPaperQuestions(updatedQuestions);
    } catch (err) {
      alert("Verification failed.");
    } finally {
      setIsAuditingId(null);
    }
  };

  const handleApprove = (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
        : item
    );
    updateCurrentPaperQuestions(updated);
  };

  const handleApproveAll = () => {
    if (window.confirm("Approve all currently audited questions?")) {
      const updated = questions.map(item => 
        item.audit && item.audit.status !== QuestionStatus.APPROVED
          ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
          : item
      );
      updateCurrentPaperQuestions(updated);
    }
  };

  const handleReject = (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.REJECTED }, version: item.version + 1 }
        : item
    );
    updateCurrentPaperQuestions(updated);
  };

  const handleLoadHistory = (paper: Paper) => {
    setActivePaperId(paper.id);
    // Based on role, set appropriate tab
    if (activeRole === UserRole.TEACHER) setActiveTab('review');
    else setActiveTab('approval');
  };

  const handleDeleteHistory = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Delete this paper permanently from the archive?")) {
      setHistory(prev => prev.filter(p => p.id !== id));
      if (activePaperId === id) {
        setActivePaperId(null);
        if (activeRole === UserRole.TEACHER) setActiveTab('input');
        else setActiveTab('analytics');
      }
    }
  };

  const generatePaperContent = (isRedlined: boolean = false) => {
    const title = currentPaper?.title || (isRedlined ? 'Audit Report' : 'Verified Questions');
    const htmlContent = questions.map((q, idx) => {
      const data = isRedlined && q.audit?.redlines ? q.audit.redlines : (q.audit?.clean || q.original);
      const cleanData = q.audit?.clean || q.original;
      const isNumerical = !data.options || data.options.length === 0;

      return `
        <div style="margin-bottom: 40px; page-break-inside: avoid; font-family: sans-serif;">
          <h3 style="color: #4f46e5; margin-bottom: 8px;">Question ${idx + 1} ${isNumerical ? '(Numerical)' : ''}</h3>
          <p style="font-size: 16px; line-height: 1.5;">${data.question}</p>
          <div style="margin: 15px 0;">
            ${isNumerical ? `
              <div style="margin-bottom: 5px; padding: 10px; background: #f0fdf4; border: 1px solid #bbf7d0; border-radius: 6px;">
                <strong style="color: #166534; font-size: 12px; text-transform: uppercase;">Correct Answer:</strong>
                <span style="font-size: 14px; font-weight: bold; margin-left: 10px;">${data.correctAnswer || cleanData.correctAnswer || 'N/A'}</span>
              </div>
            ` : `
              ${data.options!.map((opt, i) => `
                <div style="margin-bottom: 5px; padding: 10px; background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 6px; display: flex; align-items: flex-start; gap: 8px;">
                  <strong style="color: #6b7280; font-size: 14px;">${String.fromCharCode(65 + i)})</strong>
                  <span style="font-size: 14px; flex: 1;">${opt}</span>
                  ${!isRedlined && i === cleanData.correctOptionIndex ? '<span style="font-size: 10px; background: #10b981; color: white; padding: 2px 6px; border-radius: 4px; font-weight: bold;">CORRECT</span>' : ''}
                </div>
              `).join('')}
            `}
          </div>
          <div style="padding: 15px; background: #eef2ff; border-radius: 8px; border-left: 4px solid #4f46e5;">
            <p style="margin: 0; font-size: 14px; color: #374151;"><strong>Solution Logic:</strong> <em style="display: block; margin-top: 5px;">${data.solution}</em></p>
          </div>
          ${isRedlined && q.audit?.logs && q.audit.logs.length > 0 ? `
            <div style="margin-top: 15px; padding: 10px; border: 1px solid #fee2e2; background: #fef2f2; border-radius: 6px;">
              <strong style="font-size: 11px; text-transform: uppercase; color: #ef4444; display: block; margin-bottom: 5px;">Audit Intervention Notes:</strong>
              ${q.audit.logs.map(log => `<p style="font-size: 12px; margin: 4px 0; color: #b91c1c;">• [${log.type}] ${log.message}</p>`).join('')}
            </div>
          ` : ''}
        </div>
      `;
    }).join('');

    return `
      <html>
        <head>
          <style>
            body { padding: 40px; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; color: #1f2937; }
            h1 { text-align: center; border-bottom: 2px solid #e5e7eb; padding-bottom: 20px; color: #111827; }
            del { background-color: #fee2e2; color: #991b1b; text-decoration: line-through; padding: 0 2px; border-radius: 2px; }
            ins { background-color: #dcfce7; color: #166534; text-decoration: none; font-weight: bold; padding: 0 2px; border-radius: 2px; }
            .header-meta { text-align: right; color: #9ca3af; font-size: 12px; margin-bottom: 30px; }
          </style>
        </head>
        <body>
          <div class="header-meta">Audit System Report • ${new Date().toLocaleString()}</div>
          <h1>${title} ${isRedlined ? '(Intervention Logs)' : ''}</h1>
          ${htmlContent}
        </body>
      </html>
    `;
  };

  const handleExportPDF = () => {
    const win = window.open('', '_blank');
    if (win) {
      win.document.write(generatePaperContent(false));
      win.document.close();
      setTimeout(() => win.print(), 500);
    }
  };

  const handleExportRedlines = () => {
    const win = window.open('', '_blank');
    if (win) {
      win.document.write(generatePaperContent(true));
      win.document.close();
      setTimeout(() => win.print(), 500);
    }
  };

  const allLogs: AuditLog[] = history.flatMap(p => p.questions.flatMap(q => q.audit?.logs || []));

  const renderContent = () => {
    const workspaceKey = activePaperId || 'new-workspace';

    switch (activeTab) {
      case 'input':
        return <QuestionInput key="input-tab" onAdd={() => {}} onAddBulk={handleAddBulk} />;
      case 'review':
        return (
          <div key={workspaceKey} className="space-y-6 animate-in fade-in duration-300">
            <header className="mb-8 flex flex-col md:flex-row md:justify-between md:items-end gap-4 border-b border-slate-100 dark:border-slate-800 pb-6">
              <div>
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-[10px] font-black bg-indigo-100 dark:bg-indigo-900/40 text-indigo-600 px-2 py-0.5 rounded uppercase tracking-widest">Selected File</span>
                  {currentPaper && <span className="text-[10px] text-slate-400 font-bold">{new Date(currentPaper.createdAt).toLocaleString()}</span>}
                </div>
                <h1 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">
                  {currentPaper ? currentPaper.title : 'Workspace Empty'}
                </h1>
                <p className="text-slate-500 dark:text-slate-400 font-medium">Verify AI corrections and lock content for this specific paper.</p>
              </div>
              <div className="flex flex-wrap gap-2">
                <button 
                  onClick={handleExportRedlines}
                  disabled={questions.length === 0}
                  className="px-4 py-2 border-2 border-amber-200 dark:border-amber-900/40 text-amber-700 dark:text-amber-400 text-[10px] font-black rounded-lg hover:bg-amber-50 dark:hover:bg-amber-900/20 transition disabled:opacity-30 uppercase tracking-widest flex items-center gap-2"
                >
                  🚩 Download Redlines
                </button>
                <button 
                  onClick={handleExportPDF}
                  disabled={questions.length === 0}
                  className="px-4 py-2 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 text-[10px] font-black rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 transition disabled:opacity-30 uppercase tracking-widest"
                >
                  📄 Export Clean
                </button>
                <button 
                  onClick={() => { setActivePaperId(null); setActiveTab('input'); }}
                  className="px-6 py-2 bg-indigo-600 text-white text-[10px] font-black rounded-lg shadow-lg hover:bg-indigo-700 transition uppercase tracking-widest"
                >
                  + New Input
                </button>
              </div>
            </header>

            {questions.length === 0 ? (
              <div className="bg-white dark:bg-slate-800 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 p-16 text-center">
                <div className="w-16 h-16 bg-slate-50 dark:bg-slate-700 rounded-full flex items-center justify-center mx-auto mb-4">
                  <svg className="w-8 h-8 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
                  </svg>
                </div>
                <p className="text-slate-400 dark:text-slate-300 font-bold uppercase tracking-widest text-sm">No Paper Selected</p>
                <p className="text-xs text-slate-500 mt-2 mb-6">Select a file from the archive or start a new input.</p>
                <button onClick={() => setActiveTab('input')} className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition shadow-xl">Go to Input</button>
              </div>
            ) : (
              <div className="space-y-6">
                {questions.map((q, idx) => (
                  <QuestionCard 
                    key={`${workspaceKey}-${q.id}`} 
                    index={idx + 1}
                    data={q} 
                    onAudit={handleAuditRequest} 
                    isAuditing={isAuditingId === q.id} 
                  />
                ))}
              </div>
            )}
          </div>
        );
      case 'analytics':
        return <AnalyticsDashboard logs={allLogs} />;
      case 'approval':
        const pending = questions.filter(q => q.audit && q.audit.status !== QuestionStatus.APPROVED);
        return (
          <div key={`qc-${workspaceKey}`} className="space-y-6 animate-in fade-in duration-300">
            <header className="mb-8">
              <h1 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">QC Approvals</h1>
              <p className="text-slate-500 dark:text-slate-400 font-medium">Final review for: <span className="text-indigo-600 font-bold">{currentPaper?.title || 'No Paper Selected'}</span></p>
              <button 
                onClick={handleApproveAll} 
                disabled={pending.length === 0}
                className="mt-6 px-6 py-2.5 bg-indigo-600 text-white text-[10px] font-black rounded-lg uppercase tracking-widest hover:bg-indigo-700 transition disabled:opacity-30 shadow-lg"
              >
                Approve All Pending
              </button>
            </header>
            <div className="space-y-4">
              {pending.length === 0 ? (
                <div className="p-12 border border-dashed border-slate-200 dark:border-slate-700 rounded-2xl text-center">
                  <p className="text-slate-400 font-bold uppercase text-xs tracking-widest">All questions approved or none pending in this file.</p>
                </div>
              ) : (
                pending.map((q, idx) => {
                  // Find the true index in the full list
                  const trueIndex = questions.findIndex(item => item.id === q.id) + 1;
                  return (
                    <QuestionCard 
                      key={`qc-${workspaceKey}-${q.id}`} 
                      index={trueIndex}
                      data={q} 
                      onAudit={handleAuditRequest} 
                      onApprove={handleApprove} 
                      onReject={handleReject} 
                      isAuditing={isAuditingId === q.id} 
                      showQCControls 
                    />
                  );
                })
              )}
            </div>
          </div>
        );
      default: return null;
    }
  };

  return (
    <Layout 
      activeRole={activeRole} 
      onRoleSwitch={handleRoleSwitch}
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      history={history} 
      onLoadHistory={handleLoadHistory}
      activePaperId={activePaperId} 
      createNewPaper={() => { setActivePaperId(null); setActiveTab('input'); }}
      onDeleteHistory={handleDeleteHistory}
      isDarkMode={isDarkMode} 
      toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { QuestionData } from '../types';
import { auditRawQuestion, auditDocument } from '../services/geminiService';

interface QuestionInputProps {
  onAdd: (q: QuestionData) => void;
  onAddBulk: (qs: QuestionData[]) => void;
}

const LOADING_MESSAGES = [
  "Detecting question components...",
  "Parsing options A, B, C, D...",
  "Extracting solution logic...",
  "Verifying academic accuracy...",
  "Generating redline comparison...",
  "OCR in progress...",
];

const QuestionInput: React.FC<QuestionInputProps> = ({ onAdd, onAddBulk }) => {
  const [activeTab, setActiveTab] = useState<'SINGLE' | 'UPLOAD' | 'IMAGE'>('SINGLE');
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState(LOADING_MESSAGES[0]);
  const [progress, setProgress] = useState(0);
  const [rawInput, setRawInput] = useState('');
  const [stagedSnippets, setStagedSnippets] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    let interval: any;
    if (isProcessing) {
      let idx = 0;
      interval = setInterval(() => {
        idx = (idx + 1) % LOADING_MESSAGES.length;
        setLoadingMessage(LOADING_MESSAGES[idx]);
      }, 2000);
    }
    return () => clearInterval(interval);
  }, [isProcessing]);

  const handleStageSnippet = () => {
    if (!rawInput.trim()) return;
    setStagedSnippets(prev => [...prev, rawInput.trim()]);
    setRawInput('');
  };

  const removeStagedSnippet = (index: number) => {
    setStagedSnippets(prev => prev.filter((_, i) => i !== index));
  };

  const handleSmartPasteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const finalQueue = [...stagedSnippets];
    if (rawInput.trim()) finalQueue.push(rawInput.trim());

    if (finalQueue.length === 0) return;

    setIsProcessing(true);
    setProgress(10);
    try {
      const combinedInput = finalQueue.join('\n\n---NEXT QUESTION---\n\n');
      const results = await auditRawQuestion(combinedInput);

      const mappedQuestions: QuestionData[] = results.map((result: any) => ({
        id: Math.random().toString(36).substr(2, 9),
        topic: result.topic || 'Pasted Content',
        original: result.originalParsed,
        audit: {
          status: result.status,
          logs: result.auditLogs,
          redlines: result.redlines,
          clean: result.clean
        },
        version: 2,
        lastModified: Date.now()
      }));

      setProgress(100);
      setTimeout(() => {
        onAddBulk(mappedQuestions);
        setRawInput('');
        setStagedSnippets([]);
        setIsProcessing(false);
      }, 500);
    } catch (err) {
      alert("AI failed to parse the questions. Please ensure the text format is clear.");
      setIsProcessing(false);
    }
  };

  const processFiles = async (files: FileList | null, isImage: boolean) => {
    if (!files || files.length === 0) return;

    setIsProcessing(true);
    const filesArray: File[] = Array.from(files);

    try {
      for (let i = 0; i < filesArray.length; i++) {
        const file = filesArray[i];
        setLoadingMessage(`Scanning ${file.name} (${i + 1} of ${filesArray.length})...`);
        setProgress(Math.floor((i / filesArray.length) * 100));

        const base64 = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onload = () => {
            const result = reader.result as string;
            resolve(result.split(',')[1]);
          };
          reader.readAsDataURL(file);
        });

        const results = await auditDocument(base64, file.type);

        const mapped = results.map((res: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          topic: `[${file.name}] ${res.topic || 'General'}`,
          original: res.originalParsed,
          audit: {
            status: res.status,
            logs: res.auditLogs,
            redlines: res.redlines,
            clean: res.clean
          },
          version: 2,
          lastModified: Date.now()
        }));

        onAddBulk(mapped);
      }

      setProgress(100);
      setTimeout(() => {
        setIsProcessing(false);
      }, 500);
    } catch (err) {
      console.error(err);
      alert("Failed to process one or more files. Ensure they are clear and readable.");
      setIsProcessing(false);
    } finally {
      if (fileInputRef.current) fileInputRef.current.value = '';
      if (imageInputRef.current) imageInputRef.current.value = '';
    }
  };

  return (
    <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-700 overflow-hidden mb-8">
      <div className="flex border-b border-slate-200 dark:border-slate-700">
        <button 
          onClick={() => setActiveTab('SINGLE')}
          className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition ${activeTab === 'SINGLE' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50/30 dark:bg-indigo-900/30' : 'text-slate-400 hover:text-slate-600 dark:hover:text-slate-200'}`}
        >
          Smart Paste {stagedSnippets.length > 0 && `(${stagedSnippets.length})`}
        </button>
        <button 
          onClick={() => setActiveTab('UPLOAD')}
          className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition ${activeTab === 'UPLOAD' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50/30 dark:bg-indigo-900/30' : 'text-slate-400 hover:text-slate-600 dark:hover:text-slate-200'}`}
        >
          PDF/Docx Upload
        </button>
        <button 
          onClick={() => setActiveTab('IMAGE')}
