                <svg className="w-6 h-6" fill={activeTab === 'approval' ? "currentColor" : "none"} stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4" /></svg>
                <span className="text-[10px] font-bold">Approval</span>
              </button>

              <button onClick={() => setActiveTab('analytics')} className={`flex flex-col items-center gap-1 flex-1 py-1 transition-all ${activeTab === 'analytics' ? 'text-rose-600' : 'text-slate-400'}`}>
                <svg className="w-6 h-6" fill={activeTab === 'analytics' ? "currentColor" : "none"} stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 3.055A9.001 9.001 0 1020.945 13H11V3.055z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20.488 9H15V3.512A9.025 9.025 0 0120.488 9z" /></svg>
                <span className="text-[10px] font-bold">Stats</span>
              </button>
            </>
          )}
        </nav>
      </div>
    </div>
  );
};

export default Layout;

import React, { useState } from 'react';
import { QuestionData, QuestionStatus } from '../types';

interface QuestionCardProps {
  data: QuestionData;
  index: number; 
  onAudit: (id: string) => void;
  onApprove?: (id: string) => void;
  onReject?: (id: string) => void;
  isAuditing: boolean;
  showQCControls?: boolean;
}

const QuestionCard: React.FC<QuestionCardProps> = ({ 
  data, 
  index,
  onAudit, 
  onApprove, 
  onReject,
  isAuditing, 
  showQCControls 
}) => {
  const [viewMode, setViewMode] = useState<'AUDIT' | 'CLEAN'>('AUDIT');

  const getStatusStyle = (status: QuestionStatus) => {
    switch (status) {
      case QuestionStatus.APPROVED: return 'bg-green-100 text-green-700 border-green-200';
      case QuestionStatus.NEEDS_CORRECTION: return 'bg-amber-100 text-amber-700 border-amber-200';
      case QuestionStatus.REJECTED: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-slate-100 text-slate-600 border-slate-200';
    }
  };

  const renderRedlined = (html: any) => {
    const safeHtml = typeof html === 'string' ? html : '';
    if (!safeHtml) return <span className="text-slate-400 italic">No content available</span>;

    return (
      <div 
        className="prose-sm max-w-none dark:text-slate-200"
        dangerouslySetInnerHTML={{ 
          __html: safeHtml.replace(/<del>/g, '<del class="bg-red-100 text-red-800 line-through px-1 rounded mx-0.5">')
                      .replace(/<\/del>/g, '</del>')
                      .replace(/<ins>/g, '<ins class="bg-green-100 text-green-800 font-medium px-1 rounded mx-0.5">')
                      .replace(/<\/ins>/g, '</ins>')
        }} 
      />
    );
  };

  const displayOptions = data.audit?.redlines?.options || data.original?.options || [];
  const cleanOptions = data.audit?.clean?.options || [];
  const correctIdx = data.audit?.clean?.correctOptionIndex ?? data.original?.correctOptionIndex ?? 0;
  const isNumerical = displayOptions.length === 0;

  return (
    <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden mb-6 group transition-all">
      {/* Header */}
      <div className="px-5 py-3.5 flex flex-wrap items-center justify-between border-b border-slate-100 dark:border-slate-700 bg-slate-50/50 dark:bg-slate-800/50 gap-3">
        <div className="flex items-center gap-3">
          <span className="flex items-center justify-center w-7 h-7 rounded-lg bg-indigo-600 text-white font-black text-xs shadow-sm">
            {index}
          </span>
          <div className="flex flex-col">
            <span className="text-[10px] font-black uppercase tracking-widest text-slate-400 leading-none mb-1">Entry</span>
            <span className={`px-2 py-0.5 rounded-full text-[8px] font-black border uppercase ${getStatusStyle(data.audit?.status || QuestionStatus.PENDING)}`}>
              {data.audit?.status || 'UNAUDITED'}
            </span>
          </div>
        </div>

        <div className="flex items-center gap-2 ml-auto">
          {!data.audit && !isAuditing && (
            <button 
              onClick={() => onAudit(data.id)}
              className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-[10px] font-black rounded-lg shadow-sm transition active:scale-95 uppercase tracking-wider"
            >
              Start AI Audit
            </button>
          )}
          {isAuditing && <span className="text-[10px] text-indigo-500 animate-pulse font-black uppercase">Verifying...</span>}

          {data.audit && (
            <div className="inline-flex rounded-xl bg-slate-200 dark:bg-slate-700 p-1">
              <button 
                onClick={() => setViewMode('AUDIT')}
                className={`px-3 py-1.5 text-[9px] font-black rounded-lg transition-all ${viewMode === 'AUDIT' ? 'bg-white dark:bg-slate-900 shadow-sm text-slate-900 dark:text-slate-50' : 'text-slate-500 dark:text-slate-400'}`}
              >
                AUDIT
              </button>
              <button 
                onClick={() => setViewMode('CLEAN')}
                className={`px-3 py-1.5 text-[9px] font-black rounded-lg transition-all ${viewMode === 'CLEAN' ? 'bg-white dark:bg-slate-900 shadow-sm text-slate-900 dark:text-slate-50' : 'text-slate-500 dark:text-slate-400'}`}
              >
                CLEAN
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Content */}
      <div className="p-5">
        {viewMode === 'AUDIT' || !data.audit ? (
          <div className="space-y-5">
            <div>
              <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase mb-2 tracking-widest">Question Workspace</p>
              <div className="text-sm font-medium text-slate-800 dark:text-slate-100 leading-relaxed">
                {data.audit?.redlines?.question ? (
                  renderRedlined(data.audit.redlines.question)
                ) : (
                  data.original?.question || 'Empty question body.'
                )}
              </div>
            </div>

            {isNumerical ? (
              <div className="p-4 bg-indigo-50/50 dark:bg-indigo-900/10 border border-indigo-100 dark:border-indigo-800 rounded-xl">
                <p className="text-[9px] font-black text-indigo-500 uppercase mb-2 tracking-widest">Key Answer</p>
                <div className="text-sm font-black text-slate-700 dark:text-slate-100">
                  {data.audit?.redlines?.correctAnswer ? renderRedlined(data.audit.redlines.correctAnswer) : (data.original?.correctAnswer || 'N/A')}
                </div>
              </div>
            ) : (
              <div className="grid grid-cols-1 gap-3">
                {displayOptions.map((opt, i) => (
                  <div key={i} className={`p-3 rounded-xl border-2 flex items-start gap-3 transition-colors ${i === correctIdx ? 'bg-green-50/50 border-green-500/30' : 'border-slate-50 dark:border-slate-700 bg-slate-50/50 dark:bg-slate-700/30'}`}>
                    <span className="font-black text-[10px] text-slate-400 dark:text-slate-500 mt-0.5">{String.fromCharCode(65+i)}</span>
                    <div className="text-xs font-semibold text-slate-700 dark:text-slate-200 leading-snug">
                      {data.audit?.redlines?.options ? renderRedlined(opt) : opt}
                    </div>
                  </div>
                ))}
              </div>
            )}

            <div>
              <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase mb-2 tracking-widest">Audit Logs</p>
              <div className="bg-slate-50 dark:bg-slate-900/50 p-3 rounded-xl border border-slate-100 dark:border-slate-700 text-xs italic text-slate-600 dark:text-slate-400 leading-relaxed">
                {data.audit?.redlines?.solution ? renderRedlined(data.audit.redlines.solution) : data.original?.solution}
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <div>
              <p className="text-[9px] font-black text-green-500 uppercase mb-2 tracking-widest">Final Version</p>
              <p className="text-base font-bold text-slate-900 dark:text-slate-50 leading-relaxed">{data.audit?.clean?.question}</p>
            </div>

            {isNumerical ? (
              <div className="p-5 bg-green-50/50 dark:bg-green-900/10 border-2 border-green-500/20 rounded-2xl">
                <p className="text-[9px] font-black text-green-600 uppercase mb-2 tracking-widest">Verified Result</p>
                <p className="text-2xl font-black text-slate-900 dark:text-slate-50">{data.audit?.clean?.correctAnswer}</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 gap-3">
                {cleanOptions.map((opt, i) => (
                  <div key={i} className={`p-4 rounded-2xl border-2 transition-all ${i === correctIdx ? 'border-green-500 bg-green-50/50 shadow-sm' : 'border-slate-100 dark:border-slate-700'}`}>
                    <div className="flex items-center justify-between mb-1">
                      <span className="font-black text-slate-400 text-[10px]">{String.fromCharCode(65+i)}</span>
                      {i === correctIdx && <span className="bg-green-600 text-white text-[7px] font-black px-1.5 py-0.5 rounded-full uppercase tracking-tighter">Verified Correct</span>}
                    </div>
                    <p className="text-sm font-bold text-slate-800 dark:text-slate-100">{opt}</p>
                  </div>
                ))}
              </div>
            )}

            <div className="p-4 bg-indigo-50/50 dark:bg-indigo-900/20 rounded-2xl border border-indigo-100 dark:border-indigo-800">
               <p className="text-[9px] font-black text-indigo-500 uppercase mb-2 tracking-widest">Solution Reference</p>
               <p className="text-xs font-semibold text-slate-700 dark:text-slate-300 leading-relaxed">{data.audit?.clean?.solution}</p>
            </div>
          </div>
        )}
      </div>

      {/* QC Actions (Mobile Friendly Footer) */}
      {showQCControls && data.audit && (
        <div className="px-5 py-4 bg-slate-900 border-t border-slate-800 flex flex-col sm:flex-row justify-between items-center gap-4">
          <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.2em] hidden sm:block">Administrative QC Queue</p>
          <div className="flex w-full sm:w-auto gap-3">
             <button 
              onClick={() => onApprove?.(data.id)}
              className="flex-1 sm:px-6 py-3 bg-green-600 text-white text-[10px] font-black rounded-xl uppercase tracking-widest shadow-lg active:scale-95 transition-all"
            >
              Approve
            </button>
            <button 
              onClick={() => onReject?.(data.id)}
              className="flex-1 sm:px-6 py-3 border border-red-500/50 text-red-400 bg-red-950/20 text-[10px] font-black rounded-xl uppercase tracking-widest active:scale-95 transition-all"
            >
              Reject
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default QuestionCard;

import React, { useState, useRef, useEffect } from 'react';
import { QuestionData } from '../types';
import { auditRawQuestion, auditDocument } from '../services/geminiService';
import mammoth from 'mammoth';

interface QuestionInputProps {
  onAdd: (q: QuestionData) => void;
  onAddBulk: (qs: QuestionData[]) => void;
}

const LOADING_MESSAGES = [
  "Detecting question components...",
  "Parsing options A, B, C, D...",
  "Extracting solution logic...",
  "Verifying academic accuracy...",
  "OCR in progress...",
];

const QuestionInput: React.FC<QuestionInputProps> = ({ onAdd, onAddBulk }) => {
  const [activeTab, setActiveTab] = useState<'SINGLE' | 'UPLOAD' | 'IMAGE'>('SINGLE');
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState(LOADING_MESSAGES[0]);
  const [progress, setProgress] = useState(0);
  const [rawInput, setRawInput] = useState('');
  const [stagedSnippets, setStagedSnippets] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    let interval: any;
    if (isProcessing) {
      let idx = 0;
      interval = setInterval(() => {
        idx = (idx + 1) % LOADING_MESSAGES.length;
        setLoadingMessage(LOADING_MESSAGES[idx]);
      }, 2000);
    }
    return () => clearInterval(interval);
  }, [isProcessing]);

  const handleStageSnippet = () => {
    if (!rawInput.trim()) return;
    setStagedSnippets(prev => [...prev, rawInput.trim()]);
    setRawInput('');
  };

  const removeStagedSnippet = (index: number) => {
    setStagedSnippets(prev => prev.filter((_, i) => i !== index));
  };

  const handleSmartPasteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const finalQueue = [...stagedSnippets];
    if (rawInput.trim()) finalQueue.push(rawInput.trim());

    if (finalQueue.length === 0) return;

    setIsProcessing(true);
    setProgress(10);
    try {
      const combinedInput = finalQueue.join('\n\n---NEXT QUESTION---\n\n');
      const results = await auditRawQuestion(combinedInput);

      const mappedQuestions: QuestionData[] = results.map((result: any) => ({
        id: Math.random().toString(36).substr(2, 9),
        topic: result.topic || 'Pasted Content',
        original: result.originalParsed,
        audit: {
          status: result.status,
          logs: result.auditLogs,
          redlines: result.redlines,
          clean: result.clean
        },
        version: 2,
        lastModified: Date.now()
      }));

      setProgress(100);
      setTimeout(() => {
        onAddBulk(mappedQuestions);
        setRawInput('');
        setStagedSnippets([]);
        setIsProcessing(false);
      }, 500);
    } catch (err) {
      alert("AI failed to parse the questions.");
      setIsProcessing(false);
    }
  };

  const processFiles = async (files: FileList | null, isImage: boolean) => {
    if (!files || files.length === 0) return;

    setIsProcessing(true);
    const filesArray: File[] = Array.from(files);

    try {
      for (let i = 0; i < filesArray.length; i++) {
        const file = filesArray[i];
        setLoadingMessage(`Scanning ${file.name.slice(0, 10)}...`);
        setProgress(Math.floor((i / filesArray.length) * 100));

        const isDocx = file.name.toLowerCase().endsWith('.docx');
        let results: any[] = [];

        if (isDocx) {
          const arrayBuffer = await file.arrayBuffer();
          const extractResult = await mammoth.extractRawText({ arrayBuffer });
          results = await auditRawQuestion(extractResult.value);
        } else {
          const base64 = await new Promise<string>((resolve) => {
            const reader = new FileReader();
            reader.onload = () => resolve((reader.result as string).split(',')[1]);
            reader.readAsDataURL(file);
          });
          results = await auditDocument(base64, file.type);
        }

        const mapped = results.map((res: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          topic: `[File] ${res.topic || 'General'}`,
          original: res.originalParsed,
          audit: { status: res.status, logs: res.auditLogs, redlines: res.redlines, clean: res.clean },
          version: 2,
          lastModified: Date.now()
        }));

        onAddBulk(mapped);
      }
      setProgress(100);
      setTimeout(() => setIsProcessing(false), 500);
    } catch (err) {
      alert("Processing failed.");
      setIsProcessing(false);
    }
  };

  return (
    <div className="bg-white dark:bg-slate-800 rounded-2xl lg:rounded-3xl shadow-2xl border border-slate-200 dark:border-slate-700 overflow-hidden mb-8 transition-all">
      {/* Mobile-Friendly Segmented Controller */}
      <div className="flex p-1.5 bg-slate-100 dark:bg-slate-900 border-b border-slate-200 dark:border-slate-700">
        <button 
          onClick={() => setActiveTab('SINGLE')}
          className={`flex-1 py-2.5 text-[9px] font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'SINGLE' ? 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm' : 'text-slate-500'}`}
        >
          Paste {stagedSnippets.length > 0 && `(${stagedSnippets.length})`}
        </button>
        <button 
          onClick={() => setActiveTab('UPLOAD')}
          className={`flex-1 py-2.5 text-[9px] font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'UPLOAD' ? 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm' : 'text-slate-500'}`}
        >
          Files
        </button>
        <button 
          onClick={() => setActiveTab('IMAGE')}
          className={`flex-1 py-2.5 text-[9px] font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'IMAGE' ? 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm' : 'text-slate-500'}`}
        >
          Camera
        </button>
      </div>

      <div className="p-5 lg:p-8 relative min-h-[400px]">
        {isProcessing && (
          <div className="absolute inset-0 bg-white/95 dark:bg-slate-900/95 backdrop-blur-md z-10 flex flex-col items-center justify-center space-y-8 px-6 text-center">
            <div className="relative">
              <div className="w-20 h-20 border-4 border-slate-100 dark:border-slate-800 rounded-full"></div>
              <div className="absolute inset-0 w-20 h-20 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-900 dark:text-slate-50 uppercase tracking-widest">Processing</h3>
              <p className="text-xs font-bold text-indigo-600 animate-pulse mt-2 h-4">{loadingMessage}</p>
              <div className="mt-8 w-64 h-2.5 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden mx-auto">
                <div className="h-full bg-indigo-600 transition-all duration-500 rounded-full" style={{ width: `${progress}%` }}></div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'SINGLE' && (
          <div className="space-y-6 animate-in fade-in zoom-in-95 duration-300">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3 block px-1">Raw Content Entry</label>
              <textarea 
                rows={10}
                className="w-full px-5 py-4 rounded-2xl border-2 border-slate-100 dark:border-slate-700 focus:border-indigo-500 focus:ring-0 transition-all bg-slate-50/50 dark:bg-slate-900/50 text-slate-800 dark:text-slate-100 font-medium text-base lg:text-sm leading-relaxed shadow-inner"
                placeholder="Type or paste questions here. 16px font prevents iOS auto-zoom..."
                value={rawInput}
                onChange={e => setRawInput(e.target.value)}
              />
            </div>

            {stagedSnippets.length > 0 && (
              <div className="grid grid-cols-1 gap-2">
                {stagedSnippets.map((snippet, idx) => (
                  <div key={idx} className="flex items-center justify-between p-3.5 bg-indigo-50/30 dark:bg-indigo-900/10 border border-indigo-100/50 dark:border-indigo-800/50 rounded-xl group">
                    <div className="flex items-center gap-3 overflow-hidden">
                      <span className="w-5 h-5 flex items-center justify-center bg-indigo-600 text-white rounded-lg text-[10px] font-black shrink-0">{idx + 1}</span>
                      <p className="text-[11px] font-bold text-slate-600 dark:text-slate-300 truncate">{snippet.slice(0, 30)}...</p>
                    </div>
                    <button onClick={() => removeStagedSnippet(idx)} className="text-red-400 p-2 active:scale-90 transition-transform">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
                    </button>
                  </div>
                ))}
              </div>
            )}

            <div className="flex flex-col gap-3 pt-4 border-t border-slate-100 dark:border-slate-700">
               <button 
                type="button"
                onClick={handleStageSnippet}
                disabled={!rawInput.trim() || isProcessing}
                className="w-full py-4 border-2 border-indigo-600 text-indigo-600 font-black rounded-2xl transition active:scale-[0.98] text-xs uppercase tracking-widest flex items-center justify-center gap-2"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" /></svg>
                Stage Batch
              </button>
              <button 
                type="button"
                onClick={handleSmartPasteSubmit}
                disabled={(stagedSnippets.length === 0 && !rawInput.trim()) || isProcessing}
                className="w-full py-4 bg-slate-900 dark:bg-indigo-600 text-white font-black rounded-2xl shadow-xl transition active:scale-[0.98] text-xs uppercase tracking-widest"
              >
                Submit for Audit ({stagedSnippets.length + (rawInput.trim() ? 1 : 0)})
              </button>
            </div>
          </div>
        )}

        {activeTab === 'UPLOAD' && (
          <div className="py-12 px-6 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl group bg-slate-50/50 dark:bg-slate-900/50 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="w-16 h-16 bg-indigo-100 dark:bg-indigo-900/40 rounded-3xl flex items-center justify-center mb-6">
              <svg className="w-8 h-8 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg>
            </div>
            <h3 className="text-lg font-black text-slate-900 dark:text-slate-50 uppercase tracking-widest">Document Portal</h3>
            <p className="text-xs text-slate-500 dark:text-slate-400 mt-2 font-bold">PDF, Word, or Bulk Archives</p>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="mt-10 w-full py-4 bg-slate-900 text-white text-xs font-black uppercase tracking-widest rounded-2xl shadow-xl active:scale-95 transition-all"
            >
              Select Files
            </button>
            <input type="file" className="hidden" ref={fileInputRef} accept=".pdf,.docx" multiple onChange={(e) => processFiles(e.target.files, false)} />
          </div>
        )}

        {activeTab === 'IMAGE' && (
          <div className="py-12 px-6 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl group bg-slate-50/50 dark:bg-slate-900/50 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="w-16 h-16 bg-emerald-100 dark:bg-emerald-900/40 rounded-3xl flex items-center justify-center mb-6">
              <svg className="w-8 h-8 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
            </div>
            <h3 className="text-lg font-black text-slate-900 dark:text-slate-50 uppercase tracking-widest">Visual Scanner</h3>
            <p className="text-xs text-slate-500 dark:text-slate-400 mt-2 font-bold">Snap a photo of the paper</p>
            <button 
              onClick={() => imageInputRef.current?.click()}
              className="mt-10 w-full py-4 bg-slate-900 text-white text-xs font-black uppercase tracking-widest rounded-2xl shadow-xl active:scale-95 transition-all"
            >
              Open Camera
            </button>
            <input type="file" className="hidden" ref={imageInputRef} accept="image/*" multiple capture="environment" onChange={(e) => processFiles(e.target.files, true)} />
          </div>
        )}
      </div>
    </div>
  );
};

