{
  "name": "Paper Checker AI 2",
  "description": "An intelligent teacher-facing tool for verifying question papers, featuring AI-driven error detection, redlined corrections, and rigorous quality control.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import Layout from './components/Layout';
import QuestionInput from './components/QuestionInput';
import QuestionCard from './components/QuestionCard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import LoginScreen from './components/LoginScreen';
import { UserRole, QuestionData, Paper, QuestionStatus, AuditLog, UserProfile } from './types';
import { auditQuestion } from './services/geminiService';
import { dbService, MOCK_USERS } from './services/dbService';

const STORAGE_KEY_DARK_MODE = 'paperchecker_dark_mode_v2';
const STORAGE_KEY_USER_ID = 'paperchecker_active_user_id';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(() => {
    const savedId = localStorage.getItem(STORAGE_KEY_USER_ID);
    return MOCK_USERS.find(u => u.id === savedId) || null;
  });

  const [activeTab, setActiveTab] = useState<string>('input');
  const [history, setHistory] = useState<Paper[]>([]);
  const [activePaperId, setActivePaperId] = useState<string | null>(null);
  const [isAuditingId, setIsAuditingId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState<boolean>(false);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    try {
      const savedMode = localStorage.getItem(STORAGE_KEY_DARK_MODE);
      if (savedMode !== null) return JSON.parse(savedMode);
    } catch (e) {}
    return window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  // Handle Android Back Button / Browser Back History
  useEffect(() => {
    const handlePopState = (event: PopStateEvent) => {
      if (event.state && event.state.tab) {
        setActiveTab(event.state.tab);
        setActivePaperId(event.state.paperId || null);
      } else {
        // Fallback or exit logic if at start
      }
    };
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigateToTab = (tab: string, paperId: string | null = null) => {
    setActiveTab(tab);
    setActivePaperId(paperId);
    // Push to history for Android back button support
    window.history.pushState({ tab, paperId }, '', `#${tab}`);
  };

  // Initial Data Load
  useEffect(() => {
    const init = async () => {
      setIsLoading(true);
      try {
        const papers = await dbService.getPapers();
        setHistory(papers);
        if (papers.length > 0) {
          const firstPaper = papers[0];
          setActivePaperId(firstPaper.id);
          // Seed history
          window.history.replaceState({ tab: 'review', paperId: firstPaper.id }, '', '#review');
        }
      } finally {
        setIsLoading(false);
      }
    };
    init();
  }, []);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDarkMode);
    localStorage.setItem(STORAGE_KEY_DARK_MODE, JSON.stringify(isDarkMode));
  }, [isDarkMode]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem(STORAGE_KEY_USER_ID, currentUser.id);
      const initialTab = currentUser.role === UserRole.QC_HEAD ? 'approval' : 'input';
      setActiveTab(initialTab);
    } else {
      localStorage.removeItem(STORAGE_KEY_USER_ID);
    }
  }, [currentUser]);

  const currentPaper = useMemo(() => {
    return history.find(p => p.id === activePaperId) || null;
  }, [history, activePaperId]);

  const questions = useMemo(() => currentPaper?.questions || [], [currentPaper]);

  const createPaperFromQuestions = useCallback(async (qs: QuestionData[]) => {
    if (!currentUser) return;
    setIsSyncing(true);
    const paperName = qs[0]?.topic || 'New Submission';
    const newPaper: Paper = {
      id: Math.random().toString(36).substr(2, 9),
      title: paperName,
      subject: paperName,
      createdBy: currentUser.id,
      creatorName: currentUser.name,
      status: 'PENDING_QC',
      questions: qs,
      createdAt: Date.now()
    };

    await dbService.savePaper(newPaper);
    setHistory(prev => [newPaper, ...prev]);
    navigateToTab('review', newPaper.id);
    setIsSyncing(false);
  }, [currentUser]);

  const updateCurrentPaperQuestions = useCallback(async (newQuestions: QuestionData[]) => {
    if (!activePaperId || !currentPaper) return;
    setIsSyncing(true);
    const updatedPaper = { ...currentPaper, questions: newQuestions };
    await dbService.savePaper(updatedPaper);
    setHistory(prev => prev.map(p => p.id === activePaperId ? updatedPaper : p));
    setIsSyncing(false);
  }, [activePaperId, currentPaper]);

  const handleAuditRequest = async (id: string) => {
    const q = questions.find(item => item.id === id);
    if (!q || !q.original) return;

    setIsAuditingId(id);
    try {
      const result = await auditQuestion(q.original);
      const updatedQuestions = questions.map(item => 
        item.id === id 
          ? { 
              ...item, 
              topic: result.topic || item.topic,
              audit: {
                status: result.status,
                logs: result.auditLogs,
                redlines: result.redlines,
                clean: result.clean
              }, 
              version: item.version + 1 
            } 
          : item
      );
      await updateCurrentPaperQuestions(updatedQuestions);
    } catch (err) {
      alert("AI Audit failed.");
    } finally {
      setIsAuditingId(null);
    }
  };

  const handleApprove = async (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.APPROVED }, version: item.version + 1 }
        : item
    );
    await updateCurrentPaperQuestions(updated);
  };

  const handleReject = async (id: string) => {
    const updated = questions.map(item => 
      item.id === id && item.audit
        ? { ...item, audit: { ...item.audit, status: QuestionStatus.REJECTED }, version: item.version + 1 }
        : item
    );
    await updateCurrentPaperQuestions(updated);
  };

  const handleDeleteHistory = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Delete this submission from cloud storage?")) {
      setIsSyncing(true);
      await dbService.deletePaper(id);
      setHistory(prev => prev.filter(p => p.id !== id));
      if (activePaperId === id) setActivePaperId(null);
      setIsSyncing(false);
    }
  };

  const allLogs: AuditLog[] = history.flatMap(p => p.questions.flatMap(q => q.audit?.logs || []));

  if (isLoading) {
    return (
      <div className="h-screen-dynamic w-full flex flex-col items-center justify-center bg-slate-900 text-white">
        <div className="w-10 h-10 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4" />
        <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">Initializing Workspace</p>
      </div>
    );
  }

  if (!currentUser) {
    return <LoginScreen users={MOCK_USERS} onLogin={setCurrentUser} isDarkMode={isDarkMode} toggleDarkMode={() => setIsDarkMode(!isDarkMode)} />;
  }

  return (
    <Layout 
      currentUser={currentUser}
      onUserSwitch={setCurrentUser}
      users={MOCK_USERS}
      activeTab={activeTab} 
      setActiveTab={navigateToTab}
      history={history} 
      onLoadHistory={(p) => navigateToTab('review', p.id)}
      activePaperId={activePaperId} 
      onDeleteHistory={handleDeleteHistory}
      isDarkMode={isDarkMode} 
      toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
      isSyncing={isSyncing}
      onLogout={() => setCurrentUser(null)}
    >
      {activeTab === 'input' && <QuestionInput onAdd={() => {}} onAddBulk={createPaperFromQuestions} />}

      {activeTab === 'review' && (
        <div className="space-y-4 lg:space-y-6">
          <header className="mb-6 lg:mb-8 border-b border-slate-100 dark:border-slate-800 pb-5">
            <h1 className="text-2xl lg:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">
              {currentPaper ? currentPaper.title : 'Drafts'}
            </h1>
            <p className="text-xs lg:text-sm text-slate-500 dark:text-slate-400 font-medium mt-1">Self-audit and prepare for submission.</p>
          </header>
          {questions.length === 0 ? (
            <div className="text-center py-16 bg-white dark:bg-slate-800 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-700">
               <p className="text-slate-400 font-black uppercase tracking-widest text-[10px]">Empty Paper</p>
               <button onClick={() => navigateToTab('input')} className="mt-4 text-indigo-600 font-bold text-sm">Create content now →</button>
            </div>
          ) : (
            questions.map((q, idx) => (
              <QuestionCard key={q.id} index={idx + 1} data={q} onAudit={handleAuditRequest} isAuditing={isAuditingId === q.id} />
            ))
          )}
        </div>
      )}

      {activeTab === 'approval' && (
        <div className="space-y-4 lg:space-y-6">
           <header className="mb-6 lg:mb-8">
            <h1 className="text-2xl lg:text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight">Approval Queue</h1>
            <p className="text-xs lg:text-sm text-slate-500 dark:text-slate-400 font-medium mt-1">Final review of submitted content.</p>
          </header>
          {questions.length === 0 ? (
             <div className="text-center py-16 bg-white dark:bg-slate-800 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-700">
                <p className="text-slate-400 font-black uppercase tracking-widest text-[10px]">Queue Clear</p>
             </div>
          ) : (
            questions.map((q, idx) => (
              <QuestionCard 
                key={q.id} 
                index={idx + 1} 
                data={q} 
                onAudit={handleAuditRequest} 
                onApprove={handleApprove} 
                onReject={handleReject} 
                isAuditing={isAuditingId === q.id} 
                showQCControls 
              />
            ))
          )}
        </div>
      )}

      {activeTab === 'analytics' && <AnalyticsDashboard logs={allLogs} />}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { UserRole, Paper, UserProfile } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  currentUser: UserProfile;
  onUserSwitch: (user: UserProfile) => void;
  users: UserProfile[];
  activeTab: string;
  setActiveTab: (tab: string, paperId?: string | null) => void;
  history: Paper[];
  onLoadHistory: (paper: Paper) => void;
  onDeleteHistory: (e: React.MouseEvent, id: string) => void;
  activePaperId: string | null;
  isDarkMode: boolean;
  toggleDarkMode: () => void;
  isSyncing: boolean;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ 
  children, 
  currentUser,
  onUserSwitch,
  users,
  activeTab, 
  setActiveTab,
  history,
  onLoadHistory,
  onDeleteHistory,
  activePaperId,
  isDarkMode,
  toggleDarkMode,
  isSyncing,
  onLogout
}) => {
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);

  // Disable body scroll when drawer is open
  useEffect(() => {
    if (isDrawerOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
  }, [isDrawerOpen]);

  const toggleDrawer = () => setIsDrawerOpen(!isDrawerOpen);
  const closeDrawer = () => setIsDrawerOpen(false);

  const formatTime = (ts: number) => {
    const diff = Date.now() - ts;
    const mins = Math.floor(diff / 60000);
    if (mins < 60) return `${mins}m`;
    return new Date(ts).toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
  };

  const getStatusBadge = (status: Paper['status']) => {
    switch(status) {
      case 'PENDING_QC': return 'bg-amber-100 text-amber-700 border-amber-200 dark:bg-amber-900/40 dark:text-amber-300 dark:border-amber-800';
      case 'APPROVED': return 'bg-emerald-100 text-emerald-700 border-emerald-200 dark:bg-emerald-900/40 dark:text-emerald-300 dark:border-emerald-800';
      case 'REJECTED': return 'bg-rose-100 text-rose-700 border-rose-200 dark:bg-rose-900/40 dark:text-rose-300 dark:border-rose-800';
      default: return 'bg-slate-100 text-slate-500 border-slate-200 dark:bg-slate-800 dark:text-slate-400 dark:border-slate-700';
    }
  };

  return (
    <div className="flex h-screen-dynamic w-full bg-slate-50 text-slate-900 dark:bg-slate-900 dark:text-slate-50 transition-colors duration-300 overflow-hidden">
      {/* Mobile Drawer Backdrop */}
      <div 
        className={`fixed inset-0 bg-slate-900/70 z-[60] lg:hidden transition-opacity duration-300 ${isDrawerOpen ? 'opacity-100 backdrop-blur-sm' : 'opacity-0 pointer-events-none'}`}
        onClick={closeDrawer}
      />

      {/* Sidebar - Desktop Always, Mobile Slide-in Drawer */}
      <aside className={`fixed inset-y-0 left-0 w-72 bg-slate-900 text-white flex flex-col z-[70] shadow-2xl transition-transform duration-300 lg:translate-x-0 lg:static lg:z-10 ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-6 border-b border-slate-800 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <span className="bg-indigo-600 p-1.5 rounded-lg text-lg">🔍</span>
            <div className="flex flex-col">
              <h1 className="text-base font-black tracking-tight leading-none">PAPER CLOUD</h1>
              <div className="flex items-center gap-1.5 mt-1">
                <div className={`w-1.5 h-1.5 rounded-full ${isSyncing ? 'bg-indigo-400 animate-pulse' : 'bg-green-400'}`} />
                <span className="text-[8px] uppercase tracking-widest text-slate-500 font-black">
                  {isSyncing ? 'Syncing...' : 'Connected'}
                </span>
              </div>
            </div>
          </div>
          <button onClick={toggleDarkMode} className="p-2 rounded-xl bg-slate-800 hover:bg-slate-700 text-slate-400 transition-colors">
            {isDarkMode ? '☀️' : '🌙'}
          </button>
        </div>

        <nav className="flex-1 p-5 space-y-1 overflow-y-auto custom-scrollbar">
          <div className="px-3 mb-3">
             <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Navigation</p>
          </div>

          <div className="space-y-1">
            {currentUser.role === UserRole.TEACHER ? (
              <>
                <button onClick={() => {setActiveTab('input'); closeDrawer();}} className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-semibold transition-all ${activeTab === 'input' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800'}`}>
                  <svg className="w-5 h-5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                  New Submission
                </button>
                <button onClick={() => {setActiveTab('review'); closeDrawer();}} className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-semibold transition-all ${activeTab === 'review' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800'}`}>
                  <svg className="w-5 h-5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
                  My Papers
                </button>
              </>
            ) : (
              <>
                <button onClick={() => {setActiveTab('approval'); closeDrawer();}} className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-semibold transition-all ${activeTab === 'approval' ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800'}`}>
                  <svg className="w-5 h-5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                  QC Queue
                </button>
                <button onClick={() => {setActiveTab('analytics'); closeDrawer();}} className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-semibold transition-all ${activeTab === 'analytics' ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800'}`}>
                  <svg className="w-5 h-5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 3.055A9.001 9.001 0 1020.945 13H11V3.055z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20.488 9H15V3.512A9.025 9.025 0 0120.488 9z" /></svg>
                  Analytics
                </button>
              </>
            )}
          </div>

          <div className="pt-8 pb-4">
            <div className="px-3 flex items-center justify-between mb-4">
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Cloud Archive</p>
            </div>

            <div className="space-y-2">
              {history.length === 0 ? (
                <div className="px-4 py-6 text-center border border-dashed border-slate-800 rounded-2xl">
                  <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest">No Cloud Data</p>
                </div>
              ) : (
                history.map((paper) => (
                  <div key={paper.id} className="relative group px-1">
