                      onClick={() => { onLoadHistory(paper); closeDrawer(); }}
                      className={`w-full text-left p-3.5 rounded-2xl border transition-all active:scale-[0.97] ${activePaperId === paper.id ? 'bg-slate-800 border-indigo-600' : 'bg-slate-900/40 border-slate-800 hover:bg-slate-800'}`}
                    >
                      <div className={`text-[11px] font-bold truncate ${activePaperId === paper.id ? 'text-indigo-400' : 'text-slate-200'}`}>
                        {paper.title}
                      </div>
                      <div className="flex items-center gap-2 mt-2">
                        <span className={`text-[8px] px-1.5 py-0.5 rounded-md font-black border uppercase tracking-tighter ${getStatusBadge(paper.status)}`}>
                          {paper.status.replace('_', ' ')}
