                    </button>
                    <button onClick={(e) => onDeleteHistory(e, paper.id)} className="absolute top-2 right-3 p-1.5 text-slate-700 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                      <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        </nav>

        {/* User Account / Profile Swapper */}
        <div className="p-4 border-t border-slate-800 relative bg-slate-900/80 backdrop-blur-md">
          <button 
            onClick={() => setShowProfileMenu(!showProfileMenu)}
