import React, { useState, useRef, useEffect } from 'react';
import { QuestionData } from '../types';
import { auditRawQuestion, auditDocument } from '../services/geminiService';
import mammoth from 'mammoth';

interface QuestionInputProps {
  onAdd: (q: QuestionData) => void;
  onAddBulk: (qs: QuestionData[]) => void;
}

const LOADING_MESSAGES = [
  "Detecting question components...",
  "Parsing options A, B, C, D...",
  "Extracting solution logic...",
  "Verifying academic accuracy...",
  "OCR in progress...",
];

const QuestionInput: React.FC<QuestionInputProps> = ({ onAdd, onAddBulk }) => {
  const [activeTab, setActiveTab] = useState<'SINGLE' | 'UPLOAD' | 'IMAGE'>('SINGLE');
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState(LOADING_MESSAGES[0]);
  const [progress, setProgress] = useState(0);
  const [rawInput, setRawInput] = useState('');
  const [stagedSnippets, setStagedSnippets] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    let interval: any;
    if (isProcessing) {
      let idx = 0;
      interval = setInterval(() => {
        idx = (idx + 1) % LOADING_MESSAGES.length;
        setLoadingMessage(LOADING_MESSAGES[idx]);
      }, 2000);
    }
    return () => clearInterval(interval);
  }, [isProcessing]);

  const handleStageSnippet = () => {
    if (!rawInput.trim()) return;
    setStagedSnippets(prev => [...prev, rawInput.trim()]);
    setRawInput('');
  };

  const removeStagedSnippet = (index: number) => {
    setStagedSnippets(prev => prev.filter((_, i) => i !== index));
  };

  const handleSmartPasteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const finalQueue = [...stagedSnippets];
    if (rawInput.trim()) finalQueue.push(rawInput.trim());

    if (finalQueue.length === 0) return;

    setIsProcessing(true);
    setProgress(10);
    try {
      const combinedInput = finalQueue.join('\n\n---NEXT QUESTION---\n\n');
      const results = await auditRawQuestion(combinedInput);

      const mappedQuestions: QuestionData[] = results.map((result: any) => ({
        id: Math.random().toString(36).substr(2, 9),
        topic: result.topic || 'Pasted Content',
        original: result.originalParsed,
        audit: {
          status: result.status,
          logs: result.auditLogs,
          redlines: result.redlines,
          clean: result.clean
        },
        version: 2,
        lastModified: Date.now()
      }));

      setProgress(100);
      setTimeout(() => {
        onAddBulk(mappedQuestions);
        setRawInput('');
        setStagedSnippets([]);
        setIsProcessing(false);
      }, 500);
    } catch (err) {
      alert("AI failed to parse the questions.");
      setIsProcessing(false);
    }
  };

  const processFiles = async (files: FileList | null, isImage: boolean) => {
    if (!files || files.length === 0) return;

    setIsProcessing(true);
    const filesArray: File[] = Array.from(files);

    try {
      for (let i = 0; i < filesArray.length; i++) {
        const file = filesArray[i];
        setLoadingMessage(`Scanning ${file.name.slice(0, 10)}...`);
        setProgress(Math.floor((i / filesArray.length) * 100));

        const isDocx = file.name.toLowerCase().endsWith('.docx');
        let results: any[] = [];

        if (isDocx) {
          const arrayBuffer = await file.arrayBuffer();
          const extractResult = await mammoth.extractRawText({ arrayBuffer });
          results = await auditRawQuestion(extractResult.value);
        } else {
          const base64 = await new Promise<string>((resolve) => {
            const reader = new FileReader();
            reader.onload = () => resolve((reader.result as string).split(',')[1]);
            reader.readAsDataURL(file);
          });
          results = await auditDocument(base64, file.type);
        }

        const mapped = results.map((res: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          topic: `[File] ${res.topic || 'General'}`,
          original: res.originalParsed,
          audit: { status: res.status, logs: res.auditLogs, redlines: res.redlines, clean: res.clean },
          version: 2,
          lastModified: Date.now()
        }));

        onAddBulk(mapped);
      }
      setProgress(100);
      setTimeout(() => setIsProcessing(false), 500);
    } catch (err) {
      alert("Processing failed.");
      setIsProcessing(false);
    }
  };

  return (
    <div className="bg-white dark:bg-slate-800 rounded-2xl lg:rounded-3xl shadow-2xl border border-slate-200 dark:border-slate-700 overflow-hidden mb-8 transition-all">
      {/* Mobile-Friendly Segmented Controller */}
      <div className="flex p-1.5 bg-slate-100 dark:bg-slate-900 border-b border-slate-200 dark:border-slate-700">
        <button 
          onClick={() => setActiveTab('SINGLE')}
          className={`flex-1 py-2.5 text-[9px] font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'SINGLE' ? 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm' : 'text-slate-500'}`}
        >
          Paste {stagedSnippets.length > 0 && `(${stagedSnippets.length})`}
        </button>
        <button 
          onClick={() => setActiveTab('UPLOAD')}
          className={`flex-1 py-2.5 text-[9px] font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'UPLOAD' ? 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm' : 'text-slate-500'}`}
        >
          Files
        </button>
        <button 
          onClick={() => setActiveTab('IMAGE')}
          className={`flex-1 py-2.5 text-[9px] font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'IMAGE' ? 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm' : 'text-slate-500'}`}
        >
          Camera
        </button>
      </div>

      <div className="p-5 lg:p-8 relative min-h-[400px]">
        {isProcessing && (
          <div className="absolute inset-0 bg-white/95 dark:bg-slate-900/95 backdrop-blur-md z-10 flex flex-col items-center justify-center space-y-8 px-6 text-center">
            <div className="relative">
              <div className="w-20 h-20 border-4 border-slate-100 dark:border-slate-800 rounded-full"></div>
              <div className="absolute inset-0 w-20 h-20 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-900 dark:text-slate-50 uppercase tracking-widest">Processing</h3>
              <p className="text-xs font-bold text-indigo-600 animate-pulse mt-2 h-4">{loadingMessage}</p>
              <div className="mt-8 w-64 h-2.5 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden mx-auto">
                <div className="h-full bg-indigo-600 transition-all duration-500 rounded-full" style={{ width: `${progress}%` }}></div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'SINGLE' && (
          <div className="space-y-6 animate-in fade-in zoom-in-95 duration-300">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3 block px-1">Raw Content Entry</label>
              <textarea 
                rows={10}
                className="w-full px-5 py-4 rounded-2xl border-2 border-slate-100 dark:border-slate-700 focus:border-indigo-500 focus:ring-0 transition-all bg-slate-50/50 dark:bg-slate-900/50 text-slate-800 dark:text-slate-100 font-medium text-base lg:text-sm leading-relaxed shadow-inner"
                placeholder="Type or paste questions here. You can include MCQs or numerical problems..."
                value={rawInput}
                onChange={e => setRawInput(e.target.value)}
              />
            </div>

            {stagedSnippets.length > 0 && (
              <div className="grid grid-cols-1 gap-2">
                {stagedSnippets.map((snippet, idx) => (
                  <div key={idx} className="flex items-center justify-between p-3.5 bg-indigo-50/30 dark:bg-indigo-900/10 border border-indigo-100/50 dark:border-indigo-800/50 rounded-xl group">
                    <div className="flex items-center gap-3 overflow-hidden">
                      <span className="w-5 h-5 flex items-center justify-center bg-indigo-600 text-white rounded-lg text-[10px] font-black shrink-0">{idx + 1}</span>
                      <p className="text-[11px] font-bold text-slate-600 dark:text-slate-300 truncate">{snippet.slice(0, 30)}...</p>
                    </div>
                    <button onClick={() => removeStagedSnippet(idx)} className="text-red-400 p-2 active:scale-90 transition-transform">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
                    </button>
                  </div>
                ))}
              </div>
            )}

            <div className="flex flex-col gap-3 pt-4 border-t border-slate-100 dark:border-slate-700">
               <button 
                type="button"
                onClick={handleStageSnippet}
                disabled={!rawInput.trim() || isProcessing}
                className="w-full py-4 border-2 border-indigo-600 text-indigo-600 font-black rounded-2xl transition active:scale-[0.98] text-xs uppercase tracking-widest flex items-center justify-center gap-2"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" /></svg>
                Stage Batch
              </button>
              <button 
                type="button"
                onClick={handleSmartPasteSubmit}
                disabled={(stagedSnippets.length === 0 && !rawInput.trim()) || isProcessing}
                className="w-full py-4 bg-slate-900 dark:bg-indigo-600 text-white font-black rounded-2xl shadow-xl transition active:scale-[0.98] text-xs uppercase tracking-widest"
              >
                Submit for Audit ({stagedSnippets.length + (rawInput.trim() ? 1 : 0)})
              </button>
            </div>
          </div>
        )}

        {activeTab === 'UPLOAD' && (
          <div className="py-12 px-6 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl group bg-slate-50/50 dark:bg-slate-900/50 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="w-16 h-16 bg-indigo-100 dark:bg-indigo-900/40 rounded-3xl flex items-center justify-center mb-6">
              <svg className="w-8 h-8 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg>
            </div>
            <h3 className="text-lg font-black text-slate-900 dark:text-slate-50 uppercase tracking-widest">Document Portal</h3>
            <p className="text-xs text-slate-500 dark:text-slate-400 mt-2 font-bold">PDF, Word, or Bulk Archives</p>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="mt-10 w-full py-4 bg-slate-900 text-white text-xs font-black uppercase tracking-widest rounded-2xl shadow-xl active:scale-95 transition-all"
            >
              Select Files
            </button>
            <input type="file" className="hidden" ref={fileInputRef} accept=".pdf,.docx" multiple onChange={(e) => processFiles(e.target.files, false)} />
          </div>
        )}

        {activeTab === 'IMAGE' && (
          <div className="py-12 px-6 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl group bg-slate-50/50 dark:bg-slate-900/50 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="w-16 h-16 bg-emerald-100 dark:bg-emerald-900/40 rounded-3xl flex items-center justify-center mb-6">
              <svg className="w-8 h-8 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
            </div>
            <h3 className="text-lg font-black text-slate-900 dark:text-slate-50 uppercase tracking-widest">Visual Scanner</h3>
            <p className="text-xs text-slate-500 dark:text-slate-400 mt-2 font-bold">Snap a photo of the paper</p>
            <button 
              onClick={() => imageInputRef.current?.click()}
              className="mt-10 w-full py-4 bg-slate-900 text-white text-xs font-black uppercase tracking-widest rounded-2xl shadow-xl active:scale-95 transition-all"
            >
              Open Camera
            </button>
            <input type="file" className="hidden" ref={imageInputRef} accept="image/*" multiple capture="environment" onChange={(e) => processFiles(e.target.files, true)} />
          </div>
        )}
      </div>
