export const auditDocument = async (base64Data: string, mimeType: string): Promise<any[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const DOCUMENT_AUDIT_PROMPT = `CORE TASK: Extract and Audit EVERY academic question found in this document (PDF, Docx, or Image).

  DOCUMENT ANALYSIS RULES:
  1. Scan every page thoroughly. 
  2. For each question:
     - Identify if it is an MCQ (4 options) or a Numerical Problem (Question + Solution/Answer).
     - Extract Question Body, Options (if any), Correct Answer, and the full Solution logic.
  3. Replace all LaTeX math with plain text descriptions or simple symbols.
  4. Perform a rigorous audit on each question for clarity and accuracy.

  OUTPUT REQUIREMENT:
  Return an array of JSON objects following the defined schema. One object per question found.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: mimeType } }, 
          { text: DOCUMENT_AUDIT_PROMPT }
        ]
      },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: questionSchemaProperties,
            required: ['status', 'topic', 'auditLogs', 'originalParsed', 'redlines', 'clean']
          }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Gemini Document/Image Audit Error:", error);
    throw error;
  }
};
